# When running automated tests, skip heavy timezone resource loading which can hang on
# some Windows environments where tzdata resource loading is slow or blocked.
if os.environ.get('NOC_CONFIGMAKER_TESTS') == '1':
    CST_ZONEINFO = None
    CST_PYTZ = None
else:
    if ZoneInfo is not None:
        try:
            CST_ZONEINFO = ZoneInfo(TIMEZONE_NAME)
        except Exception:
            CST_ZONEINFO = None
    else:
        CST_ZONEINFO = None

    if pytz is not None:
        try:
            CST_PYTZ = pytz.timezone(TIMEZONE_NAME)
        except Exception:
            CST_PYTZ = None
    else:
        CST_PYTZ = None


def _manual_cst_now():
    """Fallback CST/CDT calculation when zoneinfo/pytz are unavailable."""
    utc_now = datetime.now(timezone.utc)
    # Approximate DST window (Mar-Nov). Good enough until tzdata available.
    is_dst = 3 <= utc_now.month <= 11
    offset_hours = -5 if is_dst else -6
    return utc_now + timedelta(hours=offset_hours)


def get_cst_now():
    """Get current time in CST/CDT timezone (America/Chicago)."""
    if CST_ZONEINFO is not None:
        return datetime.now(timezone.utc).astimezone(CST_ZONEINFO)
    if CST_PYTZ is not None:
        return pytz.utc.localize(datetime.utcnow()).astimezone(CST_PYTZ)
    return _manual_cst_now()


def get_cst_timestamp():
    """Get current timestamp in CST/CDT as ISO format string."""
    return get_cst_now().isoformat()


def get_cst_datetime_string():
    """Get current datetime in CST/CDT as formatted string (YYYY-MM-DD HH:MM:SS)."""
    return get_cst_now().strftime('%Y-%m-%d %H:%M:%S')


def get_utc_now():
    return datetime.now(timezone.utc)


def get_utc_timestamp():
    """Get current timestamp in UTC as ISO string with Z suffix."""
    return get_utc_now().isoformat().replace('+00:00', 'Z')


def get_unix_timestamp():
    return int(get_utc_now().timestamp())


def _health_check_secure_data():
    secure_dir = ensure_secure_data_dir()
    result = {
        'name': 'secure_data',
        'ok': True,
        'path': str(secure_dir),
        'detail': 'secure_data directory is writable',
    }
    probe_name = f".healthcheck_{os.getpid()}_{int(time.time())}"
    probe_path = secure_dir / probe_name
    try:
        with open(probe_path, 'w', encoding='utf-8') as handle:
            handle.write('ok')
        probe_path.unlink(missing_ok=True)
    except Exception as exc:
        result['ok'] = False
        result['detail'] = f'secure_data directory is not writable: {exc}'
    return result


def _health_check_ido_backend():
    backend_url = _ido_backend_url()
    result = {
        'name': 'ido_backend',
        'ok': True,
        'configured': bool(backend_url),
        'backend_url': backend_url,
        'detail': 'IDO backend reachable',
    }
    if not backend_url:
        result['ok'] = False
        result['detail'] = 'IDO backend URL is not configured'
        return result
    try:
        resp = requests.get(urljoin(backend_url.rstrip('/') + '/', 'health/full'), timeout=1.5)
        result['status_code'] = resp.status_code
        if resp.headers.get('content-type', '').lower().startswith('application/json'):
            payload = resp.json()
            result['payload'] = payload
            result['ok'] = bool(payload.get('ok', resp.status_code == 200))
            if not result['ok']:
                result['detail'] = payload.get('missing_required_modules') or payload.get('detail') or 'IDO backend reported unhealthy'
        else:
            result['ok'] = resp.status_code == 200
            if not result['ok']:
                result['detail'] = f'IDO backend returned HTTP {resp.status_code}'
    except Exception as exc:
        result['ok'] = False
        result['detail'] = f'IDO backend health check failed: {exc}'
    return result


_HEALTH_CHECKS_CACHE: dict[str, object] = {
    'timestamp': 0.0,
    'checks': None,
}
_HEALTH_CHECKS_TTL_SECONDS = 30.0


def _collect_health_checks(force: bool = False):
    now = time.time()
    cached_checks = _HEALTH_CHECKS_CACHE.get('checks')
    cached_at = float(_HEALTH_CHECKS_CACHE.get('timestamp') or 0.0)
    if not force and cached_checks is not None and (now - cached_at) < _HEALTH_CHECKS_TTL_SECONDS:
        return cached_checks

    checks = [
        _health_check_secure_data(),
        _health_check_ido_backend(),
    ]
    _HEALTH_CHECKS_CACHE['checks'] = checks
    _HEALTH_CHECKS_CACHE['timestamp'] = now
    return checks


