def _get_dynamic_compliance_blocks(loopback_ip: str = "10.0.0.1/32", return_source: bool = False):
    """Get compliance blocks with GitLab-first loading and bundled fallback.

    Every endpoint that needs compliance blocks should call this instead of
    duplicating the GitLab loader / local reference fallback logic.

    Args:
        loopback_ip: Loopback IP address to inject into compliance blocks.
        return_source: If True, returns (blocks, source) tuple.

    Returns:
        dict of block_name -> RouterOS config text (default)
        OR (dict, str) tuple if return_source=True
    """
    blocks = {}

    # GitLab dynamic compliance is preferred when configured.
    if _HAS_GITLAB_COMPLIANCE and _get_gitlab_compliance_loader is not None:
        try:
            loader = _get_gitlab_compliance_loader()
            if loader.is_configured():
                gl_blocks = loader.get_compliance_blocks_from_script(loopback_ip=loopback_ip)
                if gl_blocks:
                    print(f"[COMPLIANCE] Using GitLab dynamic compliance blocks ({len(gl_blocks)} blocks)")
                    if return_source:
                        return gl_blocks, 'gitlab'
                    return gl_blocks
                else:
                    print("[COMPLIANCE] WARNING: GitLab returned empty compliance blocks")
            else:
                print("[COMPLIANCE] WARNING: GitLab compliance loader is not configured")
        except Exception as _exc:
            print(f"[COMPLIANCE] ERROR: GitLab compliance loader failed: {_exc}")
    else:
        print("[COMPLIANCE] WARNING: GitLab compliance module not available")

    # Fall back to the bundled reference blocks so compliance-backed features
    # keep working in local/dev or when GitLab is temporarily unavailable.
    try:
        fallback_blocks = get_all_compliance_blocks(loopback_ip=loopback_ip)
        if fallback_blocks:
            print(f"[COMPLIANCE] Using bundled fallback compliance blocks ({len(fallback_blocks)} blocks)")
            if return_source:
                return fallback_blocks, 'bundled-local'
            return fallback_blocks
    except Exception as _exc:
        print(f"[COMPLIANCE] ERROR: bundled compliance fallback failed: {_exc}")

    print("[COMPLIANCE] WARNING: No compliance blocks available from GitLab or bundled fallback")
    if return_source:
        return blocks, 'unavailable'
    return blocks


def _get_raw_gitlab_compliance_text(loopback_ip: str = "10.0.0.1") -> str | None:
    """Fetch the VERBATIM compliance script text from GitLab.

    Returns the full TX-ARv2.rsc content with only $LoopIP substituted on
    operational lines (src-address, etc).  All comments, section headers,
    inline comment=\"...\" attributes, command syntax — everything is
    preserved word-for-word exactly as engineering wrote it.

    Returns None when GitLab is unavailable so callers can fall back.
    """
    if not _HAS_GITLAB_COMPLIANCE or _get_gitlab_compliance_loader is None:
        return None
    try:
        loader = _get_gitlab_compliance_loader()
        if not loader.is_configured():
            return None
        raw = loader.get_raw_compliance_text(loopback_ip=loopback_ip)
        if raw:
            print(f"[COMPLIANCE] Loaded verbatim GitLab compliance text ({len(raw)} chars)")
        return raw
    except Exception as exc:
        print(f"[COMPLIANCE] Raw GitLab text fetch failed: {exc}")
        return None

