def _aviat_queue_find(ip):
    for entry in aviat_shared_queue:
        if entry.get("ip") == ip:
            return entry
    return None

def _aviat_queue_upsert(ip, updates=None):
    entry = _aviat_queue_find(ip)
    if entry is None:
        entry = {"ip": ip}
        aviat_shared_queue.append(entry)
    if updates:
        entry.update(updates)
    entry["updated_at"] = datetime.utcnow().isoformat() + "Z"
    return entry

def _aviat_expand_tasks(task_types):
    if not task_types:
        return []
    tasks = list(task_types)
    if "all" in tasks:
        return ["firmware", "password", "snmp", "buffer", "sop", "activate"]
    return [t for t in tasks if t]


def _aviat_clean_remaining_tasks(task_types):
    if not task_types:
        return []
    # For scheduled/loaded flows, firmware + activate already handled.
    return [task for task in _aviat_expand_tasks(task_types) if task not in ("firmware", "activate")]


def _aviat_remaining_tasks_for_reboot(task_types):
    # For reboot-required flows, keep firmware/activate so the upgrade continues after reboot.
    return _aviat_expand_tasks(task_types)

def _aviat_queue_remove(ip):
    aviat_shared_queue[:] = [e for e in aviat_shared_queue if e.get("ip") != ip]

def _aviat_error_is_transient(error_text):
    text = str(error_text or "").strip().lower()
    if not text:
        return False
    markers = (
        "socket is closed",
        "not connected",
        "connection reset",
        "broken pipe",
        "timeout",
        "timed out",
        "channel closed",
        "unable to connect to port 22",
        "connection failed",
        "connection timeout",
        "authentication failed",
        "ssh error",
        "device did not recover",
        "firmware version not ready",
        "failed to parse firmware version",
        "failed to parse inactive firmware version",
    )
    return any(marker in text for marker in markers)

def _aviat_is_transient_result(result):
    status = ((result or {}).get("status") or "").lower()
    if status in ("loading", "pending_verify", "reboot_pending", "rebooting"):
        return True
    return _aviat_error_is_transient((result or {}).get("error"))

def _aviat_status_from_result(result):
    status = (result or {}).get("status")
    success = result.get("success")
    err_text = str((result or {}).get("error") or "").lower()
    target_version = _aviat_target_version(result or {})
    final_version = _aviat_extract_version(
        (result or {}).get("firmware_version_after") or (result or {}).get("firmware_version_before")
    )
    final_ok = _aviat_version_meets_target(final_version, target_version)
    hard_component_error = any(
        (result or {}).get(k) is False for k in ("password_changed", "snmp_configured", "buffer_configured")
    )
    hard_precheck_error = any(
        (result or {}).get(k) is False for k in ("license_ok", "stp_ok", "subnet_ok")
    )
    if "precheck blocked upgrade" in err_text:
        return "pending"
    if "software operation already in progress" in err_text:
        return "loading"
    if "no software ready to activate" in err_text:
        return "pending"
    if status in ("reboot_pending", "rebooting"):
        return status
    if status == "reboot_required":
        return "reboot_required"
    if status == "precheck_failed":
        return "pending"
    if status in ("scheduled", "manual", "loading", "pending_verify"):
        return status
    if status == "aborted":
        return "aborted"
    if _aviat_is_transient_result(result):
        return "pending_verify"
    if final_ok and not hard_component_error and not hard_precheck_error:
        return "success"
    if hard_precheck_error:
        return "pending"
    if success:
        return "success"
    return "error"

def _aviat_substatus(flag, scheduled=False, loading=False, pending_verify=False):
    if pending_verify:
        return "pending_verify"
    if loading:
        return "loading"
    if scheduled:
        return "scheduled"
    return "success" if flag else "pending"


def _aviat_extract_version(value):
    if not value:
        return None
    match = re.search(r"\b(\d+\.\d+\.\d+)\b", str(value))
    return match.group(1) if match else None


def _aviat_target_version(payload):
    if not isinstance(payload, dict):
        return None
    explicit = payload.get("target_version") or payload.get("targetVersion")
    explicit = _aviat_extract_version(explicit)
    if explicit:
        return explicit
    maintenance = payload.get("maintenance_params") or {}
    target_name = str(maintenance.get("firmware_target") or payload.get("firmware_target") or "").strip().lower()
    if target_name == "baseline":
        return _aviat_extract_version(getattr(AVIAT_CONFIG, "firmware_baseline_version", "2.11.11"))
    if target_name == "final":
        return _aviat_extract_version(getattr(AVIAT_CONFIG, "firmware_final_version", "6.1.0"))
    return None


def _aviat_version_tuple(version):
    if not version:
        return (0, 0, 0)
    parts = [int(p) for p in re.findall(r"\d+", str(version))[:3]]
    while len(parts) < 3:
        parts.append(0)
    return tuple(parts)


def _aviat_firmware_is_final(version):
    target = _aviat_extract_version(getattr(AVIAT_CONFIG, "firmware_final_version", "6.1.0"))
    return _aviat_version_tuple(_aviat_extract_version(version)) >= _aviat_version_tuple(target)


def _aviat_version_meets_target(version, target_version=None):
    actual = _aviat_extract_version(version)
    target = _aviat_extract_version(target_version) or _aviat_extract_version(
        getattr(AVIAT_CONFIG, "firmware_final_version", "6.1.0")
    )
    if not actual or not target:
        return False
    baseline = _aviat_extract_version(getattr(AVIAT_CONFIG, "firmware_baseline_version", "2.11.11"))
    if baseline and _aviat_version_tuple(target) <= _aviat_version_tuple(baseline):
        return _aviat_version_tuple(actual) == _aviat_version_tuple(target)
    return _aviat_version_tuple(actual) >= _aviat_version_tuple(target)

def _aviat_queue_update_from_result(result, username=None):
    if not result:
        return
    ip = result.get("ip")
    if not ip:
        return
    status = _aviat_status_from_result(result)
    target_version = _aviat_target_version(result)
    updates = {
        "status": status,
        "firmwareStatus": _aviat_substatus(
            result.get("firmware_downloaded") or result.get("firmware_activated"),
            scheduled=result.get("firmware_scheduled"),
            loading=status == "loading",
            pending_verify=status == "pending_verify",
        ),
        "passwordStatus": _aviat_substatus(result.get("password_changed")),
        "snmpStatus": _aviat_substatus(result.get("snmp_configured")),
        "bufferStatus": _aviat_substatus(result.get("buffer_configured")),
        "sopStatus": _aviat_substatus(result.get("sop_passed")),
    }
    if target_version:
        updates["targetVersion"] = target_version
    subnet_ok = result.get("subnet_ok")
    subnet_detail = result.get("subnet_actual")
    # Fallback from SOP output when direct subnet fields are absent.
    if subnet_ok is None and isinstance(result.get("sop_results"), list):
        for item in result.get("sop_results") or []:
            if str(item.get("name", "")).strip().lower() == "subnet mask":
                subnet_ok = bool(item.get("pass"))
                subnet_detail = item.get("actual")
                break
    if subnet_ok is True:
        updates["subnetStatus"] = "success"
    elif subnet_ok is False:
        updates["subnetStatus"] = "error"
    else:
        updates["subnetStatus"] = "pending"
    if subnet_detail is not None:
        updates["subnetDetail"] = str(subnet_detail)
    elif subnet_ok is False:
        updates["subnetDetail"] = "Subnet mask mismatch detected"

    license_ok = result.get("license_ok")
    if license_ok is True:
        updates["licenseStatus"] = "success"
    elif license_ok is False:
        updates["licenseStatus"] = "error"
    else:
        updates["licenseStatus"] = "pending"
    if result.get("license_detail") is not None:
        updates["licenseDetail"] = str(result.get("license_detail"))

    stp_ok = result.get("stp_ok")
    if stp_ok is True:
        updates["stpStatus"] = "success"
    elif stp_ok is False:
        updates["stpStatus"] = "error"
    else:
        updates["stpStatus"] = "pending"
    if result.get("stp_detail") is not None:
        updates["stpDetail"] = str(result.get("stp_detail"))

    if (result.get("status") or "").lower() == "precheck_failed":
        updates["precheckStatus"] = "blocked"
        updates["precheckDetail"] = result.get("error") or "Precheck blocked upgrade"
    elif "precheck blocked upgrade" in str(result.get("error") or "").lower():
        updates["status"] = "pending"
        updates["precheckStatus"] = "blocked"
        updates["precheckDetail"] = result.get("error") or "Precheck blocked upgrade"

    # Reconcile occasional stale/incorrect "error" status when final state is actually good.
    final_version = _aviat_extract_version(
        result.get("firmware_version_after") or result.get("firmware_version_before")
    )
    final_ok = _aviat_version_meets_target(final_version, target_version)
    hard_component_error = any(
        updates.get(k) == "error" for k in ("passwordStatus", "snmpStatus", "bufferStatus")
    )
    hard_precheck_error = any(
        result.get(k) is False for k in ("license_ok", "stp_ok", "subnet_ok")
    )
    if updates.get("status") == "error" and final_ok and not hard_component_error and not hard_precheck_error:
        updates["status"] = "success"
        updates["error"] = None
    if final_ok and updates.get("status") not in (
        "loading",
        "pending_verify",
        "scheduled",
        "reboot_required",
        "reboot_pending",
        "rebooting",
    ):
        updates["firmwareStatus"] = "success"

    if username:
        updates["username"] = username
    _aviat_queue_upsert(ip, updates)

_aviat_load_shared_queue()

def _short_username(raw):
    if not raw:
        return "unknown"
    if "@" in raw:
        return raw.split("@", 1)[0]
    return raw

def _aviat_connect_with_fallback(ip, callback=None):
    client = None
    try:
        client = AviatSSHClient(
            ip,
            username=AVIAT_CONFIG.default_username,
            password=AVIAT_CONFIG.new_password,
        )
        client.connect()
        if callback:
            callback(f"[{ip}] Connected with new password", "info")
        return client
    except Exception:
        if client:
            try:
                client.close()
            except Exception:
                pass
    client = AviatSSHClient(
        ip,
        username=AVIAT_CONFIG.default_username,
        password=AVIAT_CONFIG.default_password,
    )
    client.connect()
    if callback:
        callback(f"[{ip}] Connected with default password", "info")
    return client

def _aviat_reboot_device(ip, callback=None):
    client = None
    try:
        client = _aviat_connect_with_fallback(ip, callback=callback)
        # Aviat WTM uses "restart" with confirmation.
        output = client.send_command("restart", wait_for=['?', ':', '#', '>', ']'], timeout=8)
        if "Are you sure" in output or "no,yes" in output or "[no,yes]" in output:
            client.send_command("yes", wait_for=['#', '>', ']'], timeout=5)
        if callback:
            callback(f"[{ip}] Reboot command sent.", "info")
        return True, None
    except Exception as e:
        if callback:
            callback(f"[{ip}] Reboot failed: {e}", "error")
        return False, str(e)
    finally:
        if client:
            try:
                client.close()
            except Exception:
                pass


_TASK_TTL_SECONDS = 7200  # 2 hours — keep completed/aborted task state for status queries

def _purge_stale_tasks(tasks_dict, log_queues_dict):
    """Remove completed/aborted tasks older than _TASK_TTL_SECONDS to prevent OOM."""
    cutoff = datetime.utcnow().isoformat() + 'Z'
    to_delete = []
    for tid, task in list(tasks_dict.items()):
        status = task.get('status', '')
        if status not in ('completed', 'aborted', 'failed'):
            continue
        completed_at = task.get('completed_at')
        if not completed_at:
            continue
        try:
            age = (datetime.utcnow() - datetime.fromisoformat(completed_at.rstrip('Z'))).total_seconds()
            if age > _TASK_TTL_SECONDS:
                to_delete.append(tid)
        except Exception:
            pass
    for tid in to_delete:
        tasks_dict.pop(tid, None)
        log_queues_dict.pop(tid, None)


def _aviat_loading_check_loop():
    while True:
        try:
            _purge_stale_tasks(aviat_tasks, aviat_log_queues)
        except Exception:
            pass
        if not HAS_AVIAT:
            time.sleep(AVIAT_LOADING_CHECK_INTERVAL)
            continue
        if not aviat_loading_queue:
            time.sleep(AVIAT_LOADING_CHECK_INTERVAL)
            continue
        now = datetime.utcnow()
        to_schedule = []
        still_loading = []
        deferred_verify = []
        with aviat_loading_lock:
            aviat_loading_queue[:] = _aviat_dedupe_queue(aviat_loading_queue)
            for entry in list(aviat_loading_queue):
                ip = entry.get("ip")
                if not ip:
                    continue
                current_check_count = int(entry.get("check_count") or 0)
                unknown_count = int(entry.get("unknown_count") or 0)
                started_at = entry.get("started_at")
                if started_at:
                    try:
                        started_dt = datetime.fromisoformat(started_at.replace("Z", ""))
                        if (now - started_dt).total_seconds() > AVIAT_LOADING_MAX_WAIT:
                            deferred_verify.append(entry)
                            continue
                    except Exception:
                        pass
                try:
                    def local_log(message, level):
                        _aviat_broadcast_log(message, level)
                    client = _aviat_connect_with_fallback(ip, callback=local_log)
                    software_state = _aviat_software_state(client)
                    active_version = aviat_get_firmware_version(client, callback=local_log)
                    inactive_raw = aviat_get_inactive_firmware_version(client, callback=local_log)
                    # Enforce reboot-first if uptime exceeds threshold
                    try:
                        uptime_days = aviat_get_uptime_days(client, callback=local_log)
                    except Exception:
                        uptime_days = None
                    client.close()
                except Exception as exc:
                    _aviat_broadcast_log(f"[{ip}] Loading check failed: {exc}", "warning")
                    entry["check_count"] = current_check_count + 1
                    entry["updated_at"] = datetime.utcnow().isoformat() + "Z"
                    still_loading.append(entry)
                    continue
                if uptime_days is not None and uptime_days > 250:
                    _aviat_broadcast_log(
                        f"[{ip}] Uptime {uptime_days} days exceeds 250; reboot required before upgrade.",
                        "warning",
                    )
                    if not any(e.get("ip") == ip for e in aviat_reboot_queue):
                        aviat_reboot_queue.append({
                            "ip": ip,
                            "reason": f"Uptime {uptime_days} days exceeds 250; reboot required before upgrade.",
                            "remaining_tasks": entry.get("remaining_tasks", []),
                            "maintenance_params": entry.get("maintenance_params", {}),
                            "username": entry.get("username") or "aviat-tool",
                            "started_at": datetime.utcnow().isoformat() + "Z",
                        })
                    _aviat_queue_upsert(ip, {
                        "status": "reboot_required",
                        "username": entry.get("username") or "aviat-tool",
                    })
                    _aviat_save_reboot_queue()
                    continue
                if isinstance(inactive_raw, str) and inactive_raw.lower() == "loadok":
                    _aviat_broadcast_log(
                        f"[{ip}] Firmware loadOk detected; moving to scheduled queue.",
                        "success",
                    )
                    to_schedule.append(entry)
                    continue
                if software_state == "loadok":
                    _aviat_broadcast_log(
                        f"[{ip}] Firmware state is loadOk; moving to scheduled queue.",
                        "success",
                    )
                    to_schedule.append(entry)
                    continue
                inactive_version = _aviat_extract_version(inactive_raw)
                active_version = _aviat_extract_version(active_version)
                target_version = _aviat_extract_version(entry.get("target_version"))
                ready_versions = {
                    _aviat_extract_version(AVIAT_CONFIG.firmware_baseline_version),
                    _aviat_extract_version(AVIAT_CONFIG.firmware_final_version),
                }
                if target_version:
                    ready_versions.add(target_version)

                # If active firmware already meets target (or final), resume deferred tasks
                # immediately instead of waiting on inactive/loadOk state.
                if target_version and active_version and _aviat_version_tuple(active_version) >= _aviat_version_tuple(target_version):
                    _aviat_broadcast_log(
                        f"[{ip}] Active firmware {active_version} already applied; removing from loading queue.",
                        "success",
                    )
                    resumed = _aviat_resume_remaining_tasks(entry, callback=local_log)
                    if resumed is None:
                        _aviat_queue_upsert(ip, {
                            "status": "success",
                            "firmwareStatus": "success",
                            "username": entry.get("username") or "aviat-tool",
                        })
                    continue
                if active_version and _aviat_version_tuple(active_version) >= _aviat_version_tuple(AVIAT_CONFIG.firmware_final_version):
                    _aviat_broadcast_log(
                        f"[{ip}] Active firmware {active_version} already final; removing from loading queue.",
                        "success",
                    )
                    resumed = _aviat_resume_remaining_tasks(entry, callback=local_log)
                    if resumed is None:
                        _aviat_queue_upsert(ip, {
                            "status": "success",
                            "firmwareStatus": "success",
                            "username": entry.get("username") or "aviat-tool",
                        })
                    continue

                # Do not schedule activation solely from inactive version text. Radios can show
                # inactive final while software state is idle/loadError and not activation-ready.
                if inactive_version and inactive_version in ready_versions and software_state != "loadok":
                    entry["check_count"] = current_check_count + 1
                    entry["unknown_count"] = 0
                    entry["updated_at"] = datetime.utcnow().isoformat() + "Z"
                    still_loading.append(entry)
                    _aviat_broadcast_log(
                        f"[{ip}] Inactive firmware {inactive_version} present but state={software_state}; waiting for loadOk before scheduling activation.",
                        "info",
                    )
                    continue

                if software_state in ("loaderror", "rollbackerror"):
                    retry_count = int(entry.get("loaderror_retries") or 0)
                    target_ver = _aviat_extract_version(entry.get("target_version"))
                    target_uri = AVIAT_CONFIG.firmware_final_uri
                    if target_ver and _aviat_version_tuple(target_ver) <= _aviat_version_tuple(AVIAT_CONFIG.firmware_baseline_version):
                        target_uri = AVIAT_CONFIG.firmware_baseline_uri
                    if retry_count < 2:
                        _aviat_broadcast_log(
                            f"[{ip}] Software state {software_state}; retrying load ({retry_count + 1}/2).",
                            "warning",
                        )
                        try:
                            client_retry = _aviat_connect_with_fallback(ip, callback=local_log)
                            try:
                                retry_ok, retry_msg = aviat_trigger_firmware_download(
                                    client_retry,
                                    target_uri,
                                    activation_time=None,
                                    activate_now=True,
                                    activation_mode="immediate",
                                    callback=local_log,
                                )
                            finally:
                                client_retry.close()
                            retry_out = retry_msg or ""
                            if retry_ok:
                                entry["loaderror_retries"] = retry_count + 1
                                entry["check_count"] = current_check_count + 1
                                entry["unknown_count"] = 0
                                entry["updated_at"] = datetime.utcnow().isoformat() + "Z"
                                still_loading.append(entry)
                                _aviat_broadcast_log(
                                    f"[{ip}] Load retry accepted; keeping in loading queue.",
                                    "info",
                                )
                                continue
                            entry["defer_reason"] = "load_retry_failed"
                            deferred_verify.append(entry)
                            _aviat_broadcast_log(
                                f"[{ip}] Load retry failed to start; moving to deferred verification.",
                                "warning",
                            )
                            continue
                        except Exception as exc:
                            entry["defer_reason"] = "load_retry_failed"
                            deferred_verify.append(entry)
                            _aviat_broadcast_log(
                                f"[{ip}] Load retry failed: {exc}",
                                "warning",
                            )
                            continue
                    entry["defer_reason"] = "load_error"
                    deferred_verify.append(entry)
                    _aviat_broadcast_log(
                        f"[{ip}] Software state {software_state} after retries; moving to deferred verification.",
                        "warning",
                    )
                    continue

                if (
                    not inactive_version
                    or str(inactive_version).lower() in ("none", "unknown", "0.0.0", "0")
                ):
                    entry["check_count"] = current_check_count + 1
                    entry["unknown_count"] = unknown_count + 1
                    entry["updated_at"] = datetime.utcnow().isoformat() + "Z"
                    if entry["unknown_count"] >= AVIAT_LOADING_UNKNOWN_MAX_CHECKS:
                        deferred_verify.append(entry)
                        _aviat_broadcast_log(
                            f"[{ip}] Inactive firmware unreadable after {entry['unknown_count']} checks; deferring verification.",
                            "warning",
                        )
                        continue
                    still_loading.append(entry)
                    _aviat_broadcast_log(
                        f"[{ip}] Inactive firmware version unknown (check {entry['unknown_count']}/{AVIAT_LOADING_UNKNOWN_MAX_CHECKS}); keeping in loading queue.",
                        "warning",
                    )
                    continue
                entry["check_count"] = current_check_count + 1
                entry["unknown_count"] = 0
                entry["updated_at"] = datetime.utcnow().isoformat() + "Z"
                still_loading.append(entry)
                _aviat_broadcast_log(
                    f"[{ip}] Firmware still loading; next check in {AVIAT_LOADING_CHECK_INTERVAL // 60} min.",
                    "info",
                )

            if deferred_verify:
                for entry in deferred_verify:
                    ip = entry.get("ip")
                    if ip:
                        reason = "timeout" if entry.get("started_at") else "parse_stalled"
                        if entry.get("defer_reason"):
                            reason = entry.get("defer_reason")
                        if int(entry.get("unknown_count") or 0) >= AVIAT_LOADING_UNKNOWN_MAX_CHECKS:
                            reason = "parse_stalled"
                        _aviat_queue_upsert(ip, {
                            "status": "pending_verify",
                            "firmwareStatus": "pending_verify",
                            "username": entry.get("username") or "aviat-tool",
                            "error": reason,
                        })
                        if reason == "parse_stalled":
                            _aviat_broadcast_log(
                                f"[{ip}] Firmware load verification stalled (unreadable inactive status). Keeping radio in deferred verification.",
                                "warning",
                            )
                        else:
                            _aviat_broadcast_log(
                                f"[{ip}] Firmware load check timed out after {AVIAT_LOADING_MAX_WAIT // 60} min. Keeping radio in deferred verification.",
                                "warning",
                            )
                _aviat_save_shared_queue()

            if to_schedule:
                for entry in to_schedule:
                    remaining_tasks = _aviat_clean_remaining_tasks(entry.get("remaining_tasks", []))
                    aviat_scheduled_queue.append({
                        "ip": entry.get("ip"),
                        "remaining_tasks": remaining_tasks,
                        "maintenance_params": entry.get("maintenance_params", {}),
                        "activation_at": entry.get("activation_at"),
                        "username": entry.get("username") or "aviat-tool",
                    })
                    _aviat_queue_upsert(entry.get("ip"), {
                        "status": "scheduled",
                        "firmwareStatus": "scheduled",
                        "username": entry.get("username") or "aviat-tool",
                    })
                _aviat_save_scheduled_queue()
                _aviat_save_shared_queue()

            aviat_loading_queue[:] = still_loading
            _aviat_save_loading_queue()

        if aviat_loading_queue:
            next_check = get_cst_now() + timedelta(seconds=AVIAT_LOADING_CHECK_INTERVAL)
            _aviat_broadcast_log(
                f"[AVIAT] Next loading check at {next_check.strftime('%H:%M')} CST",
                "info",
            )

        time.sleep(AVIAT_LOADING_CHECK_INTERVAL)


def _start_aviat_background_threads():
    global _aviat_background_threads_started
    if not HAS_AVIAT:
        return
    with _aviat_background_threads_lock:
        if _aviat_background_threads_started:
            return
        if AVIAT_AUTO_ACTIVATE:
            print("[AVIAT] Auto-activation scheduler is ENABLED")
            threading.Thread(target=_aviat_auto_activate_loop, daemon=True).start()
        else:
            print("[AVIAT] Auto-activation scheduler is DISABLED")
        print(f"[AVIAT] Firmware loading checker is ENABLED ({AVIAT_LOADING_CHECK_INTERVAL}s interval)")
        threading.Thread(target=_aviat_loading_check_loop, daemon=True).start()
        _aviat_background_threads_started = True


def _aviat_resume_remaining_tasks(entry, callback=None):
    ip = entry.get("ip")
    remaining_tasks = _aviat_clean_remaining_tasks(entry.get("remaining_tasks", []))
    username = entry.get("username") or "aviat-tool"
    if not ip or not remaining_tasks:
        return None

    _aviat_queue_upsert(ip, {
        "status": "processing",
        "username": username,
    })
    _aviat_save_shared_queue()
    if callback:
        callback(f"[{ip}] Firmware active; resuming deferred tasks: {', '.join(remaining_tasks)}", "info")

    result = aviat_process_radio(
        ip,
        remaining_tasks,
        callback=callback,
        maintenance_params=entry.get("maintenance_params", {}),
    )
    res_dict = _aviat_result_dict(result, username=username)
    # Propagate tenant context from the entry if it was stored there
    if entry.get('_tenant_id') is not None:
        res_dict['_tenant_id'] = entry['_tenant_id']
        res_dict['_tenant_slug'] = entry.get('_tenant_slug', '')
    _log_aviat_activity(res_dict)
    _aviat_queue_update_from_result(res_dict, username=username)
    _aviat_queue_upsert(ip, {
        "firmwareStatus": "success",
        "targetVersion": res_dict.get("target_version") or entry.get("target_version"),
        "username": username,
    })
    _aviat_save_shared_queue()
    return result

def _aviat_activate_entries(task_id, to_activate, username=None):
    aviat_tasks[task_id]['status'] = 'running'

    def log_callback(message, level):
        _aviat_broadcast_log(message, level, task_id=task_id)
        if task_id in aviat_log_queues:
            aviat_log_queues[task_id].put({'message': message, 'level': level})

    activation_limit = int(os.environ.get("AVIAT_ACTIVATION_MAX", "20"))
    worker_count = max(1, min(len(to_activate), activation_limit))

    def run_activation(entry):
        ip = entry["ip"]
        # Activation should be isolated; do not re-run other steps.
        full_tasks = ["activate"]
        result = aviat_process_radio(
            ip,
            full_tasks,
            callback=log_callback,
            maintenance_params=entry.get("maintenance_params", {}),
        )
        return entry, result

    with ThreadPoolExecutor(max_workers=worker_count) as executor:
        futures = [executor.submit(run_activation, entry) for entry in to_activate]
        for future in as_completed(futures):
            entry, result = future.result()
            ip = entry["ip"]
            remaining_tasks = _aviat_clean_remaining_tasks(entry.get("remaining_tasks", []))
            aviat_tasks[task_id]['results'].append({
                'ip': ip,
                'username': entry.get("username") or username,
                'success': result.success,
                'status': result.status,
                'firmware_downloaded': result.firmware_downloaded,
                'firmware_scheduled': result.firmware_scheduled,
                'firmware_activated': result.firmware_activated,
                'password_changed': result.password_changed,
                'snmp_configured': result.snmp_configured,
                'buffer_configured': result.buffer_configured,
                'sop_checked': result.sop_checked,
                'sop_passed': result.sop_passed,
                'sop_results': result.sop_results,
                'firmware_version_before': result.firmware_version_before,
                'firmware_version_after': result.firmware_version_after,
                'error': result.error
            })
            res_dict = _aviat_result_dict(result, username=entry.get("username") or username)
            # Inject tenant context captured at request time if available
            _act_task_tenant_id = aviat_tasks.get(task_id, {}).get('_tenant_id')
            _act_task_tenant_slug = aviat_tasks.get(task_id, {}).get('_tenant_slug', '')
            if _act_task_tenant_id is not None:
                res_dict['_tenant_id'] = _act_task_tenant_id
                res_dict['_tenant_slug'] = _act_task_tenant_slug
            _log_aviat_activity(res_dict)
            _aviat_queue_update_from_result(
                res_dict,
                username=entry.get("username") or username,
            )
            if result.status in ("loading", "pending_verify"):
                aviat_loading_queue.append({
                    "ip": ip,
                    "remaining_tasks": remaining_tasks,
                    "maintenance_params": entry.get("maintenance_params", {}),
                    "activation_at": entry.get("activation_at"),
                    "username": entry.get("username") or username or "aviat-tool",
                    "target_version": result.firmware_downloaded_version,
                    "started_at": datetime.utcnow().isoformat() + "Z",
                })
                _aviat_save_loading_queue()
                _aviat_queue_upsert(ip, {
                    "status": result.status,
                    "firmwareStatus": "pending_verify" if result.status == "pending_verify" else "loading",
                    "username": entry.get("username") or username or "aviat-tool",
                    "targetVersion": res_dict.get("target_version") or _aviat_target_version(entry),
                })
                _aviat_save_shared_queue()
            elif result.firmware_scheduled and result.status == "scheduled":
                aviat_scheduled_queue.append({
                    "ip": ip,
                    "remaining_tasks": remaining_tasks,
                    "maintenance_params": entry.get("maintenance_params", {}),
                    "activation_at": entry.get("activation_at"),
                    "username": entry.get("username") or username or "aviat-tool",
                })
                _aviat_save_scheduled_queue()
                _aviat_queue_upsert(ip, {
                    "status": "scheduled",
                    "username": entry.get("username") or username or "aviat-tool",
                    "targetVersion": res_dict.get("target_version") or _aviat_target_version(entry),
                })
                _aviat_save_shared_queue()

    aviat_tasks[task_id]['status'] = 'completed'
    _aviat_save_shared_queue()
    if task_id in aviat_log_queues:
        aviat_log_queues[task_id].put(None)


def _aviat_software_state(client) -> str:
    """Return normalized software status token (e.g. loadok/loaderror/idle/activate)."""
    try:
        raw = client.send_command("show software-status status", timeout=10) or ""
    except Exception:
        return "unknown"
    m = re.search(r"software-status\s+status\s+([A-Za-z0-9_-]+)", raw, flags=re.I)
    if not m:
        return "unknown"
    return (m.group(1) or "").strip().lower()

def _aviat_auto_activate_loop():
    while True:
        try:
            time.sleep(AVIAT_AUTO_ACTIVATE_POLL)
            if not AVIAT_AUTO_ACTIVATE:
                continue
            if not HAS_AVIAT:
                continue
            now = datetime.now()
            if not (2 <= now.hour < 5):
                continue
            if not aviat_scheduled_queue:
                continue
            if not aviat_activation_lock.acquire(blocking=False):
                continue
        except Exception as _pre_exc:
            print(f"[AVIAT] Auto-activate loop pre-check error (continuing): {_pre_exc}")
            time.sleep(AVIAT_AUTO_ACTIVATE_POLL)
            continue
        try:
            to_activate = []
            remaining = []
            for entry in aviat_scheduled_queue:
                activation_at = entry.get("activation_at")
                if activation_at:
                    try:
                        if datetime.fromisoformat(activation_at.replace("Z", "")) <= now:
                            to_activate.append(entry)
                        else:
                            remaining.append(entry)
                    except Exception:
                        to_activate.append(entry)
                else:
                    to_activate.append(entry)
            if not to_activate:
                continue
            aviat_scheduled_queue[:] = remaining
            _aviat_save_scheduled_queue()
            for entry in to_activate:
                _aviat_queue_upsert(entry["ip"], {
                    "status": "processing",
                    "username": entry.get("username") or "aviat-tool",
                })
            _aviat_save_shared_queue()
            task_id = f"auto-{uuid.uuid4()}"
            aviat_tasks[task_id] = {
                'status': 'pending',
                'abort': False,
                'ips': [x["ip"] for x in to_activate],
                'tasks': ['activate'],
                'results': []
            }
            aviat_log_queues[task_id] = queue.Queue()
            threading.Thread(
                target=_aviat_activate_entries,
                args=(task_id, to_activate),
                daemon=True,
            ).start()
        finally:
            aviat_activation_lock.release()

