# ========================================
# ENDPOINT 6: Non‑MPLS Enterprise Generator
# ========================================

def _cidr_details_gen(cidr: str) -> dict:
    """
    Return network facts for an interface CIDR.

    Notes:
    - Users sometimes paste the subnet network address (e.g. `.200/29`). RouterOS cannot
      assign the network/broadcast address, so we normalize to the first usable host.
    - DHCP pools are generated as a contiguous range starting *after* the router IP
      (router_ip+1 .. last_host), matching the UI's "gateway+1" convention.
    """
    iface = ipaddress.ip_interface(cidr)
    net = iface.network
    hosts = list(net.hosts())

    first_host = str(hosts[0]) if hosts else str(net.network_address)
    last_host = str(hosts[-1]) if hosts else str(net.broadcast_address)

    router_ip_obj = iface.ip
    # For IPv4 /0-/30 networks, network/broadcast addresses are not usable on interfaces.
    if isinstance(net, ipaddress.IPv4Network) and net.prefixlen < 31 and hosts:
        if router_ip_obj == net.network_address or router_ip_obj == net.broadcast_address:
            router_ip_obj = hosts[0]

    router_ip = str(router_ip_obj)

    pool_start = ''
    pool_end = ''
    if hosts:
        try:
            idx = hosts.index(router_ip_obj)
        except ValueError:
            idx = -1
        if 0 <= idx < (len(hosts) - 1):
            pool_start = str(hosts[idx + 1])
            pool_end = last_host

    return {
        'network': str(net.network_address),
        'prefix': net.prefixlen,
        'router_ip': router_ip,
        'first_host': first_host,
        'last_host': last_host,
        'pool_start': pool_start,
        'pool_end': pool_end,
        'broadcast': str(net.broadcast_address),
    }


app.register_blueprint(create_runtime_blueprint())
app.register_blueprint(create_ftth_blueprint(render_ftth_config, _cidr_details_gen, require_auth))


def _ros_quote(value: str) -> str:
    v = (value or "").replace('"', '\\"')
    return f"\"{v}\""

@app.route('/api/gen-enterprise-non-mpls', methods=['POST'])
@app.route('/api/gen-enterprise-Non-MPLS', methods=['POST'])  # Legacy UI alias
@require_auth
def gen_enterprise_non_mpls():
    try:
        _tenant_ctx = _get_request_tenant_context()
        _tenant_id = _tenant_ctx['tenant'].get('id')
        _check_quota(_tenant_id, 'configs_generated')
        _increment_usage(_tenant_id, 'configs_generated')
        data = request.get_json(force=True)
        device = (data.get('device') or 'RB5009').upper()
        target_version = data.get('target_version', '7.19.4')
        public_cidr = data['public_cidr']
        bh_cidr = data['bh_cidr']
        loopback_ip = data['loopback_ip']  # /32 expected
        device_profile = get_enterprise_device_profile(device)
        uplink_if = (data.get('uplink_interface') or device_profile['uplink_interface']).strip()
        public_port = (data.get('public_port') or device_profile['public_port']).strip()
        nat_port = (data.get('nat_port') or device_profile['nat_port']).strip()
        # Use environment variables or form data - RFC-09-10-25 Compliance defaults
        # Default to NextLink compliance DNS servers (142.147.112.3, 142.147.112.19)
        dns1 = data.get('dns1') or os.getenv('NEXTLINK_DNS_PRIMARY', '142.147.112.3')
        dns2 = data.get('dns2') or os.getenv('NEXTLINK_DNS_SECONDARY', '142.147.112.19')
        if not dns1 or not dns2:
            return jsonify({'success': False, 'error': 'DNS servers must be configured. Set NEXTLINK_DNS_PRIMARY and NEXTLINK_DNS_SECONDARY environment variables or configure in nextlink_constants.js'}), 400
        snmp_community = data.get('snmp_community', 'CHANGE_ME')
        syslog_ip = data.get('syslog_ip')
        coords = data.get('coords')
        identity = data.get('identity', f"RTR-{get_mikrotik_identity_prefix(device)}.AUTO-GEN")
        uplink_comment = data.get('uplink_comment', '').strip()  # Uplink comment/location for backhaul

        interface_roles = {
            'customer handoff': public_port,
            'nat': nat_port,
            'backhaul uplink': uplink_if,
        }
        duplicates = {}
        for role_name, interface_name in interface_roles.items():
            duplicates.setdefault(interface_name, []).append(role_name)
        collisions = {iface: roles for iface, roles in duplicates.items() if iface and len(roles) > 1}
        if collisions:
            collision_text = "; ".join(f"{iface}: {', '.join(roles)}" for iface, roles in collisions.items())
            return jsonify({
                'success': False,
                'error': f'Enterprise interface roles must be unique. Conflicts: {collision_text}',
                'profile': device_profile,
            }), 400

        pub = _cidr_details_gen(public_cidr)
        bh = _cidr_details_gen(bh_cidr)
        private_cidr = data.get('private_cidr', '')  # e.g., 192.168.88.1/24
        private_ip_range = data.get('private_pool', '')  # e.g., 192.168.88.10-192.168.88.254
        
        if not syslog_ip:
            syslog_ip = loopback_ip.split('/')[0]
        
        # Determine speed syntax based on RouterOS version
        def get_speed_syntax(version):
            """Determine speed syntax based on RouterOS version"""
            # Standardize on RouterOS 7.19.4+ syntax for generated configs.
            if version.startswith('7.'):
                return '1G-baseT-full'
            return '1G-baseT-full'
        
        speed_syntax = get_speed_syntax(target_version)
        loopback_ip_clean = loopback_ip.replace('/32', '').strip()
        
        # Parse private CIDR if provided
        private_network = ''
        private_gateway = ''
        if private_cidr:
            private_parts = private_cidr.split('/')
            if len(private_parts) == 2:
                private_ip = private_parts[0]
                private_prefix = private_parts[1]
                private_net = _cidr_details_gen(private_cidr)
                private_network = private_net['network']
                private_gateway = private_ip  # Use provided IP as gateway
        
        # Use standard reference blocks if available
        standard_blocks = {}
        if HAS_REFERENCE:
            try:
                standard_blocks = get_all_standard_blocks()
            except Exception as e:
                print(f"[WARN] Could not load standard blocks: {e}")
        
        # Build config blocks in proper order
        blocks = []
        
        # System Identity
        blocks.append(f"/system identity\nset name={identity}\n")
        
        # Queue Type
        blocks.append("/queue type\nset default-small pfifo-limit=50\n")
        
        # Interface Bridge
        blocks.append("/interface bridge\nadd name=loop0\nadd name=nat-bridge priority=0x1\nadd name=public-bridge priority=0x1\n")
        
        # Interface Ethernet (with speed for uplink if SFP)
        ethernet_block = f"/interface ethernet\n"
        ethernet_block += f"set [ find default-name={public_port} ] comment=\"CX HANDOFF\"\n"
        ethernet_block += f"set [ find default-name={nat_port} ] comment=NAT\n"
        # Add uplink interface comment - Use uplink comment if provided, otherwise use identity
        uplink_comment_value = uplink_comment if uplink_comment else identity
        uplink_comment_ros = _ros_quote(uplink_comment_value)
        if uplink_if.startswith('sfp'):
            # Determine speed based on RouterOS version
            speed = get_speed_syntax(target_version)
            ethernet_block += f"set [ find default-name={uplink_if} ] auto-negotiation=no comment={uplink_comment_ros} speed={speed}\n"
        else:
            # Non-SFP port - still add comment
            ethernet_block += f"set [ find default-name={uplink_if} ] comment={uplink_comment_ros}\n"
        blocks.append(ethernet_block)
        
        # Interface Bridge Port
        blocks.append("/interface bridge port\n" +
                      f"add bridge=public-bridge interface={public_port}\n" +
                      f"add bridge=nat-bridge interface={nat_port}\n")
        
        # IP Addresses (with proper network calculation)
        ip_block = "/ip address\n"
        ip_block += f"add address={loopback_ip_clean} comment=loop0 interface=loop0 network={loopback_ip_clean}\n"
        
        # Public IP - normalize network/broadcast to first usable host
        pub_router_ip = pub['router_ip']
        pub_network = pub['network']
        ip_block += f"add address={pub_router_ip}/{pub['prefix']} comment=\"PUBLIC(S)\" interface=public-bridge network={pub_network}\n"
        
        # Private IP - use provided or calculate
        private_base = ''  # Initialize for use in firewall NAT later
        if private_cidr and private_gateway:
            ip_block += f"add address={private_gateway}/{private_parts[1]} comment=PRIVATES interface=nat-bridge network={private_network}\n"
            # Extract base for firewall NAT
            private_base = private_network.rsplit('.', 1)[0] if '.' in private_network else private_network.rsplit('/', 1)[0].rsplit('.', 1)[0]
        else:
            # Fallback to calculated private
            private_base = pub['first_host'].rsplit('.', 1)[0]
            ip_block += f"add address={private_base}.1/24 comment=PRIVATES interface=nat-bridge network={private_base}.0\n"
        
        # Backhaul IP address - normalize network/broadcast to first usable host
        bh_router_ip = bh['router_ip']
        bh_network = bh['network']
        ip_block += f"add address={bh_router_ip}/{bh['prefix']} comment={uplink_comment_ros} interface={uplink_if} network={bh_network}\n"
        blocks.append(ip_block)
        
        # IP Pool
        pool_block = "/ip pool\n"
        # Public pool - use provided range or calculate
        # For /30: pool_start and pool_end are the same (customer IP only, excluding gateway)
        if pub.get('pool_start') and pub.get('pool_end'):
            if pub['pool_start'] == pub['pool_end']:
                # Single IP pool (e.g., /30 networks)
                pool_block += f"add name=public ranges={pub['pool_start']}\n"
            else:
                # Range pool
                pool_block += f"add name=public ranges={pub['pool_start']}-{pub['pool_end']}\n"
        else:
            pool_block += f"add name=public ranges={pub['router_ip']}\n"
        # Private pool
        if private_ip_range:
            pool_block += f"add name=private ranges={private_ip_range}\n"
        else:
            private_base = pub['first_host'].rsplit('.', 1)[0]
            pool_block += f"add name=private ranges={private_base}.10-{private_base}.254\n"
        blocks.append(pool_block)
        
        # Queue Tree
        blocks.append("/queue tree\n" +
                      f"add max-limit=200M name=UPLOAD parent={uplink_if}\n" +
                      "add max-limit=200M name=DOWNLOAD-PUB parent=public-bridge\n" +
                      "add max-limit=200M name=DOWNLOAD-NAT parent=nat-bridge\n" +
                      "add name=VOIP-UP packet-mark=VOIP parent=UPLOAD priority=1\n" +
                      "add name=VOIP-DOWN-PUB packet-mark=VOIP parent=DOWNLOAD-PUB priority=1\n" +
                      "add name=VOIP-DOWN-NAT packet-mark=VOIP parent=DOWNLOAD-NAT priority=1\n" +
                      "add name=ALL-DOWN-PUB packet-mark=ALL parent=DOWNLOAD-PUB\n" +
                      "add name=ALL-DOWN-NAT packet-mark=ALL parent=DOWNLOAD-NAT\n" +
                      "add name=ALL-UP packet-mark=ALL parent=UPLOAD\n")
        
        # IP Neighbor Discovery (tab-specific, not compliance)
        if standard_blocks.get('ip_neighbor_discovery'):
            blocks.append(standard_blocks['ip_neighbor_discovery'])
        
        # DHCP Server (tab-specific configuration)
        blocks.append("/ip dhcp-server\n" +
                      f"add address-pool=public interface=public-bridge lease-time=1h name=public-server\n" +
                      f"add address-pool=private interface=nat-bridge lease-time=1h name=nat-server\n")
        
        # DHCP Server Network (tab-specific configuration)
        # NOTE: dhcp-option-set=optset is NOT included in add commands because
        # optset is defined later by the compliance section. Instead, we add
        # set commands at the end that will apply optset after compliance creates it.
        dhcp_net_block = "/ip dhcp-server network\n"
        # Public DHCP network
        pub_gateway = pub_router_ip
        dhcp_net_block += f"add address={pub_network}/{pub['prefix']} dns-server={dns1},{dns2} gateway={pub_gateway}\n"
        # Private DHCP network
        if private_cidr and private_gateway:
            dhcp_net_block += f"add address={private_network}/{private_parts[1]} comment=PRIVATES dns-server={dns1},{dns2} gateway={private_gateway}\n"
        else:
            private_base = pub['first_host'].rsplit('.', 1)[0]
            dhcp_net_block += f"add address={private_base}.0/24 comment=PRIVATES dns-server={dns1},{dns2} gateway={private_base}.1\n"
        blocks.append(dhcp_net_block)
        
        # Firewall NAT (tab-specific rules - NTP, private NAT)
        # NOTE: Compliance will add additional NAT rules, but these are tab-specific
        blocks.append("/ip firewall nat\n" +
                      f"add action=src-nat chain=srcnat packet-mark=NTP to-addresses={loopback_ip_clean}\n" +
                      f"add action=src-nat chain=srcnat src-address={private_base}.0/24 to-addresses={pub_router_ip}\n")
        
        # Firewall Service Port (tab-specific)
        blocks.append("/ip firewall service-port\nset sip disabled=yes\n")
        
        # IP Route (tab-specific configuration)
        # Default route gateway should be a *neighbor* on the backhaul subnet (not the subnet network address).
        bh_net = ipaddress.ip_interface(bh_cidr).network
        bh_hosts = list(bh_net.hosts())
        if bh_hosts:
            bh_gateway = str(bh_hosts[0]) if str(bh_hosts[0]) != bh_router_ip else (str(bh_hosts[1]) if len(bh_hosts) > 1 else bh_router_ip)
        else:
            bh_gateway = bh_router_ip

        # Optional override: accept only a single IP (no CIDR) that isn't the router IP.
        gw_override = (data.get('gateway_ip') or '').strip()
        if gw_override and '/' not in gw_override:
            try:
                gw_ip = ipaddress.ip_address(gw_override)
                if gw_ip in bh_net and str(gw_ip) != bh_router_ip:
                    bh_gateway = str(gw_ip)
            except ValueError:
                pass
        blocks.append(f"/ip route\nadd disabled=no distance=1 dst-address=0.0.0.0/0 gateway={bh_gateway} routing-table=main scope=30 suppress-hw-offload=no target-scope=10\n")
        
        # SNMP (tab-specific - location and basic settings)
        # NOTE: Compliance will add SNMP community and additional settings
        loc = f" location=\"{coords}\"" if coords else ""
        blocks.append(f"/snmp\nset enabled=yes src-address={loopback_ip_clean} trap-community={snmp_community}{loc}\n")
        
        # NOTE: Compliance script will handle:
        # - /ip firewall address-list (all lists)
        # - /ip firewall filter (all input/forward rules)
        # - /ip firewall raw (all raw rules)
        # - /ip dns (DNS servers)
        # - /ip service (all service settings)
        # - /system logging action and /system logging (logging configuration)
        # - /user group (all user groups)
        # - /user aaa (RADIUS settings)
        # - /system clock and /system ntp client (time/NTP)
        # - /system routerboard settings (auto-upgrade)
        # - Additional firewall NAT rules (unauth proxy, SSH redirect)
        # - Firewall mangle rules
        # - DHCP options
        # - RADIUS configuration
        # - LDP filters

        # Join blocks with double newline, but ensure no trailing newlines in blocks
        cleaned_blocks = [block.rstrip('\n\r') for block in blocks if block.strip()]
        cfg = "\n\n".join(cleaned_blocks)
        
        # ========================================
        # RFC-09-10-25 COMPLIANCE ENFORCEMENT
        # ========================================
        if HAS_COMPLIANCE:
            try:
                print("[COMPLIANCE] Adding RFC-09-10-25 compliance to new configuration...")
                _lip = (loopback_ip or "10.0.0.1").split("/")[0]
                compliance_blocks = _get_dynamic_compliance_blocks(loopback_ip)
                cfg = inject_compliance_blocks(cfg, compliance_blocks, loopback_ip=_lip)
                
                # Validate compliance
                compliance_validation = validate_compliance(cfg)
                if not compliance_validation['compliant']:
                    print(f"[COMPLIANCE WARNING] {len(compliance_validation['missing_items'])} compliance items missing")
                else:
                    print("[COMPLIANCE] Configuration is compliant")
            except Exception as e:
                print(f"[COMPLIANCE ERROR] Failed to add compliance: {e}")
        
        # Normalize and deduplicate configuration before returning
        cfg = normalize_config(cfg)
        
        # Apply dhcp-option-set=optset to non-10.x DHCP networks
        # Must come AFTER normalize_config (which groups sections) and AFTER
        # compliance creates optset. These set commands go at the very end
        # so optset already exists when RouterOS processes them.
        dhcp_optset_suffix = ""
        if not pub_network.startswith("10."):
            dhcp_optset_suffix += f'\n/ip dhcp-server network set [find where address="{pub_network}/{pub["prefix"]}"] dhcp-option-set=optset'
        if private_cidr and private_gateway and not private_network.startswith("10."):
            dhcp_optset_suffix += f'\n/ip dhcp-server network set [find where address="{private_network}/{private_parts[1]}"] dhcp-option-set=optset'
        elif not private_cidr and not pub['first_host'].rsplit(".", 1)[0].startswith("10."):
            _priv_base = pub['first_host'].rsplit('.', 1)[0]
            dhcp_optset_suffix += f'\n/ip dhcp-server network set [find where address="{_priv_base}.0/24"] dhcp-option-set=optset'
        if dhcp_optset_suffix:
            cfg = cfg.rstrip() + "\n" + dhcp_optset_suffix.strip() + "\n"
        
        return jsonify({
            'success': True,
            'config': cfg,
            'device': device,
            'version': target_version,
            'profile': {
                **device_profile,
                'public_port': public_port,
                'nat_port': nat_port,
                'uplink_interface': uplink_if,
            }
        })
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 400

# ========================================
# HELPER FUNCTIONS
# ========================================

def get_syntax_rules(target_version):
    """Returns syntax change rules for target RouterOS version"""
    if target_version.startswith('7.'):
        return """V7 KEY CHANGES:
- OSPF: Use /routing ospf interface-template (not /routing ospf interface)
- BGP: Use /routing bgp connection (not /routing bgp peer)
- MOST SYNTAX STAYS THE SAME - only change if broken"""
    return "Keep syntax as-is"


# ========================================
# COMPLIANCE SECTION STRIPPING — DYNAMIC
# ========================================
# The compliance script (TX-ARv2.rsc from GitLab, or the hardcoded fallback)
# manages specific RouterOS sections.  We need to strip those sections from
# the source config BEFORE appending the compliance script, otherwise the
# source's version duplicates the compliance version.
#
# **Dynamic extraction** — The primary approach is to PARSE whatever
# compliance text we actually have (GitLab verbatim or GitLab parsed blocks)
# and extract the RouterOS section headers it contains.  This way, when
# engineering adds or removes sections from the GitLab compliance script
# the stripping automatically adapts — no code changes needed.
#
# GitLab is the SINGLE SOURCE OF TRUTH for compliance.  The hardcoded
# lists below serve ONLY as a safety-net for the stripping logic when
# dynamic extraction cannot run (e.g. temporary GitLab connectivity issue).
# They do NOT provide compliance content — just prevent source sections
# from surviving when compliance is injected.

# ---------------------------------------------------------------------------
# Safety-net strip list (used ONLY when dynamic extraction fails)
# ---------------------------------------------------------------------------
_COMPLIANCE_STRIP_SECTIONS_FALLBACK = [
    '/ip firewall filter',
    '/ip firewall raw',
    '/ip firewall nat',
    '/ip firewall mangle',
    '/ip firewall service-port',
    '/ip firewall connection tracking',
    '/snmp',
    '/snmp community',
    '/system logging',
    '/system logging action',
    '/ip service',
    '/ip dns',
    '/radius',
    '/user aaa',
    '/user group',
    '/user',
    '/ip dhcp-server option sets',
    '/ip dhcp-server option',
    '/mpls ldp accept-filter',
    '/mpls ldp advertise-filter',
    '/system clock',
    '/system ntp client',
    '/system ntp',
    '/system note',
    '/system scheduler',
    '/system script',
    '/system watchdog',
    '/system routerboard settings',
    '/ip proxy',
    '/ip socks',
]

_COMPLIANCE_MANAGED_LISTS_FALLBACK = {
    'EOIP-ALLOW', 'managerIP', 'BGP-ALLOW', 'SNMP', 'WALLED-GARDEN',
    'WLED-GARDEN', 'allowed-ips', 'blacklist', 'whitelist',
}

# Sections where compliance does TARGETED modifications only (set [find ..])
# and must NOT be fully stripped because they contain site-specific entries.
_COMPLIANCE_TARGETED_ONLY_SECTIONS = {
    '/interface bridge port',     # compliance: set [find interface~"vpls"] edge=yes
    '/ip dhcp-server network',    # compliance: set [find where address !~ "^10\\"] ...
}

# Sections that must ALWAYS be stripped from source config even if the GitLab
# compliance script doesn't have an explicit section header for them.  These
# are in the compliance domain — we never want the source version to survive
# because compliance owns the policy for them.  The dynamic extractor may miss
# these when the compliance script only manages a *sub*-section (e.g. GitLab
# has /snmp community but not bare /snmp, yet we want /snmp stripped too).
_COMPLIANCE_ALWAYS_STRIP_SECTIONS = {
    '/snmp',                      # daemon settings (contact, location, enabled)
    '/tool bandwidth-server',     # security: must be disabled
    '/ip socks',                  # security: must be disabled
    '/ip proxy',                  # security: must be disabled
    '/ip ssh',                    # hardening (strong-crypto, host-key-size)
    '/ip smb',                    # security: must be disabled
}


def _extract_compliance_managed_sections(compliance_text: str):
    """Parse compliance script text to dynamically discover which RouterOS
    sections and address-list names it manages.

    This is the heart of dynamic compliance stripping: instead of a hardcoded
    list we parse the actual compliance script (from GitLab or the fallback
    blocks) and extract every RouterOS section header (lines starting with
    ``/``) plus every ``list=<name>`` token inside ``/ip firewall address-list``
    blocks.

    Sections in ``_COMPLIANCE_TARGETED_ONLY_SECTIONS`` are excluded because
    compliance only makes conditional/filtered modifications there — stripping
    the whole section would destroy site-specific entries.

    Returns:
        (strip_sections: set[str], managed_address_lists: set[str])
    """
    sections = set()
    address_lists = set()
    targeted_lower = {s.lower() for s in _COMPLIANCE_TARGETED_ONLY_SECTIONS}

    in_addr_list_block = False

    for line in compliance_text.splitlines():
        stripped = line.strip()

        # Skip comments, empty lines, variable declarations
        if not stripped or stripped.startswith('#') or stripped.startswith(':'):
            continue

        # RouterOS section headers start with /
        if stripped.startswith('/'):
            # Extract just the section path (strip any inline add/set/rem/find on same line)
            section = stripped
            # If there's an inline command on the same line, extract just the path
            for marker in [' add ', ' set ', ' rem ', ' :foreach', '\nadd', '\nset']:
                idx = section.find(marker)
                if idx > 0:
                    section = section[:idx]
                    break
            section = section.strip()

            # Track whether we're inside a /ip firewall address-list block
            if section.lower() == '/ip firewall address-list':
                in_addr_list_block = True
                # Don't add to strip-sections (address-list has special handling)
                # BUT DO extract list= names from this same line — in the GitLab
                # script every address-list command has the full path prefix, e.g.:
                #   /ip firewall address-list add list=SNMP address=...
                #   /ip firewall address-list rem [find list=EOIP-ALLOW]
                # Without this, address_lists stays empty and nothing gets stripped.
                inline_lists = re.findall(r'\blist=([\w-]+)', stripped)
                for name in inline_lists:
                    if name:
                        address_lists.add(name)
                continue
            else:
                in_addr_list_block = False

            # Skip targeted-only sections
            if section.lower() in targeted_lower:
                continue

            sections.add(section)
            continue

        # Extract address-list names from add/rem lines inside address-list blocks
        # Also catch :foreach cleanup lines with list=<name>
        list_matches = re.findall(r'\blist=([\w-]+)', stripped)
        for name in list_matches:
            if name:
                address_lists.add(name)

    return sections, address_lists


def _strip_compliance_managed_sections(
    config: str,
    strip_sections: set = None,
    managed_lists: set = None,
) -> tuple:
    """Strip sections from config that the compliance script will replace.

    This prevents duplication when the compliance script is appended: the
    source config's firewall rules, logging, SNMP, users, etc. are removed
    and replaced by the authoritative GitLab compliance version.

    Site-specific sections (IP addresses, interfaces, routing, bridges,
    VLANs, bonding, VPLS, BGP, OSPF, queues, pools, DHCP servers/networks)
    are preserved untouched.

    For /ip firewall address-list, only entries with compliance-managed list
    names are stripped; site-specific lists (bgp-networks, customer lists)
    are preserved.

    Args:
        config: Full RouterOS config text.
        strip_sections: *Dynamic* set of RouterOS section paths to strip.
            When ``None`` (rare — GitLab unavailable), the safety-net
            ``_COMPLIANCE_STRIP_SECTIONS_FALLBACK`` is used.
        managed_lists: *Dynamic* set of address-list names to strip.
            When ``None`` (rare — GitLab unavailable), the safety-net
            ``_COMPLIANCE_MANAGED_LISTS_FALLBACK`` is used.
    """
    lines = config.split('\n')
    result = []
    in_stripped_section = False
    in_address_list_section = False
    stripped_sections_log = set()
    stripped_lines = 0
    stripped_addr_list_entries = 0
    compliance_stripped_ips = set()  # Track IPs removed by compliance

    # Resolve effective strip sets (dynamic first, hardcoded fallback)
    if strip_sections is not None and strip_sections:
        strip_set = {s.lower().strip() for s in strip_sections}
        source_label = 'dynamic'
    else:
        strip_set = {s.lower().strip() for s in _COMPLIANCE_STRIP_SECTIONS_FALLBACK}
        source_label = 'safety-net-fallback'

    # Use dynamic lists if provided AND non-empty, otherwise fall back to hardcoded
    effective_lists = managed_lists if managed_lists else _COMPLIANCE_MANAGED_LISTS_FALLBACK

    for line in lines:
        stripped = line.strip()
        lower = stripped.lower()

        # Detect section headers (lines starting with '/')
        if stripped.startswith('/'):
            # Check if this is a compliance-managed section
            # Match the section header exactly or as prefix of the line
            is_managed = False
            matched_section = None
            for sect in strip_set:
                # Line must start with the section header (possibly followed by space + subcommand)
                if lower == sect or lower.startswith(sect + ' ') or lower.startswith(sect + '\t'):
                    is_managed = True
                    matched_section = sect
                    break

            # Special handling for /ip firewall address-list
            if lower.startswith('/ip firewall address-list'):
                in_address_list_section = True
                in_stripped_section = False
                # Check if this is an inline add (header + add on same line)
                if ' add ' in lower or ' rem ' in lower:
                    # Check if it's a managed list
                    list_match = re.search(r'\blist=(\S+)', stripped)
                    if list_match and list_match.group(1) in effective_lists:
                        # Track IPs being stripped by compliance
                        for ipm in re.finditer(r'\b(?:\d{1,3}\.){3}\d{1,3}(?:/\d{1,2})?\b', stripped):
                            ip = ipm.group(0)
                            if not ip.startswith('0.0.') and not ip.startswith('255.255.'):
                                base_ip = ip[:-3] if ip.endswith('/32') else ip
                                compliance_stripped_ips.add(base_ip)
                        stripped_addr_list_entries += 1
                        continue  # Skip this managed entry
                result.append(line)
                continue
            elif is_managed:
                in_stripped_section = True
                in_address_list_section = False
                stripped_sections_log.add(matched_section)
                # Check for inline commands on same line as header
                # e.g., "/ip service set telnet disabled=yes" — strip entire line
                stripped_lines += 1
                continue
            else:
                # Not a managed section — new section starts, stop stripping
                in_stripped_section = False
                in_address_list_section = False
                result.append(line)
                continue

        # Inside a stripped section — skip all content lines
        if in_stripped_section:
            stripped_lines += 1
            continue

        # Inside address-list section — selectively strip managed lists
        if in_address_list_section:
            if stripped.startswith('add ') or stripped.startswith('rem '):
                list_match = re.search(r'\blist=(\S+)', stripped)
                if list_match and list_match.group(1) in effective_lists:
                    # Track IPs being stripped
                    for ipm in re.finditer(r'\b(?:\d{1,3}\.){3}\d{1,3}(?:/\d{1,2})?\b', stripped):
                        ip = ipm.group(0)
                        if not ip.startswith('0.0.') and not ip.startswith('255.255.'):
                            base_ip = ip[:-3] if ip.endswith('/32') else ip
                            compliance_stripped_ips.add(base_ip)
                    stripped_addr_list_entries += 1
                    continue  # Skip this managed entry
            result.append(line)
            continue

        # Normal line — keep it
        result.append(line)

    if stripped_sections_log:
        print(f"[COMPLIANCE-STRIP] [{source_label}] Stripped {len(stripped_sections_log)} compliance-managed sections "
              f"({stripped_lines} lines): {', '.join(sorted(stripped_sections_log))}")
    if stripped_addr_list_entries:
        print(f"[COMPLIANCE-STRIP] [{source_label}] Stripped {stripped_addr_list_entries} managed address-list entries "
              f"(preserved site-specific lists)")
    if compliance_stripped_ips:
        print(f"[COMPLIANCE-STRIP] Tracked {len(compliance_stripped_ips)} unique IPs removed by compliance")

    return '\n'.join(result), compliance_stripped_ips

def inject_compliance_blocks(
    config: str,
    compliance_blocks: dict,
    loopback_ip: str = "10.0.0.1",
    stripped_ips_out: set = None,
    raw_text_override: str | None = None,
) -> str:
    """
    Inject compliance into a RouterOS configuration.

    Source priority:
      1. **Verbatim GitLab text** — the full TX-ARv2.rsc content is appended
         word-for-word (comments, inline comment="..." attributes, exact
         command syntax, section order — all preserved exactly as engineering
         wrote it).  Only $LoopIP is substituted with the concrete IP.
      2. **Parsed compliance blocks** — if the verbatim GitLab text is
         unavailable but parsed blocks were obtained from GitLab or the
         bundled compliance reference, they are reassembled.
      3. **No blocks available** — if neither source is available, compliance
         is not injected and a clear warning is logged.

    Args:
        config: Existing RouterOS configuration
        compliance_blocks: Dictionary of compliance blocks used when verbatim
            GitLab text is unavailable
        loopback_ip: Loopback IP for $LoopIP substitutions
        stripped_ips_out: Optional mutable set; if provided, IPs removed
            by compliance stripping are added to it (for validation awareness).
        raw_text_override: Optional verbatim compliance text to use instead of
            re-fetching the GitLab raw script.
        
    Returns:
        Updated configuration with compliance blocks (only if not already present)
    """
    # Check if config is from a Tarana tab (different vendor, MikroTik compliance doesn't apply).
    # Must detect *actual* Tarana vendor configs, NOT MikroTik configs that simply
    # mention "Tarana" in an interface comment (e.g. comment="Tarana-Alpha-1").
    # Tarana configs have vendor-specific patterns like "tarana_config" sections,
    # no RouterOS header ("by RouterOS"), and no /ip or /interface sections.
    config_lower = config.lower()
    _has_routeros_header = 'by routeros' in config_lower or '# model =' in config_lower
    _has_routeros_sections = '/ip ' in config_lower or '/interface ' in config_lower or '/routing ' in config_lower
    is_tarana_config = (
        'tarana' in config_lower
        and ('sector' in config_lower or 'alpha' in config_lower)
        and not _has_routeros_header
        and not _has_routeros_sections
    )
    
    if is_tarana_config:
        print("[COMPLIANCE] Skipping compliance injection for Tarana tab (different vendor)")
        return config
    
    # Check if compliance section already exists (to avoid double-injection)
    if "# RFC-09-10-25 COMPLIANCE STANDARDS" in config or "RFC-09-10-25 COMPLIANCE STANDARDS" in config[-3000:]:
        print("[COMPLIANCE] Compliance section already exists, skipping duplicate injection")
        return config

    # ── 0. Obtain the compliance text we will append ──
    # Get it FIRST so we can parse it for dynamic section extraction.
    raw_text = raw_text_override if raw_text_override is not None else _get_raw_gitlab_compliance_text(loopback_ip)

    # Guard: if both the verbatim GitLab text and parsed compliance blocks are
    # unavailable, return config untouched.
    if not raw_text and not compliance_blocks:
        print("[COMPLIANCE] WARNING: Compliance sources unavailable — "
              "config returned WITHOUT compliance injection")
        return config

    # ── 1. Dynamic section extraction ──
    # Parse the compliance text to discover which RouterOS sections and
    # address-list names it manages.  This replaces the old hardcoded
    # _COMPLIANCE_STRIP_SECTIONS list and adapts automatically when the
    # GitLab compliance script changes.
    dyn_sections = None
    dyn_lists = None
    compliance_text_for_parsing = raw_text
    if not compliance_text_for_parsing and compliance_blocks:
        # Build parseable text from GitLab parsed blocks
        compliance_text_for_parsing = '\n'.join(v for v in compliance_blocks.values() if v)
    if compliance_text_for_parsing:
        dyn_sections, dyn_lists = _extract_compliance_managed_sections(compliance_text_for_parsing)
        if dyn_sections:
            src = 'GitLab-verbatim' if raw_text else 'GitLab-parsed-blocks'
            print(f"[COMPLIANCE] Dynamic extraction ({src}): "
                  f"{len(dyn_sections)} sections, {len(dyn_lists)} address-lists")
            print(f"[COMPLIANCE]   sections: {', '.join(sorted(dyn_sections))}")
            if dyn_lists:
                print(f"[COMPLIANCE]   address-lists: {', '.join(sorted(dyn_lists))}")

    # Merge always-strip sections into the dynamic set so source versions
    # are removed even when the compliance script only manages a sub-section
    # (e.g. GitLab has /snmp community but not bare /snmp).
    if dyn_sections is not None:
        before_count = len(dyn_sections)
        dyn_sections = dyn_sections | _COMPLIANCE_ALWAYS_STRIP_SECTIONS
        added = len(dyn_sections) - before_count
        if added:
            print(f"[COMPLIANCE] Merged {added} always-strip section(s) into dynamic set")
    elif dyn_sections is None:
        # No dynamic extraction at all — the hardcoded fallback strip list
        # will be used by _strip_compliance_managed_sections() as a safety net.
        print("[COMPLIANCE] WARNING: No dynamic section extraction possible — "
              "using hardcoded strip list as safety net")

    # ── 2. Strip compliance-managed sections from source config ──
    # This prevents duplication: source firewall/logging/SNMP/users/etc.
    # are removed and replaced by the authoritative compliance version.
    # Uses the dynamically-extracted sections when available, otherwise
    # falls back to the hardcoded list.
    config, compliance_stripped_ips = _strip_compliance_managed_sections(
        config,
        strip_sections=dyn_sections,
        managed_lists=dyn_lists,
    )
    if stripped_ips_out is not None:
        stripped_ips_out.update(compliance_stripped_ips)
    if compliance_stripped_ips:
        print(f"[COMPLIANCE] Tracked {len(compliance_stripped_ips)} IPs removed by compliance stripping")

    # ── 3. Append compliance ──
    if raw_text:
        compliance_section = (
            "\n\n# ========================================\n"
            "# RFC-09-10-25 COMPLIANCE STANDARDS\n"
            "# Source: GitLab netforge/compliance TX-ARv2.rsc (verbatim)\n"
            "# ========================================\n\n"
            + raw_text.rstrip()
            + "\n"
        )
        print(f"[COMPLIANCE] Injected verbatim GitLab compliance ({len(raw_text)} chars)")
        return config.rstrip() + "\n" + compliance_section

    # ── 4. GitLab parsed blocks (verbatim text unavailable) ──
    if not compliance_blocks:
        print("[COMPLIANCE] WARNING: Neither GitLab verbatim text nor parsed blocks available — "
              "config returned WITHOUT compliance injection")
        return config

    print("[COMPLIANCE] GitLab raw text unavailable — using GitLab parsed blocks")
    compliance_section = "\n\n# ========================================\n# RFC-09-10-25 COMPLIANCE STANDARDS\n# ========================================\n# Source: GitLab netforge/compliance TX-ARv2.rsc (parsed blocks)\n# ========================================\n\n"
    
    compliance_order = [
        'variables', 'ip_services', 'dns',
        'firewall_address_lists', 'firewall_filter_input', 'firewall_raw',
        'firewall_forward', 'firewall_nat', 'firewall_mangle',
        'clock_ntp', 'snmp', 'system_settings',
        'auto_upgrade', 'sip_alg_off', 'watchdog_timer', 'web_proxy_off',
        'vpls_edge', 'vpls_edge_ports', 'logging',
        'user_aaa', 'user_groups', 'user_profiles', 'users',
        'dhcp_options', 'radius', 'ldp_filters',
        'scripts', 'scheduler', 'sys_note',
    ]
    
    for key in compliance_order:
        if key in compliance_blocks:
            compliance_section += f"# {key.upper().replace('_', ' ')}\n"
            compliance_section += compliance_blocks[key]
            compliance_section += "\n\n"
    
    print(f"[COMPLIANCE] Injected GitLab parsed blocks compliance")
    return config.rstrip() + "\n" + compliance_section

def validate_translation(source, translated, compliance_replaced_ips=None):
    """Comprehensive validation to ensure all important information is preserved.
    Validates IP addresses, passwords, users, firewall rules, and routing configs.
    Normalizes /32 to bare IP to avoid false negatives on ROS7 fields like remote.address.
    
    Args:
        source: Source configuration text
        translated: Translated configuration text
        compliance_replaced_ips: Optional set of IPs removed by compliance stripping.
            These are excluded from missing_ips (expected removal, not data loss).
    """

    def strip_noise(text: str) -> str:
        # Remove router prompts
        text = re.sub(r"(?m)^\s*\[[^\]]+\]\s*", "", text)
        # Drop full-line comments
        text = re.sub(r"(?m)^\s*#.*$", "", text)
        # Remove /system script blocks (very noisy and may embed many IPs in strings)
        lines = text.splitlines()
        out = []
        in_script = False
        for l in lines:
            if l.startswith('/system script'):
                in_script = True
                continue
            if in_script and l.startswith('/'):
                in_script = False
            if in_script:
                continue
            out.append(l)
        return "\n".join(out)

    def extract_ips(text: str) -> set[str]:
        text = strip_noise(text)
        ips = set(re.findall(r"\b(?:\d{1,3}\.){3}\d{1,3}(?:/\d{1,2})?\b", text))
        # Normalize /32 to bare IP and filter out obviously invalid IPs
        norm = set()
        for ip in ips:
            # Skip common false positives
            if ip.startswith('0.0.') or ip.startswith('255.255.255.'):
                continue
            # Normalize /32 to bare IP
            base_ip = ip[:-3] if ip.endswith('/32') else ip
            try:
                # Validate it's a real IP
                ipaddress.ip_address(base_ip.split('/')[0])
                norm.add(base_ip)
            except:
                pass
        return norm

    source_ips = extract_ips(source)
    translated_ips = extract_ips(translated)
    missing_ips = source_ips - translated_ips

    # Extract IPs that are in PORT-EXHAUSTION comment lines (not truly lost,
    # just unavoidable when target has fewer ports than source).
    port_exhaustion_ips = set()
    for line in (translated or '').splitlines():
        if line.strip().startswith('# PORT-EXHAUSTION'):
            for m in re.finditer(r'\b(?:\d{1,3}\.){3}\d{1,3}(?:/\d{1,2})?\b', line):
                ip = m.group(0)
                if ip.startswith('0.0.') or ip.startswith('255.255.255.'):
                    continue
                base_ip = ip[:-3] if ip.endswith('/32') else ip
                try:
                    ipaddress.ip_address(base_ip.split('/')[0])
                    port_exhaustion_ips.add(base_ip)
                except Exception:
                    pass
    
    # Additional check: Are IPs present but with different CIDR notation?
    # e.g., source has 10.1.1.1/24, translated has 10.1.1.1/32
    actually_missing = []
    for ip in missing_ips:
        # Extract base IP without CIDR
        base = ip.split('/')[0]
        # Check if base IP exists in translated with any CIDR
        found = False
        for trans_ip in translated_ips:
            if trans_ip.startswith(base):
                found = True
                break
        # Also check if IP exists in PORT-EXHAUSTION lines (hardware port shortage, not a bug)
        if not found:
            for pe_ip in port_exhaustion_ips:
                if pe_ip.startswith(base) or base == pe_ip.split('/')[0]:
                    found = True
                    break
        if not found:
            actually_missing.append(ip)
    
    # Update missing_ips to only include truly missing ones
    cidr_excluded = len(missing_ips) - len(actually_missing)
    if cidr_excluded > 0:
        print(f"[VALIDATION] {cidr_excluded} IPs found with different CIDR or in PORT-EXHAUSTION - not counting as missing")
        missing_ips = set(actually_missing)
    
    # Exclude IPs removed by compliance stripping (expected replacement, not data loss).
    # These IPs were in source address-lists that compliance template replaces entirely.
    compliance_excluded_ips = set()
    if compliance_replaced_ips:
        normalized_compliance = set()
        for cip in compliance_replaced_ips:
            base = cip[:-3] if cip.endswith('/32') else cip
            normalized_compliance.add(base.split('/')[0])
        
        still_missing = set()
        for ip in missing_ips:
            base = ip.split('/')[0]
            if base in normalized_compliance:
                compliance_excluded_ips.add(ip)
            else:
                still_missing.add(ip)
        
        if compliance_excluded_ips:
            print(f"[VALIDATION] {len(compliance_excluded_ips)} IPs excluded (compliance-replaced): {sorted(compliance_excluded_ips)[:5]}")
            missing_ips = still_missing
    
    # Additional validation: Check for preserved passwords/secrets
    def extract_secrets(text: str) -> set:
        # Extract password=, secret=, auth-key= values (but not the actual values for security)
        secrets = set(re.findall(r'\b(password|secret|auth-key|auth-id)=[^\s]+', text, re.IGNORECASE))
        return secrets
    
    source_secrets = extract_secrets(source)
    translated_secrets = extract_secrets(translated)
    missing_secrets = source_secrets - translated_secrets
    
    # Check for preserved user accounts
    def extract_users(text: str) -> set:
        users = set(re.findall(r'/user\s+(?:add|set)\s+name=([^\s]+)', text, re.IGNORECASE))
        return users
    
    source_users = extract_users(source)
    translated_users = extract_users(translated)
    missing_users = source_users - translated_users
    
    # Check firewall rule count preservation
    source_fw_rules = len(re.findall(r'/ip firewall\s+(?:filter|nat|mangle|raw)\s+(?:add|set)', source, re.IGNORECASE))
    translated_fw_rules = len(re.findall(r'/ip firewall\s+(?:filter|nat|mangle|raw)\s+(?:add|set)', translated, re.IGNORECASE))
    
    is_valid = len(missing_ips) == 0 and len(missing_secrets) == 0 and len(missing_users) == 0
    
    validation_result = {
        "valid": is_valid,
        "source_ip_count": len(source_ips),
        "translated_ip_count": len(translated_ips),
        "missing_ips": sorted(list(missing_ips)),
        "port_exhaustion_ips": sorted(list(port_exhaustion_ips)),
        "compliance_replaced_ips": sorted(list(compliance_excluded_ips)),
        "source_secret_count": len(source_secrets),
        "translated_secret_count": len(translated_secrets),
        "missing_secrets": sorted(list(missing_secrets)),
        "source_user_count": len(source_users),
        "translated_user_count": len(translated_users),
        "missing_users": sorted(list(missing_users)),
        "source_firewall_rules": source_fw_rules,
        "translated_firewall_rules": translated_fw_rules,
        "firewall_rules_preserved": translated_fw_rules >= source_fw_rules * 0.95  # Allow 5% tolerance for consolidation
    }
    
    if not is_valid:
        print(f"[VALIDATION WARNING] Missing information detected:")
        if missing_ips:
            print(f"  - Missing IPs: {len(missing_ips)}")
        if missing_secrets:
            print(f"  - Missing secrets: {len(missing_secrets)}")
        if missing_users:
            print(f"  - Missing users: {len(missing_users)}")
        if not validation_result["firewall_rules_preserved"]:
            print(f"  - Firewall rules: {source_fw_rules} → {translated_fw_rules}")
    
    return validation_result

# ========================================
# ENDPOINT 5: Tarana Config Generation & Validation
# ========================================

def validate_tarana_config(config_text, device, routeros_version):
    """
    Validates Tarana sector configuration for accuracy and device compatibility.
    Returns (is_valid, errors, warnings)
    """
    errors = []
    warnings = []
    
    if not config_text or len(config_text.strip()) < 50:
        errors.append("Configuration is empty or too short")
        return False, errors, warnings
    
    # Validate required sections exist
    required_sections = [
        '/interface bridge',
        '/interface ethernet',
        '/interface vlan',
        '/interface bridge port'
    ]
    missing_sections = []
    for section in required_sections:
        if section not in config_text:
            missing_sections.append(section)
    
    if missing_sections:
        errors.append(f"Missing required sections: {', '.join(missing_sections)}")
    
    # ============================================================
    # BNG1 FORMAT VALIDATION - CRITICAL FOR LIVE DEVICES
    # ============================================================
    # BNG1 Format Requirements (IMMUTABLE):
    # - Bridge name: bridge3000 (NOT UNICORNMGMT)
    # - IP interface: bridge3000
    # - OSPF interface: bridge3000
    # - NO path-cost parameters
    # - NO port-cost-mode
    # ============================================================
    
    # Validate UNICORNMGMT IP address line exists and is correct
    # BNG1 MUST use bridge3000 interface (not UNICORNMGMT)
    # Support both quoted and unquoted comments: comment="UNICORN MGMT" or comment=UNICORNMGMT
    unicorn_ip_match = re.search(r'add address=(\d+\.\d+\.\d+\.\d+)/(\d+)\s+comment=([^\s"]+|"[^"]+")\s+interface=bridge3000\s+network=(\d+\.\d+\.\d+\.\d+)', config_text)
    if not unicorn_ip_match:
        errors.append("Missing or malformed UNICORNMGMT IP address line")
    else:
        gateway_ip = unicorn_ip_match.group(1)
        prefix = unicorn_ip_match.group(2)
        network_addr = unicorn_ip_match.group(4)  # network is group 4
        
        # Validate IP address format
        try:
            import ipaddress
            ipaddress.IPv4Address(gateway_ip)
            ipaddress.IPv4Address(network_addr)
            prefix_int = int(prefix)
            if prefix_int < 8 or prefix_int > 30:
                errors.append(f"Invalid prefix length: /{prefix} (must be between /8 and /30)")
        except ValueError as e:
            errors.append(f"Invalid IP address format: {str(e)}")
        
        # Validate network calculation (Nextlink convention: network = IP - 1)
        try:
            import ipaddress
            gateway_obj = ipaddress.IPv4Address(gateway_ip)
            expected_network = str(ipaddress.IPv4Address(int(gateway_obj) - 1))
            if network_addr != expected_network:
                errors.append(f"Network address calculation incorrect: expected {expected_network} (IP-1), got {network_addr}")
        except Exception as e:
            errors.append(f"Network calculation validation error: {str(e)}")
    
    # Validate OSPF interface-template exists and uses correct network
    # Format: /routing ospf interface-template add interfaces=bridge3000 ... network=10.243.211.112/29
    ospf_match = re.search(r'/routing ospf interface-template.*?network=(\d+\.\d+\.\d+\.\d+/\d+)', config_text, re.DOTALL)
    if not ospf_match:
        warnings.append("OSPF interface-template for UNICORNMGMT not found")
    else:
        ospf_network = ospf_match.group(1)
        # Verify OSPF uses network address, not gateway IP
        if unicorn_ip_match:
            gateway_ip = unicorn_ip_match.group(1)
            if gateway_ip in ospf_network:
                errors.append("OSPF network parameter should use network address (IP-1), not gateway IP")
    
    # Validate RouterOS syntax for specified version
    if routeros_version.startswith('7.'):
        # RouterOS 7.x uses interface-template, not interface
        if '/routing ospf interface add' in config_text and '/routing ospf interface-template' not in config_text:
            errors.append("RouterOS 7.x requires /routing ospf interface-template, not /routing ospf interface")
    elif routeros_version.startswith('6.'):
        # RouterOS 6.x uses interface, not interface-template
        if '/routing ospf interface-template' in config_text and '/routing ospf interface add' not in config_text:
            warnings.append("RouterOS 6.x typically uses /routing ospf interface, not interface-template")
    
    # Validate bridge port assignments
    bridge_port_count = len(re.findall(r'/interface bridge port\s+add', config_text))
    vlan_count = len(re.findall(r'/interface vlan\s+add', config_text))
    if bridge_port_count == 0:
        errors.append("No bridge ports configured")
    if vlan_count == 0:
        errors.append("No VLAN interfaces configured")
    
    # Validate device compatibility
    if device.lower() not in ['ccr2004', 'ccr2216']:
        warnings.append(f"Tarana sectors are typically configured on CCR2004 or CCR2216, not {device}")
    
    is_valid = len(errors) == 0
    return is_valid, errors, warnings

@app.route('/api/gen-tarana-config', methods=['POST'])
@require_auth
def gen_tarana_config():
    """
    Generates and validates Tarana sector configuration with AI-powered network calculation.
    Only returns success if configuration is accurate and device-ready.
    """
    try:
        _tenant_ctx = _get_request_tenant_context()
        _tenant_id = _tenant_ctx['tenant'].get('id')
        _check_quota(_tenant_id, 'configs_generated')
        _increment_usage(_tenant_id, 'configs_generated')
        data = request.get_json(force=True)
        raw_config = data.get('config', '')
        device = data.get('device', 'ccr2004')
        routeros_version = data.get('routeros_version', '7.19.4')
        
        if not raw_config:
            # Return error - we need a config to validate
            return jsonify({
                'success': False,
                'error': 'No configuration provided',
                'config': '',
                'device': device,
                'version': routeros_version
            }), 400
        
        # ============================================================
        # NETWORK CALCULATION - BNG1 FORMAT VALIDATION
        # ============================================================
        # BNG1 MUST use bridge3000 interface (not UNICORNMGMT)
        # Pattern: add address=IP/prefix comment=... interface=bridge3000 network=...
        # ============================================================
        unicorn_cidr_match = re.search(
            r'add address=(\d+\.\d+\.\d+\.\d+)/(\d+)\s+comment=([^\s"]+|"[^"]+")\s+interface=bridge3000\s+network=(\d+\.\d+\.\d+\.\d+)',
            raw_config
        )
        
        # CRITICAL: Reject if UNICORNMGMT interface is found (should be bridge3000)
        if re.search(r'interface=UNICORNMGMT', raw_config):
            print("[TARANA] ERROR: Config uses UNICORNMGMT interface - BNG1 must use bridge3000")
            return jsonify({
                'success': False,
                'error': 'Invalid format: BNG1 must use interface=bridge3000, not UNICORNMGMT',
                'config': raw_config
            }), 400
        if unicorn_cidr_match:
            user_ip = unicorn_cidr_match.group(1)
            prefix_len = int(unicorn_cidr_match.group(2)) if unicorn_cidr_match.group(2) else 29
            comment = unicorn_cidr_match.group(3)
            interface_name = 'bridge3000'  # BNG1 always uses bridge3000
            existing_network = unicorn_cidr_match.group(4)
            
            # Calculate network address using Nextlink convention: network = IP - 1
            try:
                import ipaddress
                ip_obj = ipaddress.IPv4Address(user_ip)
                network_obj = ipaddress.IPv4Address(int(ip_obj) - 1)
                correct_network = str(network_obj)
                
                print(f"[TARANA] User IP (Gateway): {user_ip}, Prefix: /{prefix_len}")
                print(f"[TARANA] Existing network: {existing_network}, Correct network: {correct_network}")
                print(f"[TARANA] Interface: {interface_name}")
                
                # Only fix if the network address is incorrect
                if existing_network != correct_network:
                    print(f"[TARANA] Network address incorrect, fixing from {existing_network} to {correct_network}")
                    # Fix /ip address line - replace only the network parameter
                    raw_config = re.sub(
                        r'(add address=' + re.escape(user_ip) + r'/' + str(prefix_len) + r'\s+comment=' + re.escape(comment) + r'\s+interface=' + re.escape(interface_name) + r'\s+network=)' + re.escape(existing_network),
                        r'\g<1>' + correct_network,
                        raw_config
                    )
                else:
                    print(f"[TARANA] Network address is already correct: {correct_network}")
                
                # Fix OSPF network parameter if it exists and is incorrect
                # Format: /routing ospf interface-template add interfaces=... network=10.246.2.25/29
                # Remove any corrupted OSPF lines first (lines that start with just an IP/prefix)
                raw_config = re.sub(r'^[H\d]\.\d+\.\d+\.\d+/\d+\s+priority=\d+', '', raw_config, flags=re.MULTILINE)
                
                ospf_match = re.search(r'(/routing ospf interface-template.*?network=)(\d+\.\d+\.\d+\.\d+/\d+)', raw_config, re.DOTALL)
                if ospf_match:
                    ospf_network = ospf_match.group(2)
                    expected_ospf_network = f"{correct_network}/{prefix_len}"
                    if ospf_network != expected_ospf_network:
                        print(f"[TARANA] OSPF network incorrect, fixing from {ospf_network} to {expected_ospf_network}")
                        raw_config = re.sub(
                            r'(/routing ospf interface-template.*?network=)' + re.escape(ospf_network),
                            r'\g<1>' + expected_ospf_network,
                            raw_config,
                            flags=re.DOTALL
                        )
                    else:
                        print(f"[TARANA] OSPF network is already correct: {expected_ospf_network}")
                
            except Exception as e:
                print(f"[TARANA] Network calculation error: {e}")
                # Don't modify config if calculation fails
        
        # Use AI to validate and enhance the configuration
        training_context = build_training_context()
        system_prompt = f"""You are a Nextlink NOC MikroTik RouterOS configuration expert specializing in Tarana sector configurations.

Your task:
1. **CRITICAL**: Fix network address calculations using proper CIDR subnet mathematics
2. Ensure proper RouterOS v{routeros_version} syntax
3. Verify all bridge port assignments are correct
4. Check VLAN naming consistency
5. Ensure proper formatting and spacing
6. Validate IP addresses and network calculations

**CRITICAL NETWORK CALCULATION RULES (NEXTLINK CONVENTION):**
- **Nextlink Convention**: Network = Gateway IP - 1
- Example: Gateway IP 10.246.21.64/29 → Network = 10.246.21.63
- The address parameter keeps the user's IP (gateway)
- The network parameter is always IP - 1
- OSPF networks parameter MUST use (IP - 1)/prefix, not the gateway IP
- This is a Nextlink-specific convention for UNICORNMGMT networks

**VERIFICATION:**
- Check /ip address lines: network= parameter must be the calculated network address
- Check /routing ospf interface-template: networks= parameter must be network_address/prefix (not IP_address/prefix)

Return ONLY the corrected RouterOS configuration with proper network addresses calculated. NO explanations, NO markdown code blocks, just pure RouterOS commands."""
        
        if training_context:
            system_prompt += "\n\n" + training_context
        
        user_prompt = f"""Validate and correct this Tarana sector configuration for {device.upper()} running RouterOS {routeros_version}:

{raw_config}

Return the corrected configuration with proper network calculations and formatting."""
        
        messages = [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_prompt}
        ]
        
        # Always ensure we have a valid config to return
        corrected_config = raw_config  # Start with original config (may have been fixed above)
        
        # Only use AI if the config needs enhancement - don't break valid configs
        try:
            # Try AI validation - but don't fail if it doesn't work
            try:
                ai_result = call_ai(messages, max_tokens=4000, task_type='validation')
                if ai_result:
                    # Clean up any markdown formatting
                    cleaned = ai_result.replace('```routeros', '').replace('```', '').strip()
                    # Only use AI result if it's substantial and contains the required elements
                    if cleaned and len(cleaned) > 100:
                        # Accept AI output only when it preserves the BNG1 bridge3000 format.
                        if '/ip address' in cleaned and ('interface=bridge3000' in cleaned or 'interfaces=bridge3000' in cleaned):
                            corrected_config = cleaned
                            print(f"[TARANA] AI validation successful ({len(corrected_config)} chars)")
                        else:
                            print(f"[TARANA] AI result missing required elements, using original config")
                    else:
                        print(f"[TARANA] AI result too short, using original config")
                else:
                    print(f"[TARANA] AI returned empty result, using original config")
            except Exception as ai_error:
                # AI failed - that's OK, use the original config (which may have been network-corrected)
                print(f"[TARANA] AI validation unavailable: {ai_error} - Using original config")
        except Exception as e:
            # Any other error - use original config
            print(f"[TARANA] Error during processing: {e} - Using original config")
        
        # Normalize and deduplicate before returning
        try:
            corrected_config = normalize_config(corrected_config)
        except Exception as norm_error:
            print(f"[TARANA] Normalization error: {norm_error} - Using config as-is")
            # Keep corrected_config as-is if normalization fails
        
        # CRITICAL: Validate the corrected config for accuracy
        is_valid, validation_errors, validation_warnings = validate_tarana_config(corrected_config, device, routeros_version)
        
        if not is_valid:
            # Config is not accurate - return error with details
            print(f"[TARANA] Validation failed: {validation_errors}")
            return jsonify({
                'success': False,
                'error': 'Configuration validation failed',
                'errors': validation_errors,
                'warnings': validation_warnings,
                'config': corrected_config,  # Still return config so user can see what was generated
                'device': device,
                'version': routeros_version
            }), 400
        
        # Config is valid - return success
        if validation_warnings:
            print(f"[TARANA] Validation passed with warnings: {validation_warnings}")
        
        return jsonify({
            'success': True,
            'config': corrected_config,
            'warnings': validation_warnings,  # Include warnings even on success
            'device': device,
            'version': routeros_version
        })
        
    except Exception as e:
        # Log error but return proper error response
        print(f"[TARANA] Critical error: {e}")
        import traceback
        traceback.print_exc()
        
        try:
            data = request.get_json(force=True)
            raw_config = data.get('config', '')
            device = data.get('device', 'ccr2004')
            routeros_version = data.get('routeros_version', '7.19.4')
            
            # Return error response - don't pretend everything is OK
            return jsonify({
                'success': False,
                'error': f'Backend processing error: {str(e)}',
                'config': raw_config if raw_config else '',
                'device': device,
                'version': routeros_version
            }), 500
        except:
            # Ultimate fallback - return error
            return jsonify({
                'success': False,
                'error': 'Critical backend error',
                'config': '',
                'device': 'ccr2004',
                'version': '7.19.4'
            }), 500

# ========================================
# SSH CONFIG FETCH
# ========================================

def _ssh_fetch_update_task(task_id: str, **fields) -> None:
    with ssh_fetch_tasks_lock:
        task = ssh_fetch_tasks.get(task_id)
        if not task:
            return
        task.update(fields)


def _run_mikrotik_ssh_fetch(
    host: str,
    ssh_username: str,
    ssh_password: str,
    ssh_ports: list[int],
    command: str,
    *,
    should_abort=None,
    progress_callback=None,
):
    try:
        import paramiko
    except ImportError:
        return {'success': False, 'error': 'paramiko library not installed. Run: pip install paramiko', 'status_code': 500}

    client = None
    last_error = None
    ports_tried = []
    connection_errors = []

    def _emit(message: str, **extra):
        if callable(progress_callback):
            try:
                progress_callback(message, **extra)
            except Exception:
                pass

    def _aborted_result():
        return {
            'success': False,
            'aborted': True,
            'error': 'SSH fetch aborted by user',
            'status_code': 499,
            'ports_tried': list(dict.fromkeys(ports_tried)) or list(ssh_ports),
        }

    def _close_client():
        nonlocal client
        if client:
            try:
                client.close()
            except Exception:
                pass
            client = None

    print(f"[SSH] Attempting connection to {host}, trying ports: {ssh_ports}")

    for port in ssh_ports:
        if callable(should_abort) and should_abort():
            _emit('Abort requested before next port attempt', phase='aborting')
            _close_client()
            return _aborted_result()
        try:
            _emit(f'Trying SSH port {port}', phase='connecting', current_port=port)
            print(f"[SSH] Trying port {port}...")
            client = paramiko.SSHClient()
            client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
            client.connect(
                hostname=host,
                port=port,
                username=ssh_username,
                password=ssh_password,
                timeout=10,
                banner_timeout=10,
                auth_timeout=10
            )

            print(f"[SSH] Successfully connected on port {port}")
            ports_tried.append(port)
            _emit(f'Connected on port {port}', phase='connected', current_port=port)

            if callable(should_abort) and should_abort():
                _emit('Abort requested after connect', phase='aborting', current_port=port)
                _close_client()
                return _aborted_result()

            stdin, stdout, stderr = client.exec_command(command, timeout=30)
            channel = stdout.channel
            channel.settimeout(1.0)
            deadline = time.time() + 30
            output_chunks = []
            error_chunks = []
            _emit('Running export command', phase='executing', current_port=port)

            while True:
                if callable(should_abort) and should_abort():
                    _emit('Abort requested while reading command output', phase='aborting', current_port=port)
                    try:
                        channel.close()
                    except Exception:
                        pass
                    _close_client()
                    return _aborted_result()

                drained = False
                while channel.recv_ready():
                    output_chunks.append(channel.recv(65535).decode('utf-8', errors='replace'))
                    drained = True
                while channel.recv_stderr_ready():
                    error_chunks.append(channel.recv_stderr(65535).decode('utf-8', errors='replace'))
                    drained = True

                if channel.exit_status_ready():
                    if not channel.recv_ready() and not channel.recv_stderr_ready():
                        break

                if time.time() > deadline:
                    raise TimeoutError(f'Export command timed out on port {port}')

                if not drained:
                    time.sleep(0.1)

            output = ''.join(output_chunks)
            error_output = ''.join(error_chunks)

            if error_output and 'error' in error_output.lower():
                _close_client()
                return {
                    'success': False,
                    'error': f'Device returned error on port {port}: {error_output[:200]}',
                    'status_code': 500,
                    'ports_tried': list(dict.fromkeys(ports_tried)),
                }

            if not output or not output.strip():
                _close_client()
                return {
                    'success': False,
                    'error': f'Device returned empty configuration on port {port}. Check RouterOS version and command.',
                    'status_code': 500,
                    'ports_tried': list(dict.fromkeys(ports_tried)),
                }

            normalized_output = normalize_line_breaks(output)
            print(f"[SSH] Successfully fetched config from {host}:{port}")
            _close_client()
            return {
                'success': True,
                'config': normalized_output,
                'host': host,
                'port': port,
                'command': command,
                'message': f'Successfully connected on port {port}',
                'ports_tried': list(dict.fromkeys(ports_tried)),
                'status_code': 200,
            }

        except paramiko.AuthenticationException as e:
            error_msg = f'SSH authentication failed on port {port}'
            print(f"[SSH] {error_msg}: {str(e)}")
            _close_client()
            return {
                'success': False,
                'error': f'{error_msg}. Check credentials. Tried ports: {", ".join(map(str, ssh_ports))}',
                'status_code': 401,
                'ports_tried': list(dict.fromkeys(ports_tried)) or list(ssh_ports),
            }
        except paramiko.SSHException as e:
            error_msg = f'SSH error on port {port}: {str(e)}'
            print(f"[SSH] {error_msg}")
            last_error = error_msg
            connection_errors.append(f"Port {port}: {str(e)}")
            ports_tried.append(port)
            _close_client()
            continue
        except (OSError, ConnectionError, TimeoutError) as e:
            error_msg = f'Connection error on port {port}: {str(e)}'
            print(f"[SSH] {error_msg}")
            last_error = error_msg
            connection_errors.append(f"Port {port}: {str(e)}")
            ports_tried.append(port)
            _close_client()
            continue
        except Exception as e:
            error_msg = f'Unexpected error on port {port}: {str(e)}'
            print(f"[SSH] {error_msg}")
            last_error = error_msg
            connection_errors.append(f"Port {port}: {str(e)}")
            ports_tried.append(port)
            _close_client()
            continue

    ports_str = ', '.join(map(str, dict.fromkeys(ports_tried))) if ports_tried else ', '.join(map(str, ssh_ports))
    error_details = '; '.join(connection_errors) if connection_errors else (last_error or "Unable to connect")
    print(f"[SSH] All ports failed for {host}. Tried: {ports_str}. Errors: {error_details}")
    return {
        'success': False,
        'error': f'Connection failed on all ports ({ports_str}). Errors: {error_details}',
        'ports_tried': list(dict.fromkeys(ports_tried)) if ports_tried else list(ssh_ports),
        'status_code': 502,
    }

@app.route('/api/fetch-config-ssh', methods=['POST'])
def fetch_config_ssh():
    """
    SSH into MikroTik device and fetch configuration via export command.
    Credentials can be provided in the request body, or via environment variables.
    """
    # Auth guard — equivalent to @require_auth (decorator defined later in file)
    _auth_token = request.headers.get('Authorization', '')
    if _auth_token.startswith('Bearer '):
        _auth_token = _auth_token[7:]
    if not _auth_token:
        _auth_token = (request.get_json(silent=True) or {}).get('token', '')
    if not _auth_token:
        return jsonify({'error': 'Authentication required'}), 401
    _auth_user = verify_token(_auth_token)
    if not _auth_user:
        return jsonify({'error': 'Invalid or expired token'}), 401

    try:
        data = request.get_json(force=True)
        host = data.get('host', '').strip()
        ros_version = data.get('ros_version', '7')
        command = data.get('command', '').strip()
        async_task = bool(data.get('async_task'))
        
        if not host:
            return jsonify({'error': 'Device IP address is required'}), 400
        
        # Basic IP validation
        try:
            ipaddress.IPv4Address(host)
        except ValueError:
            return jsonify({'error': 'Invalid IP address format'}), 400
        
        # Credentials
        # Prefer request-provided credentials, then tenant_settings, then env vars.
        _fcs_ts = {}
        try:
            _fcs_tenant_ctx = _get_request_tenant_context()
            _fcs_tenant = (_fcs_tenant_ctx.get('tenant') or {})
            _fcs_tenant_id = _fcs_tenant.get('id') if _fcs_tenant else None
            if _fcs_tenant_id:
                init_users_db()
                _fcs_conn = sqlite3.connect(os.path.join('secure_data', 'users.db'))
                _fcs_ts = _get_tenant_settings_row(_fcs_conn, _fcs_tenant_id)
                _fcs_conn.close()
        except Exception:
            _fcs_ts = {}
        _fcs_env_user = (_fcs_ts.get('ssh_username') or '').strip() or os.getenv('NEXTLINK_SSH_USERNAME', '')
        _fcs_env_pass = (_fcs_ts.get('ssh_password') or '').strip() or os.getenv('NEXTLINK_SSH_PASSWORD', '')
        SSH_USERNAME = (data.get('username') or _fcs_env_user).strip()
        SSH_PASSWORD = (data.get('password') or _fcs_env_pass).strip()

        if not SSH_USERNAME or not SSH_PASSWORD:
            return jsonify({
                'error': 'SSH credentials required. Provide username/password or set NEXTLINK_SSH_USERNAME and NEXTLINK_SSH_PASSWORD on the server.'
            }), 400
        
        # MikroTik SSH ports: default try 22 first, then 5022 as fallback.
        # Allow UI to pass a comma-separated string or list via `ports`, and/or a single `port` override.
        default_ports = [22, 5022]

        def _parse_ports(value):
            ports = []
            if value is None:
                return ports
            if isinstance(value, (list, tuple)):
                tokens = value
            elif isinstance(value, str):
                tokens = re.split(r'[\s,]+', value.strip())
            else:
                tokens = [value]

            for token in tokens:
                try:
                    port = int(str(token).strip())
                except (ValueError, TypeError):
                    continue
                if 1 <= port <= 65535 and port not in ports:
                    ports.append(port)
            return ports

        requested_ports = _parse_ports(data.get('ports'))
        port_override = _parse_ports(data.get('port'))

        SSH_PORTS = requested_ports[:] if requested_ports else []

        # Apply single-port override first if provided (backward compatibility with older clients).
        if port_override:
            for p in reversed(port_override):
                if p in SSH_PORTS:
                    SSH_PORTS.remove(p)
                SSH_PORTS.insert(0, p)

        # Ensure standard ports are always available as fallbacks.
        for p in default_ports:
            if p not in SSH_PORTS:
                SSH_PORTS.append(p)

        if not SSH_PORTS:
            SSH_PORTS = default_ports[:]
        
        # Determine export command based on RouterOS version
        if not command:
            if ros_version == '7':
                command = 'export'
            else:
                command = 'export'
        
        # Validate command (security: only allow export commands)
        allowed_commands = ['export', 'export show-sensitive', 'export hide-sensitive']
        if command not in allowed_commands:
            return jsonify({'error': f'Invalid command. Allowed: {", ".join(allowed_commands)}'}), 400
        
        if async_task:
            task_id = str(uuid.uuid4())
            with ssh_fetch_tasks_lock:
                ssh_fetch_tasks[task_id] = {
                    'task_id': task_id,
                    'status': 'queued',
                    'host': host,
                    'command': command,
                    'ports': SSH_PORTS,
                    'current_port': None,
                    'message': 'Queued for SSH fetch',
                    'abort': False,
                    'started_at': get_utc_timestamp(),
                    'completed_at': None,
                }

            def _worker():
                _ssh_fetch_update_task(task_id, status='running', message='Starting SSH fetch')

                def _should_abort():
                    return ssh_fetch_tasks.get(task_id, {}).get('abort') is True

                def _progress(message, **extra):
                    payload = {'message': message}
                    payload.update(extra)
                    _ssh_fetch_update_task(task_id, **payload)

                result = _run_mikrotik_ssh_fetch(
                    host,
                    SSH_USERNAME,
                    SSH_PASSWORD,
                    SSH_PORTS,
                    command,
                    should_abort=_should_abort,
                    progress_callback=_progress,
                )
                if result.get('aborted'):
                    _ssh_fetch_update_task(
                        task_id,
                        status='aborted',
                        error=result.get('error'),
                        completed_at=get_utc_timestamp(),
                    )
                    return
                if result.get('success'):
                    _ssh_fetch_update_task(
                        task_id,
                        status='completed',
                        completed_at=get_utc_timestamp(),
                        config=result.get('config'),
                        port=result.get('port'),
                        message=result.get('message'),
                        ports_tried=result.get('ports_tried'),
                    )
                    return
                _ssh_fetch_update_task(
                    task_id,
                    status='failed',
                    error=result.get('error'),
                    completed_at=get_utc_timestamp(),
                    ports_tried=result.get('ports_tried'),
                )

            threading.Thread(target=_worker, daemon=True).start()
            return jsonify({
                'success': True,
                'task_id': task_id,
                'status': 'queued',
                'message': 'SSH fetch task started',
            }), 202

        result = _run_mikrotik_ssh_fetch(
            host,
            SSH_USERNAME,
            SSH_PASSWORD,
            SSH_PORTS,
            command,
        )
        if result.get('success'):
            return jsonify({
                'config': result.get('config'),
                'host': result.get('host'),
                'port': result.get('port'),
                'command': result.get('command'),
                'message': result.get('message'),
            }), 200
        status_code = int(result.get('status_code') or 500)
        payload = {'error': result.get('error') or 'Backend error while fetching config'}
        if result.get('ports_tried'):
            payload['ports_tried'] = result.get('ports_tried')
        return jsonify(payload), status_code
                    
    except Exception as e:
        # Do not expose internal errors or credentials
        print(f"[SSH] Error: {e}")
        return jsonify({
            'error': 'Backend error while fetching config'
        }), 500


@app.route('/api/fetch-config-ssh/status/<task_id>', methods=['GET'])
@require_auth
def fetch_config_ssh_status(task_id):
    task = ssh_fetch_tasks.get(task_id)
    if not task:
        return jsonify({'error': 'Task not found'}), 404
    return jsonify(task)


@app.route('/api/fetch-config-ssh/abort/<task_id>', methods=['POST'])
@require_auth
def fetch_config_ssh_abort(task_id):
    task = ssh_fetch_tasks.get(task_id)
    if not task:
        return jsonify({'error': 'Task not found'}), 404
    if task.get('status') in {'completed', 'failed', 'aborted'}:
        return jsonify({'status': task.get('status')}), 200
    _ssh_fetch_update_task(task_id, abort=True, status='aborting', message='Abort requested')
    return jsonify({'status': 'aborting'})

