def _detect_nokia_state(config_text: str) -> dict:
    """
    Detect the deployment state/region from a MikroTik configuration.
    Uses site name prefixes first, then IP address ranges as fallback.

    Returns:
        dict with state_code, profile_name, confidence, source, has_mpls
    """
    upper = (config_text or '').upper()

    # Method 1: State prefix in system identity name (highest confidence)
    # Extract identity first, then check for state codes like "TX-HALLETTSVILLE"
    identity_m = re.search(r'(?mi)^\s*/system\s+identity\s*\n\s*set\s+name=(\S+)', config_text or '')
    if not identity_m:
        identity_m = re.search(r'(?mi)^\s*/system\s+identity\s+set\s+name=(\S+)', config_text or '')
    identity_name = (identity_m.group(1) if identity_m else '').upper().strip('"').strip("'")

    # Check for state prefix in identity: RTR-MTCCR2004-1.TX-SITENAME or similar
    state_codes = ['TX', 'NE', 'KS', 'IL', 'IA', 'OK', 'IN']
    has_mpls = bool(re.search(r'/MPLS|VPLS|BRIDGE999|BRIDGE600|BRIDGE800', upper))

    for code in state_codes:
        # Match state code after a dot or dash boundary in identity: .TX- or -TX-
        if re.search(rf'[.\-]{code}-[A-Z]', identity_name):
            profile = _NOKIA_STATE_PROFILES.get(code, {})
            return {
                'state_code': code,
                'profile_name': profile.get('name', code),
                'confidence': 'high',
                'source': 'site_name',
                'has_mpls': has_mpls,
            }

    # Method 2: IP address range detection
    ip_matches = re.findall(r'\b10\.(\d+)\.\d+\.\d+', config_text or '')
    octet_counts = {}
    for octet_str in ip_matches:
        octet = int(octet_str)
        if octet in (0, 1, 255):
            continue
        octet_counts[octet] = octet_counts.get(octet, 0) + 1
    # Map known IP octets to states
    octet_to_state = {2: 'TX', 249: 'NE', 248: 'KS', 247: 'IL', 254: 'IA', 240: 'OK', 243: 'IN'}
    best_state = None
    best_count = 0
    for octet, count in octet_counts.items():
        if octet in octet_to_state and count > best_count:
            best_count = count
            best_state = octet_to_state[octet]
    if best_state:
        profile = _NOKIA_STATE_PROFILES.get(best_state, {})
        return {
            'state_code': best_state,
            'profile_name': profile.get('name', best_state),
            'confidence': 'medium',
            'source': 'ip_range',
            'has_mpls': has_mpls,
        }

    # Default: TX (in-state) with low confidence
    return {
        'state_code': 'TX',
        'profile_name': 'Texas (In-State)',
        'confidence': 'low',
        'source': 'default',
        'has_mpls': has_mpls,
    }


def _generate_nokia_system_name(parsed: dict, state_code: str) -> str:
    """
    Generate Nokia system name from MikroTik parsed data.

    Pattern: RTR-NK7250-{N}.{STATE}-{CITY}-{DIR}-{N}
    Examples:
        RTR-MTCCR2004-1.BLUEGRASS2 + TX  → RTR-NK7250-1.TX-BLUEGRASS2
        RTR-MTCCR2116-1.NE-PAWNEECITY-SE → RTR-NK7250-1.NE-PAWNEECITY-SE
    """
    identity = (parsed.get('identity') or '').strip()
    state = (state_code or 'TX').upper()

    # Pattern 1: RTR-MT{model}-{N}.{site}
    m = re.match(r'RTR-MT\S+-(\d+)\.(.+)', identity, re.IGNORECASE)
    if m:
        number = m.group(1)
        site_part = m.group(2).strip()
        if re.match(r'^[A-Z]{2}-', site_part, re.IGNORECASE):
            return f'RTR-NK7250-{number}.{site_part}'
        return f'RTR-NK7250-{number}.{state}-{site_part}'

    # Pattern 2: {PREFIX}-{model}-{N}.{site}
    m = re.match(r'(?:RTR|SWT|BNG)[-_]\S+[-_](\d+)\.(.+)', identity, re.IGNORECASE)
    if m:
        number = m.group(1)
        site_part = m.group(2).strip()
        if re.match(r'^[A-Z]{2}-', site_part, re.IGNORECASE):
            return f'RTR-NK7250-{number}.{site_part}'
        return f'RTR-NK7250-{number}.{state}-{site_part}'

    # Pattern 3: Identity with dot separator
    if '.' in identity:
        parts = identity.split('.', 1)
        site_part = parts[1].strip()
        if re.match(r'^[A-Z]{2}-', site_part, re.IGNORECASE):
            return f'RTR-NK7250-1.{site_part}'
        return f'RTR-NK7250-1.{state}-{site_part}'

    # Pattern 4: Strip MT prefix, use identity as site
    if identity:
        cleaned = re.sub(r'^RTR-MT\S+-\d+[-.]?', '', identity, flags=re.IGNORECASE).strip()
        if cleaned:
            if re.match(r'^[A-Z]{2}-', cleaned, re.IGNORECASE):
                return f'RTR-NK7250-1.{cleaned}'
            return f'RTR-NK7250-1.{state}-{cleaned}'

    return f'RTR-NK7250-1.{state}-MIGRATED'


def _parse_mikrotik_for_nokia(config_text: str) -> dict:
    """
    Comprehensive MikroTik RouterOS parser for Nokia migration.
    Extracts all translatable data from the source config.

    Returns a dict with:
      identity, loopback_ip, router_id, interfaces, ip_addresses,
      ospf, bgp, bridges, vlans, static_routes, ntp_servers,
      snmp_communities, firewall_address_lists, users, mpls,
      ldp_deny_prefixes, interface_speeds, source_device,
      port_mapping, warnings, stats
    """
    text = config_text or ''
    warnings = []
    _clean = lambda v: (v or '').strip().strip('"').strip("'").strip()

    # ── Detect ROS version / syntax (inline — same logic as detect_routeros_syntax) ──
    syntax_info = {'version': 'unknown', 'bgp_syntax': 'unknown', 'ospf_syntax': 'unknown'}
    if 'by RouterOS 6.' in text or 'RouterOS 6.' in text:
        syntax_info['version'] = '6.x'
    elif 'by RouterOS 7.' in text or 'RouterOS 7.' in text or 'interface-template' in text:
        syntax_info['version'] = '7.x'
    if '/routing bgp peer' in text:
        syntax_info['bgp_syntax'] = 'peer'
    elif '/routing bgp connection' in text:
        syntax_info['bgp_syntax'] = 'connection'
    if '/routing ospf interface add' in text:
        syntax_info['ospf_syntax'] = 'interface'
    elif '/routing ospf interface-template' in text:
        syntax_info['ospf_syntax'] = 'interface-template'
    if syntax_info['version'] == 'unknown':
        if '/routing ospf interface-template' in text or '/routing bgp connection' in text or 'remote.address=' in text:
            syntax_info['version'] = '7.x'
        elif '/routing ospf interface' in text or '/routing bgp peer' in text:
            syntax_info['version'] = '6.x'
    is_v7 = syntax_info.get('version') == '7.x'

    # ── Detect source device (inline — simplified) ──
    source_device = {'model': 'unknown', 'type': 'unknown', 'management': 'ether1'}
    hm = re.search(r'(?m)^\s*#\s*model\s*=\s*(.+?)\s*$', text)
    if hm:
        header_model = hm.group(1).strip().strip('"').strip("'")
        try:
            if header_model in ROUTERBOARD_INTERFACES:
                specs = ROUTERBOARD_INTERFACES[header_model]
                source_device = {'model': specs['model'], 'type': specs['series'].lower(), 'management': specs.get('management_port', 'ether1')}
        except Exception:
            pass
    if source_device['model'] == 'unknown':
        im = re.search(r'(?i)\bMT(?:CCR)?(\d{3,4})\b', text)
        digits = im.group(1) if im else None
        if not digits:
            dm = re.search(r'(?i)\bCCR\s*(\d{3,4})\b', text)
            digits = dm.group(1) if dm else None
        _aliases = {'2216': 'CCR2216-1G-12XS-2XQ', '2116': 'CCR2116-12G-4S+', '2004': 'CCR2004-1G-12S+2XS', '1072': 'CCR1072-12G-4S+', '1036': 'CCR1036-12G-4S'}
        alias_key = _aliases.get(digits)
        if alias_key and alias_key in ROUTERBOARD_INTERFACES:
            specs = ROUTERBOARD_INTERFACES[alias_key]
            source_device = {'model': specs['model'], 'type': specs['series'].lower(), 'management': specs.get('management_port', 'ether1')}

    # ── Identity ──
    identity = None
    m = re.search(r'(?ms)^/system identity\s*\n\s*set\s+name=([^\n]+)\s*$', text)
    if not m:
        m = re.search(r'(?m)^\s*/system identity\s+set\s+name=([^\s]+)', text)
    if m:
        identity = _clean(m.group(1))

    # ── Loopback IP / System IP ──
    loopback_ip = None
    m = re.search(r'(?m)\badd\s+address=(\d+\.\d+\.\d+\.\d+(?:/\d+)?)\b[^\n]*\binterface=loop0\b', text)
    if m:
        loopback_ip = m.group(1) if '/' in m.group(1) else m.group(1) + '/32'
    if not loopback_ip:
        m = re.search(r'(?m)\brouter-id=(\d+\.\d+\.\d+\.\d+)\b', text)
        if m:
            loopback_ip = m.group(1) + '/32'

    # ── Router ID ──
    router_id = None
    if loopback_ip:
        router_id = loopback_ip.split('/')[0]
    m = re.search(r'(?m)\brouter-id=(\d+\.\d+\.\d+\.\d+)\b', text)
    if m:
        router_id = m.group(1)

    # ── Interface comments (descriptions) and speeds ──
    iface_comments = {}
    iface_speeds = {}   # sfp-sfpplus2 → '1000' etc.
    for m in re.finditer(r'(?m)^\s*set\s+\[?\s*find\s+default-name=([^\s\]]+)\s*\]?\s+(.*)', text):
        iface_name = _clean(m.group(1))
        rest = m.group(2)
        cm = re.search(r'comment=("([^"]+)"|(\S+))', rest)
        if cm:
            iface_comments[iface_name] = _clean(cm.group(2) or cm.group(3))
        # Extract speed setting: speed=1G-baseT-full, speed=10Gbps, speed=100M-baseT-full etc.
        sm = re.search(r'\bspeed=(\S+)', rest)
        if sm:
            speed_raw = sm.group(1).upper()
            if '100G' in speed_raw:
                iface_speeds[iface_name] = '100000'
            elif '25G' in speed_raw:
                iface_speeds[iface_name] = '25000'
            elif '10G' in speed_raw:
                iface_speeds[iface_name] = '10000'
            elif '1G' in speed_raw:
                iface_speeds[iface_name] = '1000'
            elif '100M' in speed_raw:
                iface_speeds[iface_name] = '100'

    # ── Bridges — detect bridge names early (needed to exclude from IP / port mapping) ──
    bridges = []
    bridge_names = set()
    for m in re.finditer(r'(?m)^\s*add\s+[^\n]*?\bname=(\S+)', text):
        ctx_lines = text[:m.start()].rsplit('\n', 15)
        if any('/interface bridge' == l.strip() for l in ctx_lines[-15:]):
            bname = _clean(m.group(1))
            if bname != 'loop0':  # loop0 is sometimes created as a bridge but is our loopback
                bridges.append({'name': bname, 'ports': [], 'vlans': [], 'ips': []})
                bridge_names.add(bname)
    # Bridge ports
    for m in re.finditer(r'(?m)^\s*add\s+[^\n]*?\bbridge=(\S+)[^\n]*?\binterface=(\S+)', text):
        bname = _clean(m.group(1))
        iface = _clean(m.group(2))
        for b in bridges:
            if b['name'] == bname:
                b['ports'].append(iface)
    # Also try reversed order: interface=X bridge=Y
    for m in re.finditer(r'(?m)^\s*add\s+[^\n]*?\binterface=(\S+)[^\n]*?\bbridge=(\S+)', text):
        iface = _clean(m.group(1))
        bname = _clean(m.group(2))
        for b in bridges:
            if b['name'] == bname and iface not in b['ports']:
                b['ports'].append(iface)
    # Bridge VLANs
    for m in re.finditer(r'(?m)^\s*add\s+[^\n]*?\bbridge=(\S+)[^\n]*?\bvlan-ids?=(\S+)', text):
        bname = _clean(m.group(1))
        vids = m.group(2).split(',')
        for b in bridges:
            if b['name'] == bname:
                b['vlans'].extend([v.strip() for v in vids if v.strip()])

    # ── IP Addresses (STRICT: only /ip address section) ──
    ip_addresses = []
    in_ip_address_section = False
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if not line or line.startswith('#'):
            continue
        if line.startswith('/'):
            # Track section transitions
            in_ip_address_section = line.startswith('/ip address') and 'firewall' not in line and 'dhcp' not in line.lower()
            # Handle inline: /ip address add address=X interface=Y
            if in_ip_address_section and 'add ' in line and 'address=' in line and 'interface=' in line:
                pass  # fall through
            else:
                continue
        if not in_ip_address_section:
            continue
        # Must be "add" line with address= and interface=
        if not line.startswith('add ') and 'add ' not in line:
            continue
        if 'address=' not in line or 'interface=' not in line:
            continue
        # Reject lines that have firewall-style params (dst-address, src-address, in-interface, chain=)
        if re.search(r'\b(dst-address|src-address|dst-port|src-port|in-interface|out-interface|chain|action|protocol)=', line):
            continue

        addr_m = re.search(r'\baddress=(\S+)', line)
        iface_m = re.search(r'\binterface=(\S+)', line)
        if not addr_m or not iface_m:
            continue
        addr = _clean(addr_m.group(1))
        iface = _clean(iface_m.group(1))
        # Validate address looks like an IP
        if not re.match(r'\d+\.\d+\.\d+\.\d+', addr):
            continue
        comment_m = re.search(r'\bcomment=("([^"]+)"|(\S+))', line)
        comment = _clean(comment_m.group(2) or comment_m.group(3)) if comment_m else ''
        disabled = 'disabled=yes' in line.lower()
        if disabled:
            continue
        if '/' not in addr:
            addr = addr + '/32' if iface == 'loop0' else addr + '/24'
        ip_addresses.append({
            'interface': iface,
            'address': addr,
            'comment': comment or iface_comments.get(iface, ''),
        })

    # Attach IPs to bridge records for reference
    for ip_entry in ip_addresses:
        for b in bridges:
            if ip_entry['interface'] == b['name']:
                b['ips'].append(ip_entry['address'])

    # ── OSPF ──
    ospf = {'areas': [], 'interfaces': [], 'router_id': router_id, 'found': False,
            'auth_key': None}
    # v7 interface-template — robust line-by-line with section tracking
    in_ospf_template = False
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if line.startswith('/'):
            in_ospf_template = line.startswith('/routing ospf interface-template')
            continue
        if not in_ospf_template or not line.startswith('add '):
            continue
        area_m = re.search(r'\barea=(\S+)', line)
        iface_m = re.search(r'\binterfaces?=(\S+)', line)
        if not area_m or not iface_m:
            continue
        area = _clean(area_m.group(1))
        iface = _clean(iface_m.group(1))
        ntype_m = re.search(r'\btype=(ptp|ptmp|broadcast|point-to-point)', line)
        ntype = 'point-to-point' if (ntype_m and 'ptp' in ntype_m.group(1).lower()) else ''
        cost_m = re.search(r'\bcost=(\d+)', line)
        cost = int(cost_m.group(1)) if cost_m else None
        auth_m = re.search(r'\bauth-key=(\S+)', line)
        if auth_m and not ospf['auth_key']:
            ospf['auth_key'] = _clean(auth_m.group(1))
        already = any(o['interface'] == iface for o in ospf['interfaces'])
        if not already:
            entry = {'interface': iface, 'area': area, 'type': ntype}
            if cost:
                entry['cost'] = cost
            ospf['interfaces'].append(entry)
        if area not in ospf['areas']:
            ospf['areas'].append(area)
        ospf['found'] = True
    # v6 ospf network
    for m in re.finditer(r'(?m)^\s*add\s+area=(\S+)\s+network=(\S+)', text):
        area = _clean(m.group(1))
        ospf['found'] = True
        if area not in ospf['areas']:
            ospf['areas'].append(area)
    # v6 ospf interface
    for m in re.finditer(r'(?m)^\s*add\s+interface=(\S+)(?:\s+network-type=(\S+))?', text):
        section_ctx = text[:m.start()].rsplit('\n', 20)
        if any('/routing ospf interface' in l and 'template' not in l for l in section_ctx[-20:]):
            iface = _clean(m.group(1))
            ntype = m.group(2) or ''
            if ntype == 'point-to-point':
                ntype = 'point-to-point'
            already = any(o['interface'] == iface for o in ospf['interfaces'])
            if not already:
                ospf['interfaces'].append({'interface': iface, 'area': 'backbone', 'type': ntype})
                ospf['found'] = True
    if not ospf['areas'] and ospf['found']:
        ospf['areas'] = ['backbone']

    # ── BGP ──
    bgp = {'as_number': None, 'router_id': router_id, 'peers': [], 'found': False}
    # AS number from template or instance
    as_m = re.search(r'(?m)(?:^/routing bgp (?:template|instance)[^\n]*\n\s*set[^\n]*|\badd[^\n]*)\bas=(\d+)', text)
    if not as_m:
        as_m = re.search(r'(?m)\bas=(\d+)', text)
    if as_m:
        bgp['as_number'] = int(as_m.group(1))
    # v7 connections — handle dotted params: remote.address=X .as=Y  (space before .as)
    in_bgp_conn = False
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if line.startswith('/'):
            in_bgp_conn = line.startswith('/routing bgp connection')
            continue
        if not in_bgp_conn or not line.startswith('add '):
            continue
        name_m = re.search(r'\bname=(\S+)', line)
        # Handle both "remote.address=X" and "remote-address=X"
        addr_m = re.search(r'\bremote[.\-]address=(\S+)', line)
        # Handle both "remote.as=N" and ".as=N" (continuation of remote prefix)
        ras_m = re.search(r'(?:\bremote\.as=|\.as=)(\d+)', line)
        if not name_m or not addr_m:
            continue
        peer_name = _clean(name_m.group(1))
        peer_addr = _clean(addr_m.group(1))
        remote_as = int(ras_m.group(1)) if ras_m else bgp.get('as_number')
        # Check disabled
        if re.search(r'\bdisabled=yes\b', line, re.IGNORECASE):
            continue
        if peer_addr and remote_as:
            bgp['peers'].append({
                'name': peer_name,
                'address': peer_addr,
                'remote_as': remote_as,
            })
            bgp['found'] = True
    # v6 peers (fallback if no v7 connections found)
    if not bgp['peers']:
        in_bgp_peer = False
        for raw_line in text.splitlines():
            line = raw_line.strip()
            if line.startswith('/'):
                in_bgp_peer = line.startswith('/routing bgp peer')
                continue
            if not in_bgp_peer or not line.startswith('add '):
                continue
            name_m = re.search(r'\bname=(\S+)', line)
            addr_m = re.search(r'\bremote-address=(\S+)', line)
            ras_m = re.search(r'\bremote-as=(\d+)', line)
            if not name_m or not addr_m:
                continue
            peer_name = _clean(name_m.group(1))
            peer_addr = _clean(addr_m.group(1))
            remote_as = int(ras_m.group(1)) if ras_m else bgp.get('as_number')
            if peer_addr and remote_as:
                bgp['peers'].append({
                    'name': peer_name,
                    'address': peer_addr,
                    'remote_as': remote_as,
                })
                bgp['found'] = True
    if not bgp['as_number'] and bgp['peers']:
        bgp['as_number'] = bgp['peers'][0]['remote_as']

    # ── Static Routes ──
    static_routes = []
    in_ip_route = False
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if line.startswith('/'):
            in_ip_route = line.startswith('/ip route') and 'firewall' not in line
            continue
        if not in_ip_route or not line.startswith('add '):
            continue
        dst_m = re.search(r'\bdst-address=(\S+)', line)
        gw_m = re.search(r'\bgateway=(\S+)', line)
        if not dst_m or not gw_m:
            continue
        dst = _clean(dst_m.group(1))
        gw = _clean(gw_m.group(1))
        if dst and gw and not gw.startswith('%'):
            static_routes.append({'dst': dst, 'gateway': gw})

    # ── NTP Servers ──
    ntp_servers = []
    in_ntp = False
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if line.startswith('/'):
            in_ntp = '/system ntp' in line
            continue
        if not in_ntp:
            continue
        addr_m = re.search(r'\baddress=(\S+)', line)
        if addr_m and line.startswith('add '):
            ntp_servers.append(_clean(addr_m.group(1)))
    if not ntp_servers:
        m = re.search(r'server-dns-names?=(\S+)', text)
        if m:
            ntp_servers = [s.strip() for s in m.group(1).split(',') if s.strip()]

    # ── SNMP communities ──
    snmp_communities = []
    in_snmp_comm = False
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if line.startswith('/'):
            in_snmp_comm = '/snmp community' in line
            continue
        if not in_snmp_comm:
            continue
        name_m = re.search(r'\bname=(\S+)', line)
        if name_m and line.startswith('add '):
            val = _clean(name_m.group(1))
            if val and val not in ('public', 'private'):
                snmp_communities.append(val)

    # ── Firewall address-lists ──
    address_lists = {}
    in_addr_list = False
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if line.startswith('/'):
            in_addr_list = '/ip firewall address-list' in line
            continue
        if not in_addr_list or not line.startswith('add '):
            continue
        list_m = re.search(r'\blist=(\S+)', line)
        addr_m = re.search(r'\baddress=(\S+)', line)
        if list_m and addr_m:
            list_name = _clean(list_m.group(1))
            addr = _clean(addr_m.group(1))
            if list_name not in address_lists:
                address_lists[list_name] = []
            address_lists[list_name].append(addr)

    # ── Users ──
    users = []
    for m in re.finditer(r'(?m)^\s*add\s+.*?\bname=(\S+).*?\bgroup=(\S+)', text):
        ctx = text[:m.start()].rsplit('\n', 10)
        if any('/user' == l.strip() or l.strip().startswith('/user ') for l in ctx[-10:]):
            uname = _clean(m.group(1))
            group = _clean(m.group(2))
            pw_m = re.search(r'\bpassword=(\S+)', m.group(0))
            pw = _clean(pw_m.group(1)) if pw_m else ''
            users.append({'name': uname, 'group': group, 'password': pw})

    # ── MPLS/LDP detection ──
    mpls = {
        'ldp_enabled': bool(re.search(r'/mpls ldp', text)),
        'ldp_interfaces': [],
        'found': False,
    }
    for m in re.finditer(r'(?m)^\s*add\s+interface=(\S+)', text):
        ctx = text[:m.start()].rsplit('\n', 10)
        if any('/mpls' in l for l in ctx[-10:]):
            mpls['ldp_interfaces'].append(_clean(m.group(1)))
            mpls['found'] = True
    if mpls['ldp_enabled']:
        mpls['found'] = True

    # ── LDP accept-filter deny prefixes (from /mpls ldp accept-filter) ──
    ldp_deny_prefixes = []
    in_ldp_accept = False
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if line.startswith('/'):
            in_ldp_accept = '/mpls ldp accept-filter' in line
            continue
        if not in_ldp_accept or not line.startswith('add '):
            continue
        if 'accept=no' in line:
            pfx_m = re.search(r'\bprefix=(\S+)', line)
            if pfx_m:
                ldp_deny_prefixes.append(_clean(pfx_m.group(1)))

    # ── Port mapping (MikroTik → Nokia) ──
    # Nokia 7250 IXR: card imm24-sfp++8-sfp28+2-qsfp28
    # Ports: 1/1/1..1/1/24 (SFP+/SFP28), connectors 1/1/c23..1/1/c32 (QSFP28 w/ breakout)
    port_mapping = {}
    mgmt_port = source_device.get('management', 'ether1')

    # ═══ Interface role classification ═══
    # Nokia 7250 is a TRANSPORT-ONLY router.  The fundamental rule:
    #   ► An interface gets a Nokia port ONLY if it has POSITIVE transport evidence.
    #   ► Everything else is excluded (deny-by-default).
    #
    # POSITIVE transport signals (any one is sufficient):
    #   1.  OSPF participation  (strongest — definitive transport)
    #   2.  Transport keyword in comment  (UPLINK, BACKHAUL, FIBER, TRUNK, …)
    #   3.  /30 or /31 address  (point-to-point link — very likely transport)
    #
    # NEGATIVE signals (force access even if Rule 3 would match):
    #   A.  Access keyword in comment  (NETONIX, SWITCH, OLT, Tarana names, …)
    #   B.  Interface is parent of VLANs going to bridges (customer aggregation)
    #   C.  Management port
    #
    # Tarana wireless radios use NATO/Greek alphabet naming:
    #   Alpha ###, Beta ###, Gamma ###, Delta ###, Echo ###, Foxtrot ###, etc.

    _ACCESS_KEYWORDS = re.compile(
        r'(?i)\b(NETONIX|LEGACY\s*NETONIX|SWITCH|NETONIX[-_ ]?SWITCH|'
        r'OLT|POWER|UPS|CAMERA|AP\b|CPE|CUSTOMER|DOWNSTREAM|WISP[-_ ]?SW|'
        r'ACCESS[-_ ]?SW|DSLAM|GPON|LEGACY[-_ ]?SW|LEGACY\b|'
        r'ALPHA\s*\d{2,3}|BETA\s*\d{2,3}|GAMMA\s*\d{2,3}|DELTA\s*\d{2,3}|'
        r'ECHO\s*\d{2,3}|FOXTROT\s*\d{2,3}|GOLF\s*\d{2,3}|HOTEL\s*\d{2,3}|'
        r'INDIA\s*\d{2,3}|JULIET\s*\d{2,3}|KILO\s*\d{2,3}|LIMA\s*\d{2,3}|'
        r'MIKE\s*\d{2,3}|NOVEMBER\s*\d{2,3}|OSCAR\s*\d{2,3}|PAPA\s*\d{2,3}|'
        r'QUEBEC\s*\d{2,3}|ROMEO\s*\d{2,3}|SIERRA\s*\d{2,3}|TANGO\s*\d{2,3}|'
        r'UNIFORM\s*\d{2,3}|VICTOR\s*\d{2,3}|WHISKEY\s*\d{2,3}|XRAY\s*\d{2,3}|'
        r'YANKEE\s*\d{2,3}|ZULU\s*\d{2,3}|TARANA\b|'
        r'UNICORN\s*MGMT|MGMT\b)', re.IGNORECASE
    )
    _TRANSPORT_KEYWORDS = re.compile(
        r'(?i)\b(UPLINK|BACKHAUL|TRANSPORT|FIBER|TRUNK|CORE|CR\d|BNG|PE[-_ ]|'
        r'P[-_ ]LINK|RING|MPLS|AGGREGATE)', re.IGNORECASE
    )

    # ── Detect VLAN interfaces and their parents ──
    # Track BOTH:
    #   - vlan_iface_names: the VLAN sub-interface names (e.g., 'vlan1000-sfp-sfpplus8')
    #     These are NOT physical ports — they must NEVER get Nokia port assignments.
    #   - vlan_parent_ifaces: the physical parent interfaces carrying VLANs
    #     These carry customer/service VLANs and should be excluded from Nokia.
    vlan_parent_ifaces = set()
    vlan_iface_names = set()   # VLAN sub-interfaces — NOT physical ports
    in_vlan_section = False
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if line.startswith('/'):
            in_vlan_section = line.startswith('/interface vlan')
            continue
        if not in_vlan_section or not line.startswith('add '):
            continue
        # Collect the VLAN sub-interface name
        nm = re.search(r'\bname=(\S+)', line)
        if nm:
            vlan_iface_names.add(_clean(nm.group(1)))
        # Collect the parent physical interface
        pim = re.search(r'\binterface=(\S+)', line)
        if pim:
            parent = _clean(pim.group(1))
            if parent and parent not in bridge_names and parent != 'loop0':
                vlan_parent_ifaces.add(parent)

    # Build set of transport interfaces from OSPF / BGP / MPLS participation
    ospf_ifaces = {o['interface'] for o in ospf.get('interfaces', []) if o.get('interface')}
    bgp_peer_addrs = {p['address'] for p in bgp.get('peers', [])}

    # Classify each interface — DENY BY DEFAULT (unknown → excluded)
    interface_roles = {}  # iface_name → 'transport' | 'access' | 'unknown'
    for iface_name in set(list(iface_comments.keys()) + [e['interface'] for e in ip_addresses]):
        if iface_name == 'loop0' or iface_name in bridge_names:
            continue
        if iface_name == mgmt_port:
            continue  # management port handled separately
        if iface_name in vlan_iface_names:
            continue  # VLAN sub-interfaces are NOT physical ports
        comment = iface_comments.get(iface_name, '').upper()
        role = 'unknown'  # default → will be EXCLUDED from Nokia

        # Rule 1: If interface participates in OSPF → transport (strongest signal)
        if iface_name in ospf_ifaces:
            role = 'transport'
        # Rule 2: VLAN parent → access (carries customer VLANs to bridges)
        elif iface_name in vlan_parent_ifaces:
            role = 'access'
        # Rule 3: Comment-based classification
        elif _ACCESS_KEYWORDS.search(comment):
            role = 'access'
        elif _TRANSPORT_KEYWORDS.search(comment):
            role = 'transport'
        # Rule 4: If interface has a /30 or /31 address → likely point-to-point transport
        else:
            for ip_entry in ip_addresses:
                if ip_entry['interface'] == iface_name:
                    addr = ip_entry.get('address', '')
                    if addr.endswith('/30') or addr.endswith('/31'):
                        role = 'transport'
                        break

        interface_roles[iface_name] = role

    # ► TRANSPORT-ONLY: only interfaces with positive transport evidence get Nokia ports
    transport_ifaces = {k for k, v in interface_roles.items() if v == 'transport'}
    # All non-transport (access + unknown) are excluded
    excluded_ifaces = {k for k, v in interface_roles.items() if v != 'transport'}

    # ── Non-physical interface set: VLAN sub-interfaces, bridges, loopback, management ──
    # These must NEVER receive Nokia 1/1/X port assignments.
    _non_physical = bridge_names | vlan_iface_names | {'loop0', mgmt_port}

    # Collect only PHYSICAL TRANSPORT interfaces (not bridges, VLANs, loop0, mgmt, or excluded)
    all_physical_ifaces = set()
    for ip_entry in ip_addresses:
        iface = ip_entry['interface']
        if iface not in _non_physical and iface in transport_ifaces:
            all_physical_ifaces.add(iface)
    for iface_name in iface_comments:
        if iface_name not in _non_physical and iface_name in transport_ifaces:
            all_physical_ifaces.add(iface_name)
    for o in ospf.get('interfaces', []):
        iface = o['interface']
        if iface not in _non_physical:
            all_physical_ifaces.add(iface)  # OSPF → always transport (but only physical ports)
    # NOTE: Bridge member ports are NOT added to all_physical_ifaces.
    # Nokia 7250 is a transport router — bridge member ports stay on the
    # co-located MikroTik that handles DHCP/LAN.  We track them in
    # port_mapping as 'bridge-member' for UI display only.
    bridge_member_ports = set()
    for b in bridges:
        for port in b['ports']:
            bridge_member_ports.add(port)

    # Sort physical interfaces by type then number for deterministic Nokia port numbering
    sorted_phys = sorted(all_physical_ifaces, key=lambda x: (
        0 if x.startswith('sfp28-') else
        1 if x.startswith('sfp-sfpplus') else
        2 if x.startswith('sfp') and not x.startswith('sfp28') and not x.startswith('sfp-sfpplus') else
        3 if x.startswith('qsfp') else
        4 if x.startswith('ether') else
        5,
        int(re.search(r'(\d+)', x).group(1)) if re.search(r'(\d+)', x) else 999
    ))

    # Assign Nokia ports
    nokia_port_counter = 1
    # loopback always
    port_mapping['loop0'] = {'nokia_port': 'system', 'type': 'loopback'}
    # management
    if mgmt_port:
        port_mapping[mgmt_port] = {'nokia_port': 'A/1', 'type': 'management'}

    for iface in sorted_phys:
        if iface == mgmt_port:
            continue  # already mapped
        if iface.startswith('qsfp'):
            num = int(re.search(r'(\d+)', iface).group(1)) if re.search(r'(\d+)', iface) else 1
            connector_id = 22 + num  # c23, c24, ...
            port_mapping[iface] = {
                'nokia_port': f'1/1/c{connector_id}/1',
                'nokia_connector': f'1/1/c{connector_id}',
                'type': 'connector-100g',
                'speed': iface_speeds.get(iface, '100000'),
            }
            continue
        # Default speed from interface type, overridden by config-extracted speed
        default_speed = '25000' if 'sfp28' in iface else '10000' if 'sfp' in iface else '1000'
        port_mapping[iface] = {
            'nokia_port': f'1/1/{nokia_port_counter}',
            'type': 'sfp' if 'sfp' in iface else 'ethernet',
            'speed': iface_speeds.get(iface, default_speed),
        }
        nokia_port_counter += 1

    # Add bridge entries to port_mapping for UI display (type='bridge')
    for b in bridges:
        if b['name'] not in port_mapping:
            port_mapping[b['name']] = {
                'nokia_port': 'VPLS/SAP',
                'type': 'bridge',
                'bridge_ports': b['ports'],
                'bridge_ips': b['ips'],
            }
    # Add bridge member ports for UI display (type='bridge-member') — NOT on Nokia
    for bp in sorted(bridge_member_ports):
        if bp not in port_mapping:
            # Find which bridge this port belongs to
            parent_bridge = next((b['name'] for b in bridges if bp in b['ports']), 'unknown')
            port_mapping[bp] = {
                'nokia_port': '— (on MikroTik)',
                'type': 'bridge-member',
                'parent_bridge': parent_bridge,
            }
    # Add access/downstream & unclassified ports for UI display — NOT on Nokia
    # These are interfaces going to Netonix switches, OLTs, Tarana radios,
    # VLAN parents (customer aggregation), or any interface without transport evidence.
    for ap in sorted(excluded_ifaces):
        if ap not in port_mapping and ap != mgmt_port:
            comment = iface_comments.get(ap, ap)
            role_tag = interface_roles.get(ap, 'unknown')
            reason = 'downstream' if role_tag == 'access' else 'no transport evidence'
            if ap in vlan_parent_ifaces:
                reason = 'VLAN parent (customer aggregation)'
            port_mapping[ap] = {
                'nokia_port': '— (not on Nokia)',
                'type': 'access',
                'role': reason,
                'comment': comment,
            }

    if not identity:
        warnings.append('No /system identity found — using placeholder')
    if not loopback_ip:
        warnings.append('No loopback IP (loop0) or router-id found')
    if not ospf['found']:
        warnings.append('No OSPF configuration detected')
    if not bgp['found']:
        warnings.append('No BGP configuration detected')
    if not mpls['found']:
        warnings.append('No MPLS/LDP configuration detected — VPLS services may require manual setup')
    if bridge_names:
        warnings.append(f'Bridge interfaces detected: {", ".join(sorted(bridge_names))} — IPs on bridges are service-side (VPLS), not router interfaces')
    if bridge_member_ports:
        warnings.append(f'Bridge member ports excluded from Nokia: {", ".join(sorted(bridge_member_ports))} — these stay on the co-located MikroTik for DHCP/LAN')
    if excluded_ifaces:
        access_labels = [f'{ap} ({iface_comments.get(ap, "unclassified")})' for ap in sorted(excluded_ifaces)]
        warnings.append(f'Non-transport ports excluded from Nokia: {", ".join(access_labels)} — only OSPF/backhaul/fiber interfaces migrate to the 7250')

    # All interfaces for stats (physical + loopback)
    all_ifaces_used = all_physical_ifaces | {'loop0'} | bridge_names

    # Stats
    stats = {
        'interfaces_found': len(all_physical_ifaces),
        'access_excluded': len(excluded_ifaces),
        'ip_addresses': len(ip_addresses),
        'ospf_interfaces': len(ospf.get('interfaces', [])),
        'bgp_peers': len(bgp.get('peers', [])),
        'static_routes': len(static_routes),
        'bridges': len(bridges),
        'ntp_servers': len(ntp_servers),
        'users': len(users),
        'mpls_interfaces': len(mpls.get('ldp_interfaces', [])),
        'ldp_deny_prefixes': len(ldp_deny_prefixes),
        'source_model': source_device.get('model', 'unknown'),
        'ros_version': syntax_info.get('version', 'unknown'),
    }

    return {
        'identity': identity,
        'loopback_ip': loopback_ip,
        'router_id': router_id,
        'interfaces': iface_comments,
        'ip_addresses': ip_addresses,
        'ospf': ospf,
        'bgp': bgp,
        'bridges': bridges,
        'bridge_names': sorted(bridge_names),
        'vlan_iface_names': sorted(vlan_iface_names),
        'static_routes': static_routes,
        'ntp_servers': ntp_servers,
        'snmp_communities': snmp_communities,
        'firewall_address_lists': address_lists,
        'users': users,
        'mpls': mpls,
        'ldp_deny_prefixes': ldp_deny_prefixes,
        'interface_speeds': iface_speeds,
        'source_device': {
            'model': source_device.get('model', 'unknown'),
            'type': source_device.get('type', 'unknown'),
        },
        'port_mapping': port_mapping,
        'warnings': warnings,
        'stats': stats,
        'detected_state': _detect_nokia_state(config_text),
        'nokia_system_name': None,  # Populated after state is confirmed
    }


def _build_nokia_config(parsed: dict, nokia_params: dict = None) -> str:
    """
    Build Nokia SR OS classic CLI configuration from parsed MikroTik data.
    Dynamically selects in-state (TX) or out-of-state profile based on state_code.

    Args:
        parsed: Output from _parse_mikrotik_for_nokia()
        nokia_params: Optional overrides dict with:
            state_code, nokia_system_name, timezone, sdp_far_end, vpls_ids,
            autonomous_system, card_type, nokia_creds, ldp_deny_prefixes,
            ntp_servers, mgmt_acl
    """
    p = dict(nokia_params or {})
    preserve_ips = bool(p.pop('preserve_ips', True))

    # ── State/region profile ──
    state_code = (p.get('state_code') or parsed.get('detected_state', {}).get('state_code') or 'TX').upper()
    profile = _NOKIA_STATE_PROFILES.get(state_code, _NOKIA_STATE_PROFILES['TX'])
    is_instate = profile.get('is_instate', True)

    # ── System name ──
    nokia_name = p.get('nokia_system_name') or _generate_nokia_system_name(parsed, state_code)

    # ── Loopback IP: user can override with a new IP for the Nokia 7250 ──
    loopback_override = p.get('loopback_override', '').strip()
    if loopback_override:
        # Validate CIDR
        if '/' not in loopback_override:
            loopback_override = loopback_override + '/32'
        loopback = loopback_override
    else:
        loopback = parsed.get('loopback_ip') or '10.0.0.1/32'
    router_id = loopback.split('/')[0]
    as_num = p.get('autonomous_system') or (parsed.get('bgp', {}).get('as_number')) or 26077
    tz_key = p.get('timezone') or profile.get('tz', 'CST')
    tz = _NOKIA_TZ_MAP.get(tz_key)
    card_type = p.get('card_type', 'imm24-sfp++8-sfp28+2-qsfp28')

    # SDP far-ends from profile (allow single override for backward compat)
    sdp_far_ends = profile.get('sdp_far_ends', ['10.249.0.200'])
    if p.get('sdp_far_end'):
        sdp_far_ends = [p['sdp_far_end']]  # User override → single SDP

    # VPLS IDs from profile vpls_base or user override
    vpls_base = profile.get('vpls_base', 245)
    vpls_ids = p.get('vpls_ids', [f'1{vpls_base}', f'2{vpls_base}', f'3{vpls_base}', f'4{vpls_base}'])
    vpls_vlans = ['1000', '2000', '3000', '4000']

    # Credentials from env (server-side) or overrides
    creds = p.get('nokia_creds', {})
    snmp_community = creds.get('snmp_community') or os.getenv('NOKIA7250_SNMP_COMMUNITY', 'public')
    nlroot_pw = creds.get('nlroot_pw') or os.getenv('NOKIA7250_NLROOT_PW', 'changeme')
    admin_pw = creds.get('admin_pw') or os.getenv('NOKIA7250_ADMIN_PW', 'changeme')
    bgp_key = creds.get('bgp_auth_key') or os.getenv('NOKIA7250_BGP_AUTH_KEY', 'changeme')

    ntp_servers = p.get('ntp_servers') or parsed.get('ntp_servers') or profile.get('ntp', _NOKIA_DEFAULT_NTP)
    # For in-state: LDP deny prefixes; for out-of-state: LDP allow prefixes come from profile
    ldp_deny = parsed.get('ldp_deny_prefixes') or p.get('ldp_deny_prefixes') or _NOKIA_DEFAULT_LDP_DENY
    mgmt_acl = p.get('mgmt_acl') or profile.get('mgmt_acl', _NOKIA_DEFAULT_MGMT_ACL)
    acl_dst_port = profile.get('acl_dst_port', False)
    ospf_auth = parsed.get('ospf', {}).get('auth_key')

    # OSPF area: use profile default, but allow parser-detected area or user override
    ospf_area_override = p.get('ospf_area')
    profile_ospf_area = profile.get('ospf_area', '0.0.0.0')

    # Merge source managerIP entries into management ACL
    source_mgmt = parsed.get('firewall_address_lists', {}).get('managerIP', [])
    merged_acl = list(mgmt_acl)
    for addr in source_mgmt:
        if addr not in merged_acl:
            merged_acl.append(addr)

    port_map = parsed.get('port_mapping', {})
    ip_addresses = parsed.get('ip_addresses', [])
    ospf = parsed.get('ospf', {})
    bgp_data = parsed.get('bgp', {})
    bridges = parsed.get('bridges', [])
    bridge_names = set(parsed.get('bridge_names', []))
    static_routes = parsed.get('static_routes', [])
    mpls_data = parsed.get('mpls', {})

    # Build list of router interfaces (exclude loopback, bridges, and access/downstream)
    # Deduplicate by Nokia port — multiple IPs on same physical interface
    # use first as primary, extras as secondary addresses
    router_ifaces = []
    seen_ports = {}  # nokia_port → index in router_ifaces
    bridge_ip_entries = []  # IPs on bridges — service-side, not router interfaces
    for entry in ip_addresses:
        iface = entry['interface']
        if iface == 'loop0':
            continue
        # Skip bridge interfaces — these are service-side (VPLS/SAP)
        if iface in bridge_names:
            bridge_ip_entries.append(entry)
            continue
        pm = port_map.get(iface, {})
        nokia_port = pm.get('nokia_port')
        # Skip interfaces without Nokia ports, VPLS/SAP, access/downstream, bridge-member
        if not nokia_port or nokia_port == 'VPLS/SAP':
            continue
        if not nokia_port.startswith(('1/1/', 'A/')):
            continue  # Skip non-Nokia ports (e.g. '— (not on Nokia)', '— (on MikroTik)')
        if pm.get('type') in ('access', 'bridge-member', 'management'):
            continue
        desc = entry.get('comment') or parsed.get('interfaces', {}).get(iface, '') or iface
        speed = pm.get('speed', '10000')
        # Deduplicate by Nokia port
        if nokia_port in seen_ports:
            # Add as secondary address
            idx = seen_ports[nokia_port]
            if 'secondary_addresses' not in router_ifaces[idx]:
                router_ifaces[idx]['secondary_addresses'] = []
            router_ifaces[idx]['secondary_addresses'].append(entry['address'])
            continue
        ri_entry = {
            'name': desc if desc else iface,
            'address': entry['address'],
            'port': nokia_port,
            'mt_iface': iface,
            'speed': speed,
            'is_connector': pm.get('type') == 'connector-100g',
            'connector': pm.get('nokia_connector'),
            'mtu': '9212',
        }
        seen_ports[nokia_port] = len(router_ifaces)
        router_ifaces.append(ri_entry)

    # Deduplicate connectors
    connectors = {}
    for ri in router_ifaces:
        if ri.get('is_connector') and ri.get('connector'):
            connectors[ri['connector']] = ri

    # Normalize OSPF area IDs: names containing "backbone" → 0.0.0.0
    def _normalize_area(area):
        if not area:
            return '0.0.0.0'
        if area in ('0', '0.0.0.0'):
            return '0.0.0.0'
        if 'backbone' in area.lower():
            return '0.0.0.0'
        # Try dotted-quad — leave as-is if it looks like one
        if re.match(r'\d+\.\d+\.\d+\.\d+', area):
            return area
        # Try numeric area → convert to dotted quad
        try:
            num = int(area)
            return f'0.0.0.{num}' if num < 256 else area
        except ValueError:
            return area

    L = []
    echo = lambda s: L.extend([f"#{'--' * 25}", f'echo "{s}"', f"#{'--' * 25}"])

    # ── PREAMBLE ──
    L.append('# ================================================')
    L.append(f'# Nokia SR OS Configuration — Migrated from MikroTik')
    L.append(f'# Source: {parsed.get("source_device", {}).get("model", "unknown")} ({parsed.get("identity", "unknown")})')
    L.append(f'# Profile: {profile.get("name", state_code)} ({"In-State" if is_instate else "Out-of-State"})')
    if loopback_override:
        L.append(f'# Loopback: NEW {loopback} (overriding MikroTik {parsed.get("loopback_ip", "N/A")})')
    else:
        L.append(f'# Loopback: {loopback} (from MikroTik)')
    L.append(f'# Generated by NOC Config Maker — Nokia Migration')
    L.append('# ================================================')
    L.append('')
    L.append('configure global')
    L.append('/configure system management-interface cli classic-cli')
    L.append('/configure system management-interface configuration-mode classic')
    L.append('commit')
    L.append('logout')
    L.append('')
    L.append('')
    L.append('# BOF')
    L.append('/bof primary-config cf3:/startup-config')
    L.append('/bof save')
    L.append('/admin save')
    L.append('')
    L.append('exit all')
    L.append('configure')

    # ── SYSTEM ──
    echo('System Configuration')
    L.append('    system')
    L.append(f'        name "{nokia_name}"')
    L.append(f'        location "Migrated from MikroTik {parsed.get("source_device", {}).get("model", "")}"')
    L.append('        rollback')
    L.append('            rollback-location "cf3:/checkpoint_db"')
    L.append('        exit')
    L.append('        time')
    L.append('            ntp')
    L.append('                no shutdown')
    L.append('            exit')
    L.append('            sntp')
    L.append('                shutdown')
    L.append('            exit')
    if tz:
        L.append(f'            dst-zone {tz["dst"]}')
        L.append(f'                start {tz["start"]}')
        L.append(f'                end {tz["end"]}')
        L.append('            exit')
        L.append(f'            zone {tz["zone"]}')
    else:
        L.append('            zone UTC')
    L.append('        exit')
    L.append('    exit')

    # ── SECURITY ──
    echo('System Security Configuration')
    L.append('    system')
    L.append('        security')
    L.append('            management-access-filter')
    L.append('                ip-filter')
    L.append('                    shutdown')
    L.append('                    default-action permit')
    for i, acl_ip in enumerate(merged_acl):
        L.append(f'                    entry {i + 1}')
        L.append(f'                        src-ip {acl_ip}')
        if acl_dst_port:
            L.append('                        dst-port 22 65535')
        L.append('                        action permit')
        L.append('                    exit')
    L.append('                    no shutdown')
    L.append('                exit')
    L.append('            exit')

    # Administrative profile
    L.append('            profile "administrative"')
    L.append('                netconf')
    L.append('                    base-op-authorization')
    for op in ['action', 'cancel-commit', 'close-session', 'commit', 'copy-config',
               'create-subscription', 'delete-config', 'discard-changes', 'edit-config',
               'get', 'get-config', 'get-data', 'get-schema', 'kill-session', 'lock', 'validate']:
        L.append(f'                        {op}')
    L.append('                    exit')
    L.append('                exit')
    for entry in [
        (10, 'configure system security', 'permit'), (20, 'show system security', 'permit'),
        (30, 'tools perform security', 'permit'), (40, 'tools dump security', 'permit'),
        (42, 'tools dump system security', 'permit'), (50, 'admin system security', 'permit'),
        (100, 'configure li', 'deny'), (110, 'show li', 'deny'),
        (111, 'clear li', 'deny'), (112, 'tools dump li', 'deny'),
    ]:
        L.append(f'                entry {entry[0]}')
        L.append(f'                    match "{entry[1]}"')
        L.append(f'                    action {entry[2]}')
        L.append('                exit')
    L.append('            exit')

    # ── Users ──
    L.append(f'            user "nlroot"')
    L.append(f'                password "{nlroot_pw}"')
    L.append('                access console ftp snmp netconf grpc')
    L.append('                no restricted-to-home')
    L.append('                console')
    L.append('                    member "default"')
    L.append('                    member "administrative"')
    L.append('                exit')
    L.append('            exit')
    L.append(f'            user "admin"')
    L.append(f'                password "{admin_pw}"')
    L.append('                access console ftp snmp netconf grpc')
    L.append('                no restricted-to-home')
    L.append('                console')
    L.append('                    member "default"')
    L.append('                    member "administrative"')
    L.append('                exit')
    L.append('            exit')
    L.append('            snmp')
    L.append(f'                community "{snmp_community}" r version both')
    L.append('            exit')
    L.append('            telnet')
    L.append('            exit')
    L.append('        exit')
    L.append('    exit')

    # ── LOGIN CONTROL ──
    echo('System Login Control Configuration')
    L.append('    system')
    L.append('        login-control')
    L.append('            idle-timeout 90')
    L.append('        exit')
    L.append('    exit')

    # ── LOG ──
    echo('Log Configuration')
    L.append('    log')
    L.append('    exit')

    # ── OPER-GROUPS ──
    echo('Oper-Groups (Declarations) Configuration')
    L.append('    service')
    L.append('    exit')

    # ── CARD ──
    echo('Card Configuration')
    L.append('    card 1')
    L.append(f'        card-type {card_type}')
    L.append('        mda 1')
    L.append('            no shutdown')
    L.append('        exit')
    L.append('        no shutdown')
    L.append('    exit')

    # ── CONNECTORS ──
    if connectors:
        echo('Connector Configuration')
        for conn_port, c_data in connectors.items():
            L.append(f'    port {conn_port}')
            L.append(f'        description "{c_data["name"]}"')
            L.append('        connector')
            L.append('            breakout c1-100g')
            L.append('        exit')
            L.append('        no shutdown')
            L.append('    exit')

    # ── PORTS ──
    echo('Port Configuration')
    seen_port_ids = set()
    for ri in router_ifaces:
        if not ri.get('port') or ri['port'] == 'A/1':
            continue
        if ri['port'] in seen_port_ids:
            continue
        seen_port_ids.add(ri['port'])
        L.append(f'    port {ri["port"]}')
        L.append(f'        description "{ri["name"]}"')
        L.append('        ethernet')
        L.append(f'            speed {ri["speed"]}')
        L.append('            no autonegotiate')
        if ri.get('is_connector'):
            L.append('            rs-fec-mode cl91-514-528')
        L.append('        exit')
        L.append('        no shutdown')
        L.append('    exit')
    # NOTE: Bridge member ports are NOT configured on the Nokia 7250.
    # They stay on the co-located MikroTik router for DHCP/LAN.
    L.append('    port A/1')
    L.append('    exit')

    # ── SYNC-IF-TIMING ──
    echo('System Sync-If-Timing Configuration')
    L.append('    system')
    L.append('        sync-if-timing')
    L.append('            begin')
    L.append('            commit')
    L.append('        exit')
    L.append('    exit')

    # ── LAG ──
    # Nokia transport LAG — no port assignments (bridge member ports stay on MikroTik)
    has_bridge = bool(bridges)
    if has_bridge:
        echo('LAG Configuration')
        L.append('    lag 1')
        L.append('        mode hybrid')
        L.append('        encap-type dot1q')
        L.append('        lacp active administrative-key 32768')
        L.append('        no shutdown')
        L.append('    exit')

    # ── MANAGEMENT ROUTER ──
    echo('Management Router Configuration')
    L.append('    router management')
    L.append('    exit')
    L.append('')
    if preserve_ips:
        L.append('# CLASSIC CLI INTERFACE STANZAS')
        L.append(f'/configure router interface "system" address {loopback}')
        L.append('/configure router interface "system" no shutdown')
        seen_cli_ports = set()
        for ri in router_ifaces:
            if not ri.get('port') or ri['port'] == 'A/1':
                continue
            ri_key = ri['port']
            if ri_key in seen_cli_ports:
                continue
            seen_cli_ports.add(ri_key)
            L.append(f'/configure router interface "{ri["name"]}" address {ri["address"]}')
            for sec_addr in ri.get('secondary_addresses', []):
                L.append(f'/configure router interface "{ri["name"]}" secondary {sec_addr}')
            L.append(f'/configure router interface "{ri["name"]}" port {ri["port"]}')
            L.append(f'/configure router interface "{ri["name"]}" no shutdown')
        L.append('')

    # ── ROUTER BASE ──
    echo('"Router (Network Side) Configuration"')
    L.append('    router Base')
    L.append('        interface "system"')
    L.append(f'            address {loopback}')
    L.append('            no shutdown')
    L.append('        exit')
    seen_ri_names = set()
    for ri in router_ifaces:
        if not ri.get('port') or ri['port'] == 'A/1':
            continue
        ri_key = ri['port']
        if ri_key in seen_ri_names:
            continue
        seen_ri_names.add(ri_key)
        L.append(f'        interface "{ri["name"]}"')
        L.append(f'            address {ri["address"]}')
        # Secondary addresses
        for sec_addr in ri.get('secondary_addresses', []):
            L.append(f'            address {sec_addr} secondary')
        L.append(f'            port {ri["port"]}')
        L.append('            ingress')
        L.append('            exit')
        L.append('            no shutdown')
        L.append('        exit')
    L.append(f'        autonomous-system {as_num}')
    L.append(f'        router-id {router_id}')

    # ── OSPF ──
    if ospf.get('found') or ospf.get('interfaces'):
        # Determine OSPF area: user override > parser-detected > profile default
        areas_used = set()
        for oi in ospf.get('interfaces', []):
            area = oi.get('area', 'backbone')
            areas_used.add(_normalize_area(area))
        if not areas_used:
            areas_used.add(profile_ospf_area)
        if ospf_area_override:
            areas_used = {ospf_area_override}

        if is_instate:
            # ── IN-STATE: single OSPF instance 0 ──
            echo('OSPFv2 Configuration')
            L.append(f'        ospf 0 {router_id}')
            if ospf_auth:
                L.append(f'            authentication-key "{ospf_auth}"')
            for area_id in sorted(areas_used):
                L.append(f'            area {area_id}')
                L.append('                interface "system"')
                L.append('                    no shutdown')
                L.append('                exit')
                for ri in router_ifaces:
                    if not ri.get('port') or ri['port'] == 'A/1':
                        continue
                    mt_iface = ri.get('mt_iface', '')
                    matching_ospf = [
                        o for o in ospf.get('interfaces', [])
                        if o['interface'] == mt_iface and _normalize_area(o.get('area', 'backbone')) == area_id
                    ]
                    if matching_ospf:
                        oi = matching_ospf[0]
                        itype = oi.get('type', '')
                        L.append(f'                interface "{ri["name"]}"')
                        if 'point-to-point' in itype:
                            L.append('                    interface-type point-to-point')
                        cost = oi.get('cost')
                        if cost:
                            L.append(f'                    metric {cost}')
                        L.append('                    no shutdown')
                        L.append('                exit')
                L.append('            exit')
            L.append('            no shutdown')
            L.append('        exit')
        else:
            # ── OUT-OF-STATE: dual OSPF instances (0=shutdown, 1=active) ──
            echo('OSPFv2 Configuration')
            L.append('        ospf 0')
            L.append('            shutdown')
            for area_id in sorted(areas_used):
                L.append(f'            area {area_id}')
                L.append('            exit')
            L.append('        exit')

            echo('OSPFv2 (Inst: 1) Configuration')
            L.append(f'        ospf 1 {router_id}')
            for area_id in sorted(areas_used):
                L.append(f'            area {area_id}')
                L.append('                interface "system"')
                L.append('                    no shutdown')
                L.append('                exit')
                for ri in router_ifaces:
                    if not ri.get('port') or ri['port'] == 'A/1':
                        continue
                    mt_iface = ri.get('mt_iface', '')
                    matching_ospf = [
                        o for o in ospf.get('interfaces', [])
                        if o['interface'] == mt_iface and _normalize_area(o.get('area', 'backbone')) == area_id
                    ]
                    if matching_ospf:
                        oi = matching_ospf[0]
                        itype = oi.get('type', '')
                        L.append(f'                interface "{ri["name"]}"')
                        if 'point-to-point' in itype:
                            L.append('                    interface-type point-to-point')
                        cost = oi.get('cost')
                        if cost:
                            L.append(f'                    metric {cost}')
                        # Out-of-state uses message-digest auth per interface
                        if ospf_auth:
                            L.append('                    authentication-type message-digest')
                            L.append(f'                    message-digest-key 1 md5 "{ospf_auth}"')
                        L.append('                    no shutdown')
                        L.append('                exit')
                L.append('            exit')
            L.append('            no shutdown')
            L.append('        exit')

    # ── MPLS ──
    echo('MPLS Configuration')
    L.append('        mpls')
    L.append('            interface "system"')
    L.append('                no shutdown')
    L.append('            exit')
    seen_mpls = set()
    for ri in router_ifaces:
        if not ri.get('port') or ri['port'] == 'A/1':
            continue
        if ri['port'] in seen_mpls:
            continue
        seen_mpls.add(ri['port'])
        L.append(f'            interface "{ri["name"]}"')
        L.append('                no shutdown')
        L.append('            exit')
    L.append('        exit')

    # ── RSVP ──
    echo('RSVP Configuration')
    L.append('        rsvp')
    if profile.get('rsvp_shutdown'):
        L.append('            shutdown')
    L.append('            interface "system"')
    L.append('                no shutdown')
    L.append('            exit')
    seen_rsvp = set()
    for ri in router_ifaces:
        if not ri.get('port') or ri['port'] == 'A/1':
            continue
        if ri['port'] in seen_rsvp:
            continue
        seen_rsvp.add(ri['port'])
        L.append(f'            interface "{ri["name"]}"')
        L.append('                no shutdown')
        L.append('            exit')
    if not profile.get('rsvp_shutdown'):
        L.append('            no shutdown')
    L.append('        exit')

    # ── MPLS LSP ──
    echo('MPLS LSP Configuration')
    L.append('        mpls')
    L.append('            no shutdown')
    L.append('        exit')

    # ── LDP ──
    ldp_policy = profile.get('ldp_policy_name', 'LDP-FILTER-PS')
    echo('LDP Configuration')
    L.append('        ldp')
    L.append(f'            import "{ldp_policy}"')
    L.append('            import-pmsi-routes')
    L.append('            exit')
    if is_instate:
        L.append('            tcp-session-parameters')
        L.append('            exit')
    L.append('            interface-parameters')
    seen_ldp = set()
    for ri in router_ifaces:
        if not ri.get('port') or ri['port'] == 'A/1':
            continue
        if ri['port'] in seen_ldp:
            continue
        seen_ldp.add(ri['port'])
        L.append(f'                interface "{ri["name"]}" dual-stack')
        L.append('                    ipv4')
        L.append('                        no shutdown')
        L.append('                    exit')
        L.append('                    no shutdown')
        L.append('                exit')
    L.append('            exit')
    L.append('            targeted-session')
    L.append('            exit')
    L.append('            no shutdown')
    L.append('        exit')
    L.append('    exit')
    L.append('')

    # ── SERVICE / SDP / VPLS ──
    if has_bridge:
        echo('Service Configuration')
        L.append('    service')
        # Create SDPs — in-state: 1 SDP, out-of-state: multiple SDPs
        mesh_sdp_id = 101  # default for in-state
        for idx, far_end in enumerate(sdp_far_ends):
            sdp_num = 101 + idx
            L.append(f'        sdp {sdp_num} mpls create')
            L.append(f'            far-end {far_end}')
            L.append('            ldp')
            L.append('            keep-alive')
            L.append('                shutdown')
            L.append('            exit')
            L.append('            no shutdown')
            L.append('        exit')
            mesh_sdp_id = sdp_num  # VPLS mesh-sdp uses the last SDP
        L.append('        customer 1 name "1" create')
        L.append('            description "Default customer"')
        L.append('        exit')
        for vid in vpls_ids:
            L.append(f'        customer {vid} name "{vid}" create')
            L.append('        exit')
        for i, vid in enumerate(vpls_ids):
            vlan = vpls_vlans[i] if i < len(vpls_vlans) else str(1000 + i * 1000)
            lag_id = min(i + 1, len(bridges)) if bridges else 1
            L.append(f'        vpls {vid} name "{vid}" customer {vid} create')
            L.append('            service-mtu 1594')
            L.append('            fdb-table-size 1000')
            L.append('            stp')
            L.append('                shutdown')
            L.append('            exit')
            L.append(f'            sap lag-{lag_id}:{vlan} create')
            L.append('                no shutdown')
            L.append('            exit')
            L.append(f'            mesh-sdp {mesh_sdp_id}:{vid} create')
            L.append('                no shutdown')
            L.append('            exit')
            L.append('            no shutdown')
            L.append('        exit')
        L.append('    exit')

    # ── ROUTER SERVICE SIDE ──
    echo('Router (Service Side) Configuration')
    L.append('    router Base')

    # ── STATIC ROUTES ──
    if static_routes:
        echo('Static Route Configuration')
        for rt in static_routes:
            L.append(f'        static-route-entry {rt["dst"]}')
            L.append(f'            next-hop {rt["gateway"]}')
            L.append('                no shutdown')
            L.append('            exit')
            L.append('        exit')

    # ── OSPF SERVICE SIDE ──
    if ospf.get('found'):
        if is_instate:
            echo('OSPFv2 Configuration')
            L.append(f'        ospf 0 {router_id}')
            L.append('            no shutdown')
            L.append('        exit')
        else:
            echo('OSPFv2 Configuration')
            L.append('        ospf 0')
            L.append('            shutdown')
            L.append('        exit')
            echo('OSPFv2 (Inst: 1) Configuration')
            L.append(f'        ospf 1 {router_id}')
            L.append('            no shutdown')
            L.append('        exit')

    # ── POLICY ──
    echo('Policy Configuration')
    L.append('        policy-options')
    L.append('            begin')
    if is_instate:
        # IN-STATE: deny-list approach — deny specific, allow 10.0.0.0/8, drop rest
        pfx_name = profile.get('ldp_pfx_name', 'LDP-DENY-PL')
        pol_name = profile.get('ldp_policy_name', 'LDP-FILTER-PS')
        L.append(f'            prefix-list "{pfx_name}"')
        for prefix in ldp_deny:
            L.append(f'                prefix {prefix} exact')
        L.append('            exit')
        L.append('            prefix-list "LDP-ALLOW-PL"')
        L.append('                prefix 10.0.0.0/8 prefix-length-range 32-32')
        L.append('            exit')
        L.append(f'            policy-statement "{pol_name}"')
        L.append('                entry 10')
        L.append('                    from')
        L.append(f'                        prefix-list "{pfx_name}"')
        L.append('                    exit')
        L.append('                    action drop')
        L.append('                    exit')
        L.append('                exit')
        L.append('                entry 20')
        L.append('                    from')
        L.append('                        prefix-list "LDP-ALLOW-PL"')
        L.append('                    exit')
        L.append('                    action accept')
        L.append('                    exit')
        L.append('                exit')
        L.append('                entry 30')
        L.append('                    description "drop-rest"')
        L.append('                    action drop')
        L.append('                    exit')
        L.append('                exit')
        L.append('            exit')
    else:
        # OUT-OF-STATE: allow-list approach — allow specific prefixes, drop rest
        pfx_name = profile.get('ldp_pfx_name', 'LDP-IN-BNG-PL')
        pol_name = profile.get('ldp_policy_name', 'LDP-IN-BNG-PS')
        allow_prefixes = profile.get('ldp_allow_prefixes', [])
        L.append(f'            prefix-list "{pfx_name}"')
        for prefix in allow_prefixes:
            L.append(f'                prefix {prefix}')
        L.append('            exit')
        L.append(f'            policy-statement "{pol_name}"')
        L.append('                entry 10')
        L.append('                    from')
        L.append(f'                        prefix-list "{pfx_name}"')
        L.append('                    exit')
        L.append('                    action accept')
        L.append('                    exit')
        L.append('                exit')
        L.append('                entry 20')
        L.append('                    description "drop-rest"')
        L.append('                    action drop')
        L.append('                    exit')
        L.append('                exit')
        L.append('            exit')
    L.append('            commit')
    L.append('        exit')

    # ── BGP ──
    if bgp_data.get('found') or bgp_data.get('peers'):
        echo('BGP Configuration')
        L.append('        bgp')
        L.append('            ibgp-multipath')
        L.append(f'            router-id {router_id}')
        # Group peers by name prefix or remote AS
        groups = {}
        for peer in bgp_data.get('peers', []):
            # Derive group name from peer name (e.g., "CR7" → "CR", "DALLAS-RR-1" → "DALLAS-RR")
            pname = peer.get('name', '')
            group = re.sub(r'[-_]?\d+$', '', pname) if pname else 'IBGP'
            if not group:
                group = 'IBGP'
            if group not in groups:
                groups[group] = []
            groups[group].append(peer)
        if not groups:
            groups['IBGP'] = []
        for group_name, peers in groups.items():
            L.append(f'            group "{group_name}"')
            L.append(f'                description "{group_name}"')
            L.append(f'                authentication-key "{bgp_key}"')
            L.append(f'                peer-as {as_num}')
            L.append(f'                local-address {router_id}')
            for peer in peers:
                L.append(f'                neighbor {peer["address"]}')
                L.append('                exit')
            L.append('            exit')
        L.append('            no shutdown')
        L.append('        exit')
    L.append('    exit')
    L.append('')

    # ── LOG ──
    echo('Log all events for service vprn, log syslog tls-client-profile Configuration')
    L.append('    log')
    L.append('    exit')

    # ── NTP ──
    echo('System Time NTP Configuration')
    L.append('    system')
    L.append('        time')
    L.append('            ntp')
    for svr in ntp_servers:
        L.append(f'                server {svr}')
    L.append('            exit')
    L.append('        exit')
    L.append('    exit')

    # ── FINAL ──
    echo('System Configuration Mode Configuration')
    L.append('    system')
    L.append('        management-interface')
    L.append('            configuration-mode classic')
    L.append('        exit')
    L.append('    exit')
    L.append('exit all')

    return '\n'.join(L)


@app.route('/api/parse-mikrotik-for-nokia', methods=['POST'])
@require_auth
def parse_mikrotik_for_nokia_endpoint():
    """
    Parse a MikroTik config and return structured extraction data
    for the Nokia migration preview panel (no Nokia config generated).
    """
    try:
        data = request.json
        source_config = (data.get('source_config', '') or '').strip()
        if not source_config:
            return jsonify({'error': 'Source configuration is required'}), 400

        parsed = _parse_mikrotik_for_nokia(source_config)

        # Generate Nokia system name based on detected state
        state_info = parsed.get('detected_state', {})
        state_code = state_info.get('state_code', 'TX')
        parsed['nokia_system_name'] = _generate_nokia_system_name(parsed, state_code)

        # Include available state profiles for frontend dropdown
        state_options = [
            {'code': code, 'name': prof.get('name', code), 'is_instate': prof.get('is_instate', False)}
            for code, prof in _NOKIA_STATE_PROFILES.items()
        ]

        return jsonify({'success': True, 'parsed': parsed, 'state_options': state_options})
    except Exception as e:
        print(f"[NOKIA PARSE] Error: {e}")
        return jsonify({'error': str(e)}), 500


@app.route('/api/migrate-mikrotik-to-nokia', methods=['POST'])
@require_auth
def migrate_mikrotik_to_nokia():
    """
    Convert MikroTik RouterOS configuration to Nokia SR OS classic CLI syntax.
    Uses comprehensive deterministic conversion, consistent with the
    IN-STATE Nokia 7250 Configuration Maker output format.
    """
    try:
        data = request.json
        source_config = (data.get('source_config', '') or '').strip()
        preserve_ips = data.get('preserve_ips', True)
        nokia_params = dict(data.get('nokia_params', {}) or {})

        if not source_config:
            return jsonify({'error': 'Source configuration is required'}), 400

        # Parse MikroTik config
        parsed = _parse_mikrotik_for_nokia(source_config)

        # Build Nokia config
        nokia_params.setdefault('preserve_ips', preserve_ips)
        nokia_config = _build_nokia_config(parsed, nokia_params=nokia_params)

        return jsonify({
            'success': True,
            'nokia_config': nokia_config,
            'parsed': parsed,
        })

    except Exception as e:
        print(f"[NOKIA MIGRATION] Error: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({'error': f'Error converting MikroTik to Nokia: {str(e)}'}), 500

