# ========================================

@app.route('/api/bulk-ssh-fetch', methods=['POST'])
@require_auth
def bulk_ssh_fetch():
    """
    Bulk SSH fetch: connect to multiple MikroTik devices concurrently and
    retrieve their running configuration.

    Body:
        hosts       – list of IP address strings (required)
        ros_version – "6" | "7" (default "7")
        command     – export command (default "export")
        ports       – list of port numbers to try (default [22, 5022])
    """
    try:
        import paramiko
    except ImportError:
        return jsonify({'error': 'paramiko library not installed'}), 500

    from concurrent.futures import ThreadPoolExecutor, as_completed

    data = request.get_json(force=True) or {}
    hosts = data.get('hosts', [])
    if not hosts or not isinstance(hosts, list):
        return jsonify({'error': 'hosts must be a non-empty list of IP addresses'}), 400

    ros_version = data.get('ros_version', '7')
    command = data.get('command', 'export').strip()
    allowed_commands = ['export', 'export show-sensitive', 'export hide-sensitive']
    if command not in allowed_commands:
        return jsonify({'error': f'Invalid command. Allowed: {", ".join(allowed_commands)}'}), 400

    # Parse ports
    raw_ports = data.get('ports', [22, 5022])
    if isinstance(raw_ports, str):
        raw_ports = [int(p.strip()) for p in raw_ports.split(',') if p.strip().isdigit()]
    ssh_ports = [int(p) for p in raw_ports if isinstance(p, (int, float))]
    if not ssh_ports:
        ssh_ports = [22, 5022]

    SSH_USERNAME = (data.get('username') or os.getenv('NEXTLINK_SSH_USERNAME', '')).strip()
    SSH_PASSWORD = (data.get('password') or os.getenv('NEXTLINK_SSH_PASSWORD', '')).strip()
    if not SSH_USERNAME or not SSH_PASSWORD:
        return jsonify({'error': 'SSH credentials required'}), 400

    MAX_CONCURRENT = 3  # conservative

    def _fetch_one(host_ip):
        """Fetch config from a single device. Returns a result dict."""
        host_ip = host_ip.strip()
        try:
            ipaddress.IPv4Address(host_ip)
        except ValueError:
            return {'host': host_ip, 'success': False, 'error': 'Invalid IP address'}

        for port in ssh_ports:
            client = None
            try:
                client = paramiko.SSHClient()
                client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
                client.connect(
                    hostname=host_ip, port=port,
                    username=SSH_USERNAME, password=SSH_PASSWORD,
                    timeout=10, banner_timeout=10, auth_timeout=10
                )
                stdin, stdout, stderr = client.exec_command(command, timeout=30)
                output = stdout.read().decode('utf-8', errors='replace')
                err_out = stderr.read().decode('utf-8', errors='replace')
                if err_out and 'error' in err_out.lower():
                    return {'host': host_ip, 'success': False, 'error': err_out[:300], 'port': port}
                if not output or not output.strip():
                    continue  # try next port
                output = normalize_line_breaks(output)

                # Auto-detect device info from config header
                model = 'Unknown'
                version = 'Unknown'
                identity = ''
                m_model = re.search(r'(?m)^\s*#\s*model\s*=\s*(.+)', output)
                if m_model:
                    model = m_model.group(1).strip()
                m_ver = re.search(r'(?m)^\s*#\s*software id.*RouterOS\s+(\S+)', output)
                if not m_ver:
                    m_ver = re.search(r'(?m)^\s*#.*RouterOS\s+(\S+)', output)
                if m_ver:
                    version = m_ver.group(1).strip()
                m_id = re.search(r'/system identity\s*\n\s*set name=(\S+)', output)
                if m_id:
                    identity = m_id.group(1).strip()

                return {
                    'host': host_ip, 'success': True, 'port': port,
                    'config': output,
                    'config_lines': len(output.splitlines()),
                    'model': model, 'version': version, 'identity': identity
                }
            except paramiko.AuthenticationException:
                return {'host': host_ip, 'success': False, 'error': 'Authentication failed', 'port': port}
            except Exception as e:
                pass  # try next port
            finally:
                if client:
                    try:
                        client.close()
                    except Exception:
                        pass
        return {'host': host_ip, 'success': False, 'error': f'Connection failed on all ports ({", ".join(map(str, ssh_ports))})'}

    results = []
    with ThreadPoolExecutor(max_workers=MAX_CONCURRENT) as pool:
        future_map = {pool.submit(_fetch_one, h): h for h in hosts}
        for future in as_completed(future_map):
            results.append(future.result())

    # Sort results back to original order
    host_order = {h: i for i, h in enumerate(hosts)}
    results.sort(key=lambda r: host_order.get(r['host'], 999))

    success_count = sum(1 for r in results if r.get('success'))
    return jsonify({
        'success': True,
        'total': len(hosts),
        'succeeded': success_count,
        'failed': len(hosts) - success_count,
        'results': results
    })


@app.route('/api/bulk-generate', methods=['POST'])
@require_auth
def bulk_generate():
    """
    Bulk config generation for multiple sites.

    Body:
        sites       – list of site config objects (required)
        config_type – "tower" | "non-mpls" | "mpls" | "bng2" (required)
    """
    _require_feature('bulk_ops')
    _tenant_ctx = _get_request_tenant_context()
    _tenant_id = _tenant_ctx['tenant'].get('id')
    _check_quota(_tenant_id, 'configs_generated')
    _increment_usage(_tenant_id, 'configs_generated')
    data = request.get_json(force=True) or {}
    sites = data.get('sites', [])
    config_type = data.get('config_type', 'non-mpls')

    if not sites or not isinstance(sites, list):
        return jsonify({'error': 'sites must be a non-empty list'}), 400

    results = []
    for idx, site in enumerate(sites):
        site_name = site.get('site_name') or site.get('tower_name') or f'Site_{idx + 1}'
        try:
            if config_type == 'tower':
                # Use MTTowerConfig if available, otherwise fall back to AI-based
                if HAS_MT_CONFIG_GEN:
                    apply_compliance = bool(site.pop('apply_compliance', True))
                    payload_loopback = site.get('loopback_subnet') or site.get('loop_ip')
                    cfg = MTTowerConfig(**site)
                    config_text = cfg.generate_config()
                    if apply_compliance and HAS_ENGINEERING_COMPLIANCE:
                        config_text = apply_engineering_compliance(config_text, payload_loopback)
                    results.append({
                        'index': idx, 'site_name': site_name,
                        'success': True, 'config': config_text
                    })
                else:
                    results.append({
                        'index': idx, 'site_name': site_name,
                        'success': False, 'error': 'Tower config generator unavailable (BASE_CONFIG_PATH not set)'
                    })

            elif config_type == 'non-mpls':
                # Re-use existing gen_enterprise_non_mpls logic inline
                device = (site.get('device') or site.get('model') or 'RB5009').upper()
                target_version = site.get('target_version', '7.19.4')
                public_cidr = site.get('public_cidr', '')
                bh_cidr = site.get('bh_cidr', '')
                loopback_ip = site.get('loopback_ip', '')
                if not (public_cidr and bh_cidr and loopback_ip):
                    results.append({
                        'index': idx, 'site_name': site_name,
                        'success': False, 'error': 'Missing required fields: public_cidr, bh_cidr, loopback_ip'
                    })
                    continue

                # Build the config using the same logic as gen_enterprise_non_mpls
                # Create a mock request context with site data
                import flask
                with app.test_request_context(
                    '/api/gen-enterprise-non-mpls',
                    method='POST',
                    json=site,
                    content_type='application/json'
                ):
                    resp = gen_enterprise_non_mpls()
                    if isinstance(resp, tuple):
                        resp_obj, status_code = resp
                    else:
                        resp_obj = resp
                        status_code = 200
                    resp_data = resp_obj.get_json()
                    if status_code == 200 and resp_data.get('success'):
                        results.append({
                            'index': idx, 'site_name': site_name,
                            'success': True,
                            'config': resp_data.get('config', ''),
                            'device': resp_data.get('device', device)
                        })
                    else:
                        results.append({
                            'index': idx, 'site_name': site_name,
                            'success': False,
                            'error': resp_data.get('error', 'Generation failed')
                        })

            elif config_type == 'bng2':
                if HAS_MT_CONFIG_GEN:
                    apply_compliance = bool(site.pop('apply_compliance', True))
                    payload_loopback = site.get('loopback_subnet') or site.get('loop_ip')
                    cfg = MTBNG2Config(**site)
                    config_text = cfg.generate_config()
                    config_text = _sanitize_bng2_transport_output(config_text)
                    if apply_compliance and HAS_ENGINEERING_COMPLIANCE:
                        config_text = apply_engineering_compliance(config_text, payload_loopback)
                    results.append({
                        'index': idx, 'site_name': site_name,
                        'success': True, 'config': config_text
                    })
                else:
                    results.append({
                        'index': idx, 'site_name': site_name,
                        'success': False, 'error': 'BNG2 config generator unavailable'
                    })

            else:
                results.append({
                    'index': idx, 'site_name': site_name,
                    'success': False, 'error': f'Unknown config_type: {config_type}'
                })

        except Exception as exc:
            results.append({
                'index': idx, 'site_name': site_name,
                'success': False, 'error': str(exc)
            })

    success_count = sum(1 for r in results if r.get('success'))
    return jsonify({
        'success': True,
        'total': len(sites),
        'succeeded': success_count,
        'failed': len(sites) - success_count,
        'results': results
    })


@app.route('/api/bulk-migration-analyze', methods=['POST'])
@require_auth
def bulk_migration_analyze():
    """
    Bulk migration analysis: SSH-fetch configs from multiple devices,
    auto-detect model/version, and generate migration recommendations.

    Body:
        hosts          – list of IP addresses (required)
        target_model   – target device model key, e.g. "CCR2004-1G-12S+2XS" (required)
        target_version – target RouterOS version, e.g. "7" (default "7")
        ports          – SSH ports to try (default [22, 5022])
    """
    try:
        import paramiko
    except ImportError:
        return jsonify({'error': 'paramiko library not installed'}), 500

    from concurrent.futures import ThreadPoolExecutor, as_completed

    data = request.get_json(force=True) or {}
    hosts = data.get('hosts', [])
    target_model = data.get('target_model', 'CCR2004-1G-12S+2XS')
    target_version = data.get('target_version', '7')

    if not hosts or not isinstance(hosts, list):
        return jsonify({'error': 'hosts must be a non-empty list'}), 400

    if target_model not in ROUTERBOARD_INTERFACES:
        return jsonify({'error': f'Unknown target_model: {target_model}. Available: {", ".join(ROUTERBOARD_INTERFACES.keys())}'}), 400

    raw_ports = data.get('ports', [22, 5022])
    if isinstance(raw_ports, str):
        raw_ports = [int(p.strip()) for p in raw_ports.split(',') if p.strip().isdigit()]
    ssh_ports = [int(p) for p in raw_ports if isinstance(p, (int, float))]
    if not ssh_ports:
        ssh_ports = [22, 5022]

    SSH_USERNAME = (data.get('username') or os.getenv('NEXTLINK_SSH_USERNAME', '')).strip()
    SSH_PASSWORD = (data.get('password') or os.getenv('NEXTLINK_SSH_PASSWORD', '')).strip()
    if not SSH_USERNAME or not SSH_PASSWORD:
        return jsonify({'error': 'SSH credentials required'}), 400

    MAX_CONCURRENT = 3

    def _analyze_one(host_ip):
        host_ip = host_ip.strip()
        try:
            ipaddress.IPv4Address(host_ip)
        except ValueError:
            return {'host': host_ip, 'success': False, 'error': 'Invalid IP address'}

        # Step 1: SSH fetch
        config_text = None
        connected_port = None
        for port in ssh_ports:
            client = None
            try:
                client = paramiko.SSHClient()
                client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
                client.connect(
                    hostname=host_ip, port=port,
                    username=SSH_USERNAME, password=SSH_PASSWORD,
                    timeout=10, banner_timeout=10, auth_timeout=10
                )
                stdin, stdout, stderr = client.exec_command('export', timeout=30)
                output = stdout.read().decode('utf-8', errors='replace')
                if output and output.strip():
                    config_text = normalize_line_breaks(output)
                    connected_port = port
                    break
            except paramiko.AuthenticationException:
                return {'host': host_ip, 'success': False, 'error': 'Authentication failed'}
            except Exception:
                pass
            finally:
                if client:
                    try:
                        client.close()
                    except Exception:
                        pass

        if not config_text:
            return {'host': host_ip, 'success': False, 'error': 'Could not fetch config from any port'}

        # Step 2: Auto-detect model, version, identity
        current_model = 'Unknown'
        current_version = 'Unknown'
        identity = ''
        ros_major = 'unknown'

        m_model = re.search(r'(?m)^\s*#\s*model\s*=\s*(.+)', config_text)
        if m_model:
            current_model = m_model.group(1).strip()
        m_ver = re.search(r'(?m)^\s*#.*RouterOS\s+(\S+)', config_text)
        if m_ver:
            current_version = m_ver.group(1).strip()
            ros_major = 'v7' if current_version.startswith('7') else 'v6' if current_version.startswith('6') else 'unknown'
        m_id = re.search(r'/system identity\s*\n\s*set name=(\S+)', config_text)
        if m_id:
            identity = m_id.group(1).strip()

        # Step 3: Detect source model key for interface migration
        source_model_key = None
        for model_key in ROUTERBOARD_INTERFACES:
            if model_key.lower() in current_model.lower() or current_model.lower() in model_key.lower():
                source_model_key = model_key
                break
        # Fallback: try pattern matching
        if not source_model_key:
            digits = re.search(r'(\d{4})', current_model)
            if digits:
                d = digits.group(1)
                for model_key in ROUTERBOARD_INTERFACES:
                    if d in model_key:
                        source_model_key = model_key
                        break

        # Step 4: Build interface migration map
        interface_map = {}
        port_analysis = []
        policy_summary = {}
        manual_review_required = False
        migration_warnings = []
        if source_model_key:
            mapping_analysis = analyze_nextlink_port_mapping(config_text, source_model_key, target_model)
            interface_map = mapping_analysis.get('interface_map') or {}
            port_analysis = mapping_analysis.get('port_analysis') or []
            policy_summary = mapping_analysis.get('policy_summary') or {}
            manual_review_required = bool(mapping_analysis.get('manual_review_required'))
            migration_warnings.extend(mapping_analysis.get('warnings') or [])
        if source_model_key and source_model_key != target_model:
            if not interface_map:
                migration_warnings.append(f'Could not build interface map from {source_model_key} to {target_model}')
            # Check for port exhaustion
            source_ports = ROUTERBOARD_INTERFACES[source_model_key].get('total_ports', 0)
            target_ports = ROUTERBOARD_INTERFACES[target_model].get('total_ports', 0)
            if source_ports > target_ports:
                migration_warnings.append(f'Port count mismatch: source has {source_ports} ports, target has {target_ports}. Some ports may need reassignment.')
        elif source_model_key == target_model:
            migration_warnings.append('Source and target are the same model — version upgrade only')

        # Step 5: Determine migration type
        needs_version_migration = ros_major == 'v6' and target_version.startswith('7')
        needs_device_migration = source_model_key is not None and source_model_key != target_model

        migration_type = []
        if needs_version_migration:
            migration_type.append('v6→v7')
        if needs_device_migration:
            migration_type.append(f'{source_model_key}→{target_model}')
        if not migration_type:
            migration_type.append('config-audit')

        # Step 6: Count significant config elements
        ip_count = len(re.findall(r'\b(?:\d{1,3}\.){3}\d{1,3}(?:/\d{1,2})?\b', config_text))
        bridge_count = len(re.findall(r'/interface bridge\s', config_text))
        vpls_count = len(re.findall(r'/interface vpls', config_text))
        firewall_count = len(re.findall(r'/ip firewall', config_text))
        ospf_found = '/routing ospf' in config_text
        bgp_found = '/routing bgp' in config_text
        mpls_found = '/mpls' in config_text or '/interface vpls' in config_text

        return {
            'host': host_ip,
            'success': True,
            'port': connected_port,
            'identity': identity,
            'current_model': current_model,
            'current_version': current_version,
            'ros_major': ros_major,
            'target_model': target_model,
            'target_version': target_version,
            'migration_type': ' + '.join(migration_type),
            'needs_version_migration': needs_version_migration,
            'needs_device_migration': needs_device_migration,
            'interface_map': interface_map,
            'port_analysis': port_analysis,
            'policy_summary': policy_summary,
            'manual_review_required': manual_review_required,
            'warnings': migration_warnings,
            'config_lines': len(config_text.splitlines()),
            'config_text': config_text,
            'config_preview': '\n'.join(config_text.splitlines()[:15]),
            'complexity': {
                'ip_addresses': ip_count,
                'bridges': bridge_count,
                'vpls_tunnels': vpls_count,
                'firewall_sections': firewall_count,
                'ospf': ospf_found,
                'bgp': bgp_found,
                'mpls': mpls_found
            }
        }

    results = []
    with ThreadPoolExecutor(max_workers=MAX_CONCURRENT) as pool:
        future_map = {pool.submit(_analyze_one, h): h for h in hosts}
        for future in as_completed(future_map):
            results.append(future.result())

    # Sort back to original order
    host_order = {h: i for i, h in enumerate(hosts)}
    results.sort(key=lambda r: host_order.get(r['host'], 999))

    success_count = sum(1 for r in results if r.get('success'))
    return jsonify({
        'success': True,
        'total': len(hosts),
        'succeeded': success_count,
        'failed': len(hosts) - success_count,
        'target_model': target_model,
        'target_version': target_version,
        'results': results
    })


@app.route('/api/bulk-compliance-scan', methods=['POST'])
@require_auth
def bulk_compliance_scan():
    """
    Bulk compliance scanner: validate multiple configs against RFC-09-10-25.

    Input modes:
      A) {configs: [{name, config_text}, ...]}               — scan provided configs
      B) {hosts: [...], ports: [22,5022]}                     — SSH fetch then scan
      C) {configs: [{name, config_text}], apply_fix: true}    — scan + auto-fix

    Returns per-device:
      name, compliant, score (0-100), grade (A-F),
      missing_items, warnings, total_checks, passed_checks,
      checks (detailed pass/fail per check), identity, model, version
    """
    if not HAS_COMPLIANCE:
        return jsonify({'error': 'Compliance reference module not available'}), 500

    data = request.get_json(force=True) or {}
    configs = data.get('configs', [])
    hosts = data.get('hosts', [])
    apply_fix = data.get('apply_fix', False)
    raw_ports = data.get('ports', [22, 5022])

    # Mode B: SSH fetch configs first
    if hosts and isinstance(hosts, list) and not configs:
        try:
            import paramiko
        except ImportError:
            return jsonify({'error': 'paramiko not installed'}), 500
        from concurrent.futures import ThreadPoolExecutor, as_completed

        if isinstance(raw_ports, str):
            raw_ports = [int(p.strip()) for p in raw_ports.split(',') if p.strip().isdigit()]
        ssh_ports = [int(p) for p in raw_ports if isinstance(p, (int, float))]
        if not ssh_ports:
            ssh_ports = [22, 5022]

        SSH_USERNAME = os.getenv('NEXTLINK_SSH_USERNAME', '').strip()
        SSH_PASSWORD = os.getenv('NEXTLINK_SSH_PASSWORD', '').strip()
        if not SSH_USERNAME or not SSH_PASSWORD:
            return jsonify({'error': 'SSH credentials not configured on server'}), 400

        def _fetch_one(host_ip):
            host_ip = host_ip.strip()
            for port in ssh_ports:
                client = None
                try:
                    client = paramiko.SSHClient()
                    client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
                    client.connect(hostname=host_ip, port=port,
                                   username=SSH_USERNAME, password=SSH_PASSWORD,
                                   timeout=10, banner_timeout=10, auth_timeout=10)
                    stdin, stdout, stderr = client.exec_command('export', timeout=30)
                    output = stdout.read().decode('utf-8', errors='replace')
                    if output and output.strip():
                        return {'name': host_ip, 'config_text': normalize_line_breaks(output), 'port': port}
                except paramiko.AuthenticationException:
                    return {'name': host_ip, 'config_text': None, 'error': 'Authentication failed'}
                except Exception:
                    pass
                finally:
                    if client:
                        try: client.close()
                        except Exception: pass
            return {'name': host_ip, 'config_text': None, 'error': 'Could not connect'}

        fetched = []
        with ThreadPoolExecutor(max_workers=3) as pool:
            futures = {pool.submit(_fetch_one, h): h for h in hosts}
            for f in as_completed(futures):
                fetched.append(f.result())
        # Preserve original order
        order = {h: i for i, h in enumerate(hosts)}
        fetched.sort(key=lambda r: order.get(r['name'], 999))
        configs = fetched

    if not configs:
        return jsonify({'error': 'No configs or hosts provided'}), 400

    # Build tenant-specific compliance checks per request
    _b_scan_tenant_ctx = _get_request_tenant_context()
    _b_scan_tenant = _b_scan_tenant_ctx.get('tenant') or {}
    _b_scan_tenant_id = _b_scan_tenant.get('id') if _b_scan_tenant else None
    _b_scan_ts = {}
    if _b_scan_tenant_id:
        try:
            init_users_db()
            _b_scan_conn = sqlite3.connect(os.path.join('secure_data', 'users.db'))
            _b_scan_ts = _get_tenant_settings_row(_b_scan_conn, _b_scan_tenant_id)
            _b_scan_conn.close()
        except Exception:
            _b_scan_ts = {}

    # Resolve tenant-driven IP values for compliance checks
    _ts_dns1 = (_b_scan_ts.get('compliance_dns_primary') or _b_scan_ts.get('dns_primary') or
                os.getenv('NEXTLINK_DNS_PRIMARY', '142.147.112.3')).strip()
    _ts_dns2 = (_b_scan_ts.get('compliance_dns_secondary') or _b_scan_ts.get('dns_secondary') or
                os.getenv('NEXTLINK_DNS_SECONDARY', '142.147.112.19')).strip()
    _ts_syslog = (_b_scan_ts.get('compliance_syslog') or _b_scan_ts.get('syslog_server') or '142.147.116.215').strip()
    _ts_ntp = (_b_scan_ts.get('compliance_ntp') or _b_scan_ts.get('ntp_primary') or 'ntp-pool.nxlink.com').strip()
    _ts_snmp = (_b_scan_ts.get('compliance_snmp_community') or _b_scan_ts.get('snmp_community') or 'FBZ1yYdphf').strip()

    # Static structural checks (device hardening — same for all tenants)
    # Plus tenant-driven IP checks for DNS, syslog, NTP, SNMP
    COMPLIANCE_CHECKS = [
        {'id': 'svc_telnet',     'category': 'IP Services',    'label': 'Telnet disabled (port 5023)',      'pattern': r'telnet.*disabled=yes'},
        {'id': 'svc_www',        'category': 'IP Services',    'label': 'HTTP disabled (port 1234)',        'pattern': r'www.*disabled=yes.*port=1234|www.*port=1234.*disabled=yes'},
        {'id': 'svc_www_ssl',    'category': 'IP Services',    'label': 'HTTPS enabled (port 443)',         'pattern': r'www-ssl.*disabled=no.*port=443|www-ssl.*port=443.*disabled=no'},
        {'id': 'svc_winbox',     'category': 'IP Services',    'label': 'Winbox on port 8291',              'pattern': r'winbox.*port=8291'},
        {'id': 'svc_ssh',        'category': 'IP Services',    'label': 'SSH on port 22',                   'pattern': r'ssh.*port=22'},
        {'id': 'dns_primary',    'category': 'DNS',            'label': f'Primary DNS ({_ts_dns1})',        'pattern': re.escape(_ts_dns1)},
        {'id': 'dns_secondary',  'category': 'DNS',            'label': f'Secondary DNS ({_ts_dns2})',      'pattern': re.escape(_ts_dns2)},
        {'id': 'fw_eoip',        'category': 'Firewall',       'label': 'EOIP-ALLOW address list',          'pattern': r'list=eoip-allow'},
        {'id': 'fw_mgr',         'category': 'Firewall',       'label': 'managerIP address list',           'pattern': r'list=managerip'},
        {'id': 'fw_bgp',         'category': 'Firewall',       'label': 'BGP-ALLOW address list',           'pattern': r'list=bgp-allow'},
        {'id': 'fw_snmp',        'category': 'Firewall',       'label': 'SNMP address list',                'pattern': r'list=snmp'},
        {'id': 'fw_input_est',   'category': 'Firewall',       'label': 'Input chain: allow est/rel',       'pattern': r'chain=input.*allow est rel|chain=input.*established'},
        {'id': 'fw_input_drop',  'category': 'Firewall',       'label': 'Input chain: drop rule',           'pattern': r'chain=input.*drop input|chain=input.*action=drop'},
        {'id': 'fw_raw_udp',     'category': 'Firewall',       'label': 'Raw: drop bad UDP port=0',        'pattern': r'chain=prerouting.*drop bad udp|port=0.*action=drop'},
        {'id': 'fw_udp_timeout', 'category': 'Firewall',       'label': 'UDP timeout = 30s',                'pattern': r'udp-timeout=30s'},
        {'id': 'fw_sip_off',     'category': 'Firewall',       'label': 'SIP ALG disabled',                 'pattern': r'sip.*disabled=yes'},
        {'id': 'sys_tz',         'category': 'System',         'label': 'Timezone America/Chicago',         'pattern': r'america/chicago'},
        {'id': 'sys_ntp',        'category': 'System',         'label': f'NTP: {_ts_ntp}',                  'pattern': re.escape(_ts_ntp).replace(re.escape('.'), r'\.')},
        {'id': 'sys_snmp',       'category': 'SNMP',           'label': 'SNMP community configured',        'pattern': rf'name={re.escape(_ts_snmp.lower())}|name={re.escape(_ts_snmp)}'},
        {'id': 'sys_watchdog',   'category': 'System',         'label': 'Watchdog timer enabled',           'pattern': r'watchdog-timer=yes'},
        {'id': 'sys_autoupg',    'category': 'System',         'label': 'Auto-upgrade enabled',             'pattern': r'auto-upgrade=yes'},
        {'id': 'log_syslog',     'category': 'Logging',        'label': f'Remote syslog ({_ts_syslog})',    'pattern': re.escape(_ts_syslog)},
    ]

    SOFT_CHECKS = [
        {'id': 'aaa_radius',     'category': 'AAA',            'label': 'User AAA: use-radius=no',          'pattern': r'use-radius=no'},
        {'id': 'dhcp_opt43',     'category': 'DHCP',           'label': 'DHCP Option 43 (uss.nxlink.com)',  'pattern': r'uss\.nxlink\.com|0x011768747470733a2f2f7573732e6e786c696e6b2e636f6d|code=43.*name=opt43'},
        {'id': 'radius_primary', 'category': 'RADIUS',         'label': 'RADIUS server 142.147.112.2',     'pattern': r'142\.147\.112\.2[^0-9]'},
        {'id': 'radius_secondary','category': 'RADIUS',        'label': 'RADIUS server 142.147.112.18',    'pattern': r'142\.147\.112\.18[^0-9]'},
    ]

    total_hard = len(COMPLIANCE_CHECKS)
    total_soft = len(SOFT_CHECKS)
    total_all = total_hard + total_soft

    results = []
    grade_counts = {'A': 0, 'B': 0, 'C': 0, 'D': 0, 'F': 0}

    for entry in configs:
        name = entry.get('name', 'Unknown')
        config_text = entry.get('config_text', '')
        fetch_error = entry.get('error', '')

        if not config_text:
            results.append({
                'name': name, 'success': False, 'error': fetch_error or 'No config text',
                'compliant': False, 'score': 0, 'grade': 'F'
            })
            grade_counts['F'] += 1
            continue

        config_lower = config_text.lower()

        # Auto-detect identity, model, version
        identity = ''
        model = ''
        version = ''
        m_id = re.search(r'/system identity\s*\n\s*set name=(\S+)', config_text)
        if m_id: identity = m_id.group(1).strip()
        m_model = re.search(r'(?m)^\s*#\s*model\s*=\s*(.+)', config_text)
        if m_model: model = m_model.group(1).strip()
        m_ver = re.search(r'(?m)^\s*#.*RouterOS\s+(\S+)', config_text)
        if m_ver: version = m_ver.group(1).strip()

        # Run detailed checks
        checks = []
        hard_passed = 0
        soft_passed = 0

        for chk in COMPLIANCE_CHECKS:
            passed = bool(re.search(chk['pattern'], config_lower if chk['id'] not in ('sys_snmp',) else config_text))
            if passed: hard_passed += 1
            checks.append({
                'id': chk['id'], 'category': chk['category'], 'label': chk['label'],
                'severity': 'hard', 'passed': passed
            })

        for chk in SOFT_CHECKS:
            passed = bool(re.search(chk['pattern'], config_lower if chk['id'] not in ('radius_primary','radius_secondary') else config_text))
            if passed: soft_passed += 1
            checks.append({
                'id': chk['id'], 'category': chk['category'], 'label': chk['label'],
                'severity': 'soft', 'passed': passed
            })

        # Score: hard checks = 80% weight, soft checks = 20% weight
        hard_pct = (hard_passed / total_hard * 100) if total_hard else 100
        soft_pct = (soft_passed / total_soft * 100) if total_soft else 100
        score = round(hard_pct * 0.8 + soft_pct * 0.2)

        grade = 'A' if score >= 90 else 'B' if score >= 75 else 'C' if score >= 60 else 'D' if score >= 40 else 'F'
        grade_counts[grade] += 1

        # Derive compliant from the regex-based score (accurate against SSH export output)
        # validate_compliance() uses substring matching that fails on export's extra properties
        # like address="" in /ip service lines, so we only use it for informational missing_items
        compliant = (hard_passed == total_hard)  # All 22 hard checks must pass

        # Run validate_compliance() for informational missing_items list (NOT for compliant decision)
        try:
            official = validate_compliance(config_text)
            # Merge: only keep missing_items that also failed in our regex checks
            failed_check_labels = set(c['label'] for c in checks if not c['passed'])
            missing_items = [m for m in official.get('missing_items', []) if any(fl.lower() in m.lower() for fl in failed_check_labels)] if failed_check_labels else []
            # Build missing_items from failed regex checks if validate gave us nothing useful
            if not missing_items and not compliant:
                missing_items = [c['label'] for c in checks if not c['passed'] and c['severity'] == 'hard']
            warnings = official.get('warnings', [])
        except Exception:
            missing_items = [c['label'] for c in checks if not c['passed'] and c['severity'] == 'hard']
            warnings = [c['label'] for c in checks if not c['passed'] and c['severity'] == 'soft']

        result = {
            'name': name,
            'success': True,
            'identity': identity,
            'model': model,
            'version': version,
            'compliant': compliant,
            'score': score,
            'grade': grade,
            'total_checks': total_all,
            'hard_passed': hard_passed,
            'hard_total': total_hard,
            'soft_passed': soft_passed,
            'soft_total': total_soft,
            'checks': checks,
            'missing_items': missing_items,
            'warnings': warnings,
            'config_lines': len(config_text.splitlines())
        }

        # Apply fix if requested and device has failed hard checks
        if apply_fix and not compliant:
            try:
                loopback_ip = ''
                lm = re.search(r'/ip address\s+add address=([0-9.]+/[0-9]+)\s+interface=loop0', config_text, re.IGNORECASE)
                if lm: loopback_ip = lm.group(1)
                if not loopback_ip: loopback_ip = '10.0.0.1/32'
                _lip = loopback_ip.split('/')[0]
                compliance_blocks = _get_dynamic_compliance_blocks(loopback_ip)
                fixed_config = inject_compliance_blocks(config_text, compliance_blocks, loopback_ip=_lip)
                # Re-score with the same regex checks (not validate_compliance)
                fixed_lower = fixed_config.lower()
                fixed_hard = sum(1 for chk in COMPLIANCE_CHECKS if re.search(chk['pattern'], fixed_lower if chk['id'] not in ('sys_snmp',) else fixed_config))
                fixed_soft = sum(1 for chk in SOFT_CHECKS if re.search(chk['pattern'], fixed_lower if chk['id'] not in ('radius_primary','radius_secondary') else fixed_config))
                fixed_hard_pct = (fixed_hard / total_hard * 100) if total_hard else 100
                fixed_soft_pct = (fixed_soft / total_soft * 100) if total_soft else 100
                fixed_score = round(fixed_hard_pct * 0.8 + fixed_soft_pct * 0.2)
                result['fixed_config'] = fixed_config
                result['fixed_compliant'] = (fixed_hard == total_hard)
                result['fixed_score'] = fixed_score
                result['fixed_missing'] = [chk['label'] for chk in COMPLIANCE_CHECKS if not re.search(chk['pattern'], fixed_lower if chk['id'] not in ('sys_snmp',) else fixed_config)]
            except Exception as e:
                result['fix_error'] = str(e)

        results.append(result)

    total = len(results)
    succeeded = sum(1 for r in results if r.get('success'))
    compliant_count = sum(1 for r in results if r.get('compliant'))
    avg_score = round(sum(r.get('score', 0) for r in results) / total) if total else 0
    fleet_grade = 'A' if avg_score >= 90 else 'B' if avg_score >= 75 else 'C' if avg_score >= 60 else 'D' if avg_score >= 40 else 'F'

    return jsonify({
        'success': True,
        'total': total,
        'succeeded': succeeded,
        'compliant_count': compliant_count,
        'non_compliant_count': total - compliant_count,
        'average_score': avg_score,
        'fleet_grade': fleet_grade,
        'grade_distribution': grade_counts,
        'results': results
    })


@app.route('/api/bulk-migration-execute', methods=['POST'])
@require_auth
def bulk_migration_execute():
    """
    Execute migration transformation on previously-analyzed device configs.

    Body:
        devices – list of objects containing:
            config_text          – full source config text
            interface_map        – {old_port: new_port} mapping
            target_model         – target model string
            target_version       – "6" or "7"
            needs_version_migration – bool (v6→v7)
            needs_device_migration  – bool (model swap)
            identity             – device identity string
            host                 – IP address (for labeling)
            current_model        – source model string
    """
    _require_feature('bulk_ops')
    _tenant_ctx = _get_request_tenant_context()
    _tenant_id = _tenant_ctx['tenant'].get('id')
    _check_quota(_tenant_id, 'configs_generated')
    _increment_usage(_tenant_id, 'configs_generated')
    data = request.get_json(force=True) or {}
    devices = data.get('devices', [])
    if not devices or not isinstance(devices, list):
        return jsonify({'error': 'devices must be a non-empty list'}), 400

    results = []
    for idx, dev in enumerate(devices):
        config = dev.get('config_text', '')
        imap = dev.get('interface_map', {})
        target_model = dev.get('target_model', '')
        target_version = dev.get('target_version', '7')
        needs_ver = dev.get('needs_version_migration', False)
        needs_dev = dev.get('needs_device_migration', False)
        identity = dev.get('identity', '')
        host = dev.get('host', f'device-{idx}')
        current_model = dev.get('current_model', '')

        if not config:
            results.append({'index': idx, 'host': host, 'success': False, 'error': 'No config text provided'})
            continue

        try:
            migrated = config

            # Step 1: Interface migration (remap port names)
            if needs_dev and imap:
                migrated = migrate_interface_config(migrated, imap)

            # Step 2: ROS v6 → v7 syntax conversion
            if needs_ver:
                migrated = apply_ros6_to_ros7_syntax(migrated)

            # Step 3: Update identity to reflect target model
            if identity and needs_dev:
                new_identity = identity
                # Replace model references in identity (e.g., RTR-MT1072.SITE → RTR-MT2004.SITE)
                for model_key, model_info in ROUTERBOARD_INTERFACES.items():
                    series = model_info.get('series', '')
                    if series and series.upper() in identity.upper():
                        target_info = ROUTERBOARD_INTERFACES.get(target_model, {})
                        target_series = target_info.get('series', '')
                        if target_series:
                            import re as _re
                            new_identity = _re.sub(_re.escape(series), target_series, identity, flags=_re.IGNORECASE)
                        break
                migrated = re.sub(
                    r'(/system identity\s*\nset name=)\S+',
                    r'\g<1>' + new_identity,
                    migrated
                )

            # Step 4: Update model/version header comments
            if needs_dev:
                migrated = re.sub(
                    r'(?m)^(\s*#\s*model\s*=\s*)(.+)$',
                    r'\g<1>' + target_model,
                    migrated
                )
            if needs_ver:
                migrated = re.sub(
                    r'(?m)^(\s*#.*RouterOS\s+)(\S+)',
                    r'\g<1>7.x (migrated from \2)',
                    migrated
                )

            # Step 5: Add migration header
            timestamp = datetime.now().strftime('%Y-%m-%d %H:%M')
            header = f"# === MIGRATION CONFIG ===\n"
            header += f"# Generated by NOC-ConfigMaker Bulk Migration\n"
            header += f"# Source: {current_model} → Target: {target_model}\n"
            if needs_ver:
                header += f"# Version: v6 → v7 syntax conversion applied\n"
            if needs_dev and imap:
                header += f"# Interface map: {len(imap)} ports remapped\n"
            header += f"# Date: {timestamp}\n"
            header += f"# Host: {host} | Identity: {identity}\n"
            header += f"# ========================\n\n"
            migrated = header + migrated

            results.append({
                'index': idx,
                'host': host,
                'identity': identity,
                'success': True,
                'migrated_config': migrated,
                'config_lines': len(migrated.splitlines()),
                'changes': {
                    'interfaces_remapped': len(imap) if needs_dev else 0,
                    'version_migrated': needs_ver,
                    'device_migrated': needs_dev,
                    'source_model': current_model,
                    'target_model': target_model
                }
            })
        except Exception as e:
            results.append({'index': idx, 'host': host, 'success': False, 'error': str(e)})

    success_count = sum(1 for r in results if r.get('success'))
    return jsonify({
        'success': True,
        'total': len(devices),
        'succeeded': success_count,
        'failed': len(devices) - success_count,
        'results': results
    })


# ─── SSH Push Config to Live MikroTik Devices ────────────────────────
@app.route('/api/ssh-push-config', methods=['POST'])
def ssh_push_config():
    """
    Push .rsc config text to MikroTik devices via SFTP upload + /import.
    Safety: creates a binary backup before import, sets a dead-man's-switch
    scheduler that auto-restores the backup if the push fails.

    Body JSON:
        devices: [ { host, config_text, label? } ]
        ports: [22, 5022]              (optional, default [22,5022])
        create_backup: true            (optional, default true)
        rollback_minutes: 5            (optional, default 5, 0 = no rollback)
    """
    import paramiko
    import io as _io
    import time as _time
    from concurrent.futures import ThreadPoolExecutor, as_completed

    data = request.get_json(force=True, silent=True) or {}
    devices = data.get('devices', [])
    if not devices:
        return jsonify({'error': 'No devices provided'}), 400

    # Batch 10: prefer tenant_settings credentials over env vars
    _push_ts = {}
    try:
        _push_tenant_ctx = _get_request_tenant_context()
        _push_tenant = _push_tenant_ctx.get('tenant') or {}
        _push_tenant_id = _push_tenant.get('id') if _push_tenant else None
        if _push_tenant_id:
            init_users_db()
            _push_conn = sqlite3.connect(os.path.join('secure_data', 'users.db'))
            _push_ts = _get_tenant_settings_row(_push_conn, _push_tenant_id)
            _push_conn.close()
    except Exception:
        _push_ts = {}

    ssh_user = (_push_ts.get('ssh_username') or '').strip() or os.getenv('NEXTLINK_SSH_USERNAME', '')
    ssh_pass = (_push_ts.get('ssh_password') or '').strip() or os.getenv('NEXTLINK_SSH_PASSWORD', '')
    if not ssh_user or not ssh_pass:
        return jsonify({'error': 'SSH credentials not configured on server'}), 500

    raw_ports = data.get('ports', [22, 5022])
    if isinstance(raw_ports, str):
        raw_ports = [int(p.strip()) for p in raw_ports.split(',') if p.strip().isdigit()]
    elif isinstance(raw_ports, (int, float)):
        raw_ports = [int(raw_ports)]
    ports = [int(p) for p in raw_ports if 0 < int(p) < 65536] or [22, 5022]

    create_backup = data.get('create_backup', True)
    rollback_minutes = int(data.get('rollback_minutes', 5))

    MAX_CONCURRENT = 3

    def _push_one(dev):
        host = (dev.get('host') or '').strip()
        config_text = (dev.get('config_text') or '').strip()
        label = dev.get('label') or host

        if not host or not config_text:
            return {'host': host, 'label': label, 'success': False, 'error': 'Missing host or config_text'}

        # Validate IP
        try:
            import ipaddress
            ipaddress.IPv4Address(host)
        except ValueError:
            return {'host': host, 'label': label, 'success': False, 'error': f'Invalid IP: {host}'}

        filename = f'noc_push_{host.replace(".", "_")}_{int(_time.time())}.rsc'
        steps = []
        client = None
        connected_port = None

        # ── Step 1: SSH Connect ──
        for port in ports:
            try:
                client = paramiko.SSHClient()
                client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
                client.connect(
                    hostname=host, port=port,
                    username=ssh_user, password=ssh_pass,
                    timeout=10, banner_timeout=10, auth_timeout=10
                )
                connected_port = port
                break
            except paramiko.AuthenticationException:
                if client:
                    client.close()
                return {'host': host, 'label': label, 'success': False,
                        'error': f'Authentication failed on port {port}', 'port': port}
            except (paramiko.SSHException, OSError):
                if client:
                    try:
                        client.close()
                    except Exception:
                        pass
                client = None
                continue

        if client is None:
            return {'host': host, 'label': label, 'success': False,
                    'error': f'Connection failed on ports {ports}'}

        try:
            steps.append(f'Connected on port {connected_port}')
            backup_name = None

            # ── Step 2: Create backup ──
            if create_backup:
                backup_name = f'pre-push-{int(_time.time())}'
                stdin, stdout, stderr = client.exec_command(
                    f'/system backup save name={backup_name}', timeout=30
                )
                stdout.read()
                _time.sleep(2)  # give RouterOS time to write backup file
                steps.append(f'Backup created: {backup_name}.backup')

            # ── Step 3: Dead-man's-switch scheduler ──
            if rollback_minutes > 0 and backup_name:
                sched_cmd = (
                    f'/system scheduler add name=noc-push-rollback '
                    f'interval={rollback_minutes}m '
                    f'on-event="/system backup load name={backup_name}" '
                    f'policy=ftp,reboot,read,write,policy,test,password,sniff,sensitive,romon '
                    f'comment="NOC push safety — auto-restore in {rollback_minutes}m"'
                )
                stdin, stdout, stderr = client.exec_command(sched_cmd, timeout=15)
                stdout.read()
                steps.append(f'Rollback scheduler set ({rollback_minutes}m)')

            # ── Step 4: SFTP upload .rsc file ──
            try:
                sftp = client.open_sftp()
                sftp.putfo(_io.BytesIO(config_text.encode('utf-8')), filename)
                sftp.close()
                steps.append(f'Uploaded {filename} ({len(config_text)} bytes)')
            except Exception as sftp_err:
                steps.append(f'SFTP failed: {sftp_err}')
                return {'host': host, 'label': label, 'success': False,
                        'error': f'SFTP upload failed: {sftp_err}', 'port': connected_port, 'steps': steps}

            # ── Step 5: Import the .rsc file ──
            import_cmd = f'/import file-name={filename} verbose=yes'
            stdin, stdout, stderr = client.exec_command(import_cmd, timeout=120)
            import_stdout = stdout.read().decode('utf-8', errors='replace')
            import_stderr = stderr.read().decode('utf-8', errors='replace')

            # RouterOS sends import output to EITHER stdout or stderr depending
            # on version/channel.  Merge them for analysis.
            combined_output = (import_stdout + '\n' + import_stderr).strip()
            all_lines = combined_output.splitlines()

            import re as _re

            # Positive success indicator from RouterOS
            success_marker = any(
                'script file loaded and executed successfully' in l.lower()
                for l in all_lines
            )

            # "failure: already have" is benign — item already exists on device
            benign_pattern = _re.compile(r'failure:\s*already have', _re.IGNORECASE)
            benign_count = sum(1 for l in all_lines if benign_pattern.search(l))

            # These are real errors that indicate broken config syntax
            critical_pattern = _re.compile(
                r'bad command name|syntax error|input does not match|'
                r'expected end of command|invalid value',
                _re.IGNORECASE
            )
            critical_lines = [l.strip() for l in all_lines
                              if critical_pattern.search(l) and not benign_pattern.search(l)]

            # Decision: if RouterOS says "executed successfully" → trust it
            # Only fail if we see real critical syntax errors AND no success marker
            if critical_lines and not success_marker:
                steps.append(f'Import completed WITH {len(critical_lines)} critical error(s) — rollback scheduler remains active')
                return {
                    'host': host, 'label': label, 'success': False,
                    'error': f'Import had {len(critical_lines)} critical error(s)',
                    'critical_lines': critical_lines[:20],
                    'port': connected_port, 'steps': steps,
                    'import_output': combined_output[:6000],
                    'benign_skipped': benign_count
                }

            # Success path
            status_parts = []
            if success_marker:
                status_parts.append('RouterOS confirmed execution')
            if benign_count > 0:
                status_parts.append(f'{benign_count} items already existed (skipped)')
            if critical_lines:
                status_parts.append(f'{len(critical_lines)} minor warnings (import still succeeded)')
            if not status_parts:
                status_parts.append('completed successfully')
            steps.append('Import ' + ' — '.join(status_parts))

            # ── Step 6: Remove rollback scheduler ──
            if rollback_minutes > 0 and backup_name:
                try:
                    stdin, stdout, stderr = client.exec_command(
                        '/system scheduler remove noc-push-rollback', timeout=10
                    )
                    stdout.read()
                    steps.append('Rollback scheduler removed (push confirmed OK)')
                except Exception:
                    steps.append('WARNING: Could not remove rollback scheduler')

            # ── Step 7: Clean up uploaded .rsc file ──
            try:
                stdin, stdout, stderr = client.exec_command(
                    f'/file remove {filename}', timeout=10
                )
                stdout.read()
                steps.append(f'Cleaned up {filename}')
            except Exception:
                pass

            return {
                'host': host, 'label': label, 'success': True,
                'port': connected_port, 'steps': steps,
                'import_output': combined_output[:6000],
                'benign_skipped': benign_count
            }

        except Exception as e:
            return {'host': host, 'label': label, 'success': False,
                    'error': f'Unexpected error: {str(e)}', 'port': connected_port,
                    'steps': steps}
        finally:
            try:
                client.close()
            except Exception:
                pass

    # Dispatch all devices through thread pool
    results = []
    host_order = {dev.get('host', ''): i for i, dev in enumerate(devices)}
    with ThreadPoolExecutor(max_workers=MAX_CONCURRENT) as pool:
        future_map = {pool.submit(_push_one, dev): dev for dev in devices}
        for future in as_completed(future_map):
            try:
                results.append(future.result())
            except Exception as e:
                dev = future_map[future]
                results.append({'host': dev.get('host', ''), 'success': False,
                                'error': f'Thread error: {str(e)}'})

    # Sort back to original order
    results.sort(key=lambda r: host_order.get(r.get('host', ''), 999))

    success_count = sum(1 for r in results if r.get('success'))
    return jsonify({
        'success': True,
        'total': len(devices),
        'succeeded': success_count,
        'failed': len(devices) - success_count,
        'results': results
    })


